// Universal badge component — clean, consistent across all of EstateIQ
const ColorBadge = ({ label, color, icon, size = "sm" }) => {
  const pad = size === "lg" ? "5px 12px" : "2px 8px";
  const fs  = size === "lg" ? 12 : 11;
  return (
    <span style={{
      background: (color||"#94a3b8") + "18",
      color: color||"#94a3b8",
      border: `1px solid ${(color||"#94a3b8")}33`,
      borderRadius: 4,
      padding: pad,
      fontSize: fs,
      fontWeight: 700,
      display: "inline-flex",
      alignItems: "center",
      gap: 3,
      whiteSpace: "nowrap",
      letterSpacing: "0.02em",
    }}>
      {icon && <span style={{ fontSize: fs }}>{icon}</span>}
      {label}
    </span>
  );
};

// Convenience badge components
const PropTypeBadge     = ({ type })   => <ColorBadge label={type}   color={propertyTypeColors[type]||"#94a3b8"} />;
const ListingStatusBadge = ({ status }) => <ColorBadge label={status} color={listingStatusColors[status]||"#94a3b8"} />;
const StageBadge        = ({ stage })  => <ColorBadge label={stage}  color={stageColors[stage]||"#94a3b8"} />;
const SourceBadge       = ({ source }) => <ColorBadge label={source} color={sourceColors[source]||"#94a3b8"} />;
const DealTypeBadge     = ({ type })   => <ColorBadge label={type}   color={dealTypeColors[type]||"#94a3b8"} />;
const InvestBadge       = ({ type })   => <ColorBadge label={type}   color={investTypeColors[type]||"#94a3b8"} />;

// ── COLOR LEGEND COMPONENT ───────────────────────────────────────────────────
// Displays the full color key — accessible from any page
function ColorLegend({ onClose }) {
  const sections = [
    { title: "Pipeline Stages", items: Object.entries(stageColors) },
    { title: "Lead Temperature", items: [["🔥 Hot", "#ef4444"], ["☀️ Warm", "#f59e0b"], ["❄️ Cold", "#3b82f6"]] },
    { title: "Property Types", items: Object.entries(propertyTypeColors) },
    { title: "Listing Status", items: Object.entries(listingStatusColors) },
    { title: "Deal Types", items: Object.entries(dealTypeColors) },
    { title: "Investment Types", items: Object.entries(investTypeColors) },
    { title: "Transaction Status", items: Object.entries(txStatusColors) },
  ];

  return (
    <div style={{ position: "fixed", inset: 0, background: "rgba(15,23,42,0.5)", zIndex: 300, display: "flex", alignItems: "center", justifyContent: "center" }}>
      <div style={{ background: "white", borderRadius: 14, width: 720, maxHeight: "88vh", overflow: "auto", boxShadow: "0 24px 64px rgba(0,0,0,0.2)" }}>
        <div style={{ padding: "20px 24px", borderBottom: "1px solid #f1f5f9", display: "flex", justifyContent: "space-between", alignItems: "center", position: "sticky", top: 0, background: "white", zIndex: 1 }}>
          <div>
            <div style={{ color: "#0f172a", fontSize: 18, fontWeight: 800 }}>🎨 EstateIQ Color Legend</div>
            <div style={{ color: "#94a3b8", fontSize: 12, marginTop: 2 }}>Your complete color-coding reference guide</div>
          </div>
          <button onClick={onClose} style={{ background: "#f8fafc", border: "1px solid #e2e8f0", color: "#64748b", borderRadius: 7, padding: "7px 14px", fontSize: 13, cursor: "pointer", fontFamily: "inherit" }}>Close ✕</button>
        </div>

        {/* Design Philosophy */}
        <div style={{ padding: "16px 24px", background: "#f8fafc", borderBottom: "1px solid #f1f5f9" }}>
          <div style={{ color: "#0f172a", fontSize: 13, fontWeight: 700, marginBottom: 10 }}>Design Philosophy</div>
          <div style={{ display: "flex", gap: 12, flexWrap: "wrap" }}>
            {[["🟢 Green", "Good / Active / Closed / Success", "#059669"], ["🟡 Amber", "Caution / Pending / Warm / In Progress", "#f59e0b"], ["🔴 Red", "Urgent / Distressed / Alert / Problem", "#ef4444"], ["🔵 Blue", "Neutral / New / Informational / Cold", "#3b82f6"], ["🟣 Purple", "Premium / Complex / Special", "#7c3aed"], ["⬜ Gray", "Inactive / Unknown / Cancelled", "#94a3b8"]].map(([label, desc, color]) => (
              <div key={label} style={{ display: "flex", alignItems: "center", gap: 8, background: "white", border: "1px solid #f1f5f9", borderRadius: 8, padding: "8px 12px", flex: "1 0 180px" }}>
                <div style={{ width: 12, height: 12, borderRadius: 3, background: color, flexShrink: 0 }} />
                <div>
                  <div style={{ color: "#0f172a", fontSize: 12, fontWeight: 700 }}>{label}</div>
                  <div style={{ color: "#94a3b8", fontSize: 10 }}>{desc}</div>
                </div>
              </div>
            ))}
          </div>
        </div>

        <div style={{ padding: "20px 24px", display: "grid", gridTemplateColumns: "1fr 1fr", gap: 20 }}>
          {sections.map(sec => (
            <div key={sec.title}>
              <div style={{ color: "#475569", fontSize: 11, fontWeight: 700, textTransform: "uppercase", letterSpacing: "0.08em", marginBottom: 10 }}>{sec.title}</div>
              <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
                {sec.items.map(([label, color]) => (
                  <div key={label} style={{ display: "flex", alignItems: "center", gap: 10 }}>
                    <div style={{ width: 28, height: 20, borderRadius: 4, background: color + "20", border: `1px solid ${color}44`, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
                      <div style={{ width: 10, height: 10, borderRadius: 2, background: color }} />
                    </div>
                    <span style={{ color: "#0f172a", fontSize: 12, fontWeight: 600 }}>{label}</span>
                    <span style={{ color: "#94a3b8", fontSize: 10, marginLeft: "auto", fontFamily: "monospace" }}>{color}</span>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

