// ─── Components ───────────────────────────────────────────────────────────────
function TempBadge({ temp }) {
  const cfg = tempConfig[temp] || tempConfig.Warm;
  return (
    <span style={{ background: cfg.bg, color: cfg.color, border: `1px solid ${cfg.border}`, borderRadius: 4, padding: "2px 8px", fontSize: 11, fontWeight: 700, display: "inline-flex", alignItems: "center", gap: 3 }}>
      {cfg.icon} {temp}
    </span>
  );
}

function ScoreBadge({ score }) {
  const color = score >= 80 ? "#ef4444" : score >= 50 ? "#f97316" : "#0ea5e9";
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
      <div style={{ width: 32, height: 32, borderRadius: "50%", background: color, color: "white", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 11, fontWeight: 800 }}>{score}</div>
      <div style={{ width: 60, height: 6, background: "#f1f5f9", borderRadius: 3, overflow: "hidden" }}>
        <div style={{ width: `${score}%`, height: "100%", background: color, borderRadius: 3 }} />
      </div>
    </div>
  );
}

function AddContactModal({ onClose, onAdd }) {
  const [form, setForm] = useState({ name: "", email: "", phone: "", budget: "", stage: "New Lead", temperature: "Warm", preApproved: false, notes: "", tags: "", source: "Organic" });
  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));
  const handleSubmit = () => {
    if (!form.name.trim()) return;
    onAdd({ id: Date.now(), ...form, budget: parseInt(form.budget.replace(/\D/g, "")) || 0, tags: form.tags ? form.tags.split(",").map(t => t.trim()).filter(Boolean) : [], interest: [], lastContact: new Date().toISOString().split("T")[0], agent: "Gerald", score: 40, lastActivity: "Added manually" });
    onClose();
  };
  const inp = { width: "100%", background: "white", border: "1px solid #e2e8f0", color: "#1e293b", borderRadius: 6, padding: "9px 12px", fontSize: 13, outline: "none", fontFamily: "inherit", boxSizing: "border-box" };
  const lbl = { color: "#64748b", fontSize: 12, fontWeight: 600, display: "block", marginBottom: 5 };
  return (
    <div style={{ position: "fixed", inset: 0, background: "rgba(15,23,42,0.5)", zIndex: 200, display: "flex", alignItems: "center", justifyContent: "center" }}>
      <div style={{ background: "white", borderRadius: 12, width: 520, maxHeight: "90vh", overflow: "auto", boxShadow: "0 20px 60px rgba(0,0,0,0.2)" }}>
        <div style={{ padding: "20px 24px", borderBottom: "1px solid #f1f5f9", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
          <div>
            <div style={{ color: "#0f172a", fontSize: 16, fontWeight: 700 }}>Add New Contact</div>
            <div style={{ color: "#94a3b8", fontSize: 12, marginTop: 2 }}>Lead will be added to your pipeline</div>
          </div>
          <button onClick={onClose} style={{ background: "#f8fafc", border: "1px solid #e2e8f0", borderRadius: 6, width: 30, height: 30, cursor: "pointer", fontSize: 16, color: "#64748b", display: "flex", alignItems: "center", justifyContent: "center" }}>✕</button>
        </div>
        <div style={{ padding: 24 }}>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14, marginBottom: 14 }}>
            <div style={{ gridColumn: "1/-1" }}>
              <label style={lbl}>Full Name *</label>
              <input value={form.name} onChange={e => set("name", e.target.value)} placeholder="e.g. John & Jane Smith" style={inp} />
            </div>
            <div><label style={lbl}>Email</label><input value={form.email} onChange={e => set("email", e.target.value)} placeholder="email@example.com" style={inp} /></div>
            <div><label style={lbl}>Phone</label><input value={form.phone} onChange={e => set("phone", e.target.value)} placeholder="(512) 000-0000" style={inp} /></div>
            <div><label style={lbl}>Budget</label><input value={form.budget} onChange={e => set("budget", e.target.value)} placeholder="e.g. 750000" style={inp} /></div>
            <div>
              <label style={lbl}>Lead Source</label>
              <select value={form.source} onChange={e => set("source", e.target.value)} style={{ ...inp, cursor: "pointer" }}>
                {["Zillow", "Google Ads", "Facebook Ads", "Referral", "Organic", "Other"].map(s => <option key={s}>{s}</option>)}
              </select>
            </div>
            <div>
              <label style={lbl}>Pipeline Stage</label>
              <select value={form.stage} onChange={e => set("stage", e.target.value)} style={{ ...inp, cursor: "pointer" }}>
                {PIPELINE_STAGES.map(s => <option key={s}>{s}</option>)}
              </select>
            </div>
          </div>
          <div style={{ marginBottom: 14 }}>
            <label style={lbl}>Lead Temperature</label>
            <div style={{ display: "flex", gap: 8 }}>
              {["Hot", "Warm", "Cold"].map(t => {
                const cfg = tempConfig[t];
                return (
                  <button key={t} onClick={() => set("temperature", t)} style={{ flex: 1, padding: "10px 8px", borderRadius: 8, border: `2px solid ${form.temperature === t ? cfg.color : "#e2e8f0"}`, background: form.temperature === t ? cfg.bg : "white", cursor: "pointer", color: form.temperature === t ? cfg.color : "#94a3b8", fontSize: 13, fontWeight: 700, fontFamily: "inherit" }}>
                    {cfg.icon} {t}
                  </button>
                );
              })}
            </div>
          </div>
          <div style={{ marginBottom: 14 }}>
            <label style={lbl}>Tags (comma separated)</label>
            <input value={form.tags} onChange={e => set("tags", e.target.value)} placeholder="First Time Buyer, Pre-Approved" style={inp} />
          </div>
          <div style={{ marginBottom: 14 }}>
            <label style={{ display: "flex", alignItems: "center", gap: 8, cursor: "pointer", color: "#475569", fontSize: 13 }}>
              <input type="checkbox" checked={form.preApproved} onChange={e => set("preApproved", e.target.checked)} style={{ width: 15, height: 15, accentColor: "#6366f1" }} />
              Pre-Approved for Mortgage
            </label>
          </div>
          <div style={{ marginBottom: 20 }}>
            <label style={lbl}>Notes</label>
            <textarea value={form.notes} onChange={e => set("notes", e.target.value)} placeholder="Notes about this lead..." rows={3} style={{ ...inp, resize: "vertical", lineHeight: 1.6 }} />
          </div>
          <div style={{ display: "flex", gap: 10 }}>
            <button onClick={onClose} style={{ flex: 1, background: "white", border: "1px solid #e2e8f0", color: "#64748b", borderRadius: 6, padding: "11px", fontSize: 13, fontWeight: 600, cursor: "pointer", fontFamily: "inherit" }}>Cancel</button>
            <button onClick={handleSubmit} style={{ flex: 2, background: "#6366f1", border: "none", color: "white", borderRadius: 6, padding: "11px", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>Add Contact</button>
          </div>
        </div>
      </div>
    </div>
  );
}

