function MarketReports() {
  const [zip, setZip] = useState("77598");
  const [customZip, setCustomZip] = useState("");
  const data = MARKET_DATA[zip];

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#f8fafc" }}>
      <TopBar title="Market Reports" sub="Houston area real estate market snapshots" action={
        <button style={{ background: "#6366f1", border: "none", color: "white", borderRadius: 7, padding: "9px 18px", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>Export PDF</button>
      } />
      <div style={{ padding: "14px 24px", background: "white", borderBottom: "1px solid #f1f5f9", display: "flex", gap: 10, alignItems: "center" }}>
        <span style={{ color: "#64748b", fontSize: 13, fontWeight: 600 }}>ZIP Code:</span>
        <select value={zip} onChange={e => setZip(e.target.value)} style={{ background: "#f8fafc", border: "1px solid #e2e8f0", color: "#0f172a", borderRadius: 6, padding: "7px 12px", fontSize: 13, outline: "none", cursor: "pointer", fontFamily: "inherit", maxWidth: 280 }}>
          {Object.entries(MARKET_DATA).map(([z, d]) => (
            <option key={z} value={z}>{z} — {d.area}</option>
          ))}
        </select>
        <div style={{ display: "flex", gap: 6, marginLeft: 8 }}>
          <input value={customZip} onChange={e => setCustomZip(e.target.value)} placeholder="Enter ZIP..." style={{ background: "#f8fafc", border: "1px solid #e2e8f0", color: "#0f172a", borderRadius: 6, padding: "6px 12px", fontSize: 12, outline: "none", width: 110, fontFamily: "inherit" }} />
          <button onClick={() => customZip && setZip(customZip)} style={{ background: "#f8fafc", border: "1px solid #e2e8f0", color: "#475569", borderRadius: 6, padding: "6px 12px", fontSize: 12, cursor: "pointer" }}>Go</button>
        </div>
      </div>

      {data ? (
        <div style={{ flex: 1, overflow: "auto", padding: 24 }}>
          <div style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 12, padding: "24px 28px", marginBottom: 20, boxShadow: "0 1px 4px rgba(0,0,0,0.04)" }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 20 }}>
              <div>
                <div style={{ color: "#0f172a", fontSize: 20, fontWeight: 800 }}>{zip} — {data.area}</div>
                <div style={{ color: "#94a3b8", fontSize: 13, marginTop: 4 }}>Market snapshot · May 2026</div>
              </div>
              <div style={{ background: data.priceChange > 0 ? "#dcfce7" : "#fef2f2", color: data.priceChange > 0 ? "#16a34a" : "#dc2626", fontSize: 14, fontWeight: 800, padding: "8px 16px", borderRadius: 8 }}>
                {data.priceChange > 0 ? "▲" : "▼"} {Math.abs(data.priceChange)}% YoY
              </div>
            </div>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 14 }}>
              {[["Median Price", fmt(data.medianPrice), "#6366f1"], ["Avg Days on Market", data.avgDOM + " days", "#f59e0b"], ["Active Listings", data.activeListings, "#0ea5e9"], ["Sold Last 30 Days", data.soldLast30, "#10b981"], ["Price/Sqft", "$" + data.avgSqftPrice, "#8b5cf6"], ["Absorption Rate", data.absorption + " months", "#f97316"]].map(([k,v,c]) => (
                <div key={k} style={{ background: "#f8fafc", borderRadius: 8, padding: "16px 18px" }}>
                  <div style={{ color: "#94a3b8", fontSize: 10, fontWeight: 700, textTransform: "uppercase", letterSpacing: "0.06em", marginBottom: 8 }}>{k}</div>
                  <div style={{ color: c, fontSize: 22, fontWeight: 800 }}>{v}</div>
                </div>
              ))}
            </div>
          </div>

          <div style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 12, padding: "24px 28px", boxShadow: "0 1px 4px rgba(0,0,0,0.04)" }}>
            <div style={{ color: "#0f172a", fontSize: 14, fontWeight: 700, marginBottom: 16 }}>📋 Market Summary — Ready to Send to Clients</div>
            <div style={{ background: "#f8fafc", border: "1px solid #f1f5f9", borderRadius: 8, padding: "18px 20px", fontFamily: "inherit" }}>
              <pre style={{ color: "#475569", fontSize: 13, lineHeight: 1.9, margin: 0, whiteSpace: "pre-wrap", fontFamily: "inherit" }}>{`Houston Real Estate Market Update — ${zip} (${data.area})
May 2026

Hi [Client Name],

Here's a quick snapshot of what's happening in the ${data.area} market:

📊 Median Sale Price:    ${fmt(data.medianPrice)}
⏱  Avg Days on Market:  ${data.avgDOM} days
🏠 Active Listings:      ${data.activeListings} homes
✅ Sold Last 30 Days:    ${data.soldLast30} homes
💰 Price per Sq Ft:     $${data.avgSqftPrice}
📈 Year-over-Year:      ${data.priceChange > 0 ? "+" : ""}${data.priceChange}%
🔄 Absorption Rate:     ${data.absorption} months

${data.absorption < 3 ? "This is a strong seller's market — inventory is low and homes are moving fast." : "The market is balanced, giving buyers more options and negotiating room."}

Would you like to discuss what this means for your home's value? I'd be happy to schedule a free consultation.

Best,
Gerald`}</pre>
            </div>
          </div>
        </div>
      ) : (
        <div style={{ flex: 1, display: "flex", alignItems: "center", justifyContent: "center" }}>
          <div style={{ textAlign: "center", color: "#94a3b8" }}>
            <div style={{ fontSize: 40, marginBottom: 12 }}>📊</div>
            <div style={{ fontSize: 15, fontWeight: 600, marginBottom: 4 }}>No data for ZIP {zip}</div>
            <div style={{ fontSize: 13 }}>Try one of the preset ZIPs above, or connect PropStream for live data.</div>
          </div>
        </div>
      )}
    </div>
  );
}

// ─── Calendar ─────────────────────────────────────────────────────────────────
const INIT_EVENTS = [
  { id: 1, title: "Showing — 2847 Maple Grove Ln", date: "2026-05-26", time: "2:00 PM", type: "showing", contact: "Marcus & Elena Rivera", reminder: true },
  { id: 2, title: "Call — Dr. James Thornton", date: "2026-05-25", time: "11:00 AM", type: "call", contact: "Dr. James Thornton", reminder: true },
  { id: 3, title: "Offer Review — Priya Nair", date: "2026-05-27", time: "5:00 PM", type: "offer", contact: "Priya Nair", reminder: false },
  { id: 4, title: "Closing — Cedar Ridge Ct", date: "2026-05-28", time: "10:00 AM", type: "closing", contact: "The Kowalski Family", reminder: true },
  { id: 5, title: "Follow-up call — Alex Oduya", date: "2026-06-01", time: "3:00 PM", type: "call", contact: "Alex & Sam Oduya", reminder: false },
  { id: 6, title: "CMA Presentation — Hoffmann", date: "2026-06-03", time: "1:00 PM", type: "meeting", contact: "Gary & Susan Hoffmann", reminder: true },
];

const eventColors = { showing: "#8b5cf6", call: "#0ea5e9", offer: "#ec4899", closing: "#10b981", meeting: "#f59e0b", reminder: "#6366f1" };

function CalendarView() {
  const [events, setEvents] = useState(INIT_EVENTS);
  const [showAdd, setShowAdd] = useState(false);
  const [form, setForm] = useState({ title: "", date: "", time: "", type: "call", contact: "", reminder: false });
  const [viewMonth] = useState("May 2026");

  const days = Array.from({length: 31}, (_, i) => i + 1);
  const inp = { background: "#f8fafc", border: "1px solid #e2e8f0", color: "#0f172a", borderRadius: 6, padding: "9px 12px", fontSize: 13, outline: "none", fontFamily: "inherit", width: "100%", boxSizing: "border-box" };

  const addEvent = () => {
    setEvents(p => [...p, { ...form, id: Date.now() }]);
    setShowAdd(false);
    setForm({ title: "", date: "", time: "", type: "call", contact: "", reminder: false });
  };

  const upcomingEvents = events.sort((a,b) => a.date.localeCompare(b.date));

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#f8fafc" }}>
      <TopBar title="Calendar" sub="Schedule and manage your activities" action={
        <button onClick={() => setShowAdd(!showAdd)} style={{ background: "#6366f1", border: "none", color: "white", borderRadius: 7, padding: "9px 18px", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>+ Add Event</button>
      } />

      {showAdd && (
        <div style={{ background: "white", borderBottom: "1px solid #f1f5f9", padding: "18px 24px" }}>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(5,1fr)", gap: 12, marginBottom: 12 }}>
            <div style={{ gridColumn: "1/3" }}><label style={{ color: "#64748b", fontSize: 11, fontWeight: 600, display: "block", marginBottom: 4 }}>Event Title</label><input value={form.title} onChange={e => setForm(f=>({...f,title:e.target.value}))} placeholder="e.g. Showing — 123 Main St" style={inp} /></div>
            <div><label style={{ color: "#64748b", fontSize: 11, fontWeight: 600, display: "block", marginBottom: 4 }}>Date</label><input type="date" value={form.date} onChange={e => setForm(f=>({...f,date:e.target.value}))} style={inp} /></div>
            <div><label style={{ color: "#64748b", fontSize: 11, fontWeight: 600, display: "block", marginBottom: 4 }}>Time</label><input value={form.time} onChange={e => setForm(f=>({...f,time:e.target.value}))} placeholder="e.g. 2:00 PM" style={inp} /></div>
            <div><label style={{ color: "#64748b", fontSize: 11, fontWeight: 600, display: "block", marginBottom: 4 }}>Type</label><select value={form.type} onChange={e => setForm(f=>({...f,type:e.target.value}))} style={{...inp,cursor:"pointer"}}>{["call","showing","offer","closing","meeting","reminder"].map(t=><option key={t}>{t}</option>)}</select></div>
          </div>
          <div style={{ display: "flex", gap: 10, alignItems: "center" }}>
            <button onClick={addEvent} style={{ background: "#6366f1", border: "none", color: "white", borderRadius: 7, padding: "9px 20px", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>Save Event</button>
            <button onClick={() => setShowAdd(false)} style={{ background: "white", border: "1px solid #e2e8f0", color: "#64748b", borderRadius: 7, padding: "9px 14px", fontSize: 13, cursor: "pointer", fontFamily: "inherit" }}>Cancel</button>
            <label style={{ display: "flex", alignItems: "center", gap: 6, color: "#475569", fontSize: 13, cursor: "pointer" }}>
              <input type="checkbox" checked={form.reminder} onChange={e => setForm(f=>({...f,reminder:e.target.checked}))} style={{ accentColor: "#6366f1" }} />Set Reminder
            </label>
          </div>
        </div>
      )}

      <div style={{ flex: 1, display: "flex", overflow: "hidden" }}>
        {/* Mini calendar grid */}
        <div style={{ width: 320, background: "white", borderRight: "1px solid #f1f5f9", padding: 20, flexShrink: 0, overflow: "auto" }}>
          <div style={{ color: "#0f172a", fontSize: 15, fontWeight: 800, marginBottom: 16, textAlign: "center" }}>{viewMonth}</div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(7,1fr)", gap: 4, marginBottom: 8 }}>
            {["Su","Mo","Tu","We","Th","Fr","Sa"].map(d => <div key={d} style={{ textAlign: "center", color: "#94a3b8", fontSize: 10, fontWeight: 700 }}>{d}</div>)}
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(7,1fr)", gap: 4 }}>
            {/* May 2026 starts on Friday — offset 5 */}
            {Array(5).fill(null).map((_,i) => <div key={"e"+i} />)}
            {days.map(d => {
              const dateStr = `2026-05-${String(d).padStart(2,"0")}`;
              const hasEvent = events.some(e => e.date === dateStr);
              const isToday = d === 25;
              return (
                <div key={d} style={{ width: "100%", aspectRatio: "1", borderRadius: 6, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 12, fontWeight: isToday ? 800 : 400, background: isToday ? "#6366f1" : hasEvent ? "#eef2ff" : "transparent", color: isToday ? "white" : hasEvent ? "#6366f1" : "#475569", position: "relative", cursor: "pointer" }}>
                  {d}
                  {hasEvent && !isToday && <div style={{ position: "absolute", bottom: 2, left: "50%", transform: "translateX(-50%)", width: 4, height: 4, borderRadius: "50%", background: "#6366f1" }} />}
                </div>
              );
            })}
          </div>

          <div style={{ marginTop: 20 }}>
            <div style={{ color: "#475569", fontSize: 11, fontWeight: 700, textTransform: "uppercase", letterSpacing: "0.06em", marginBottom: 10 }}>Legend</div>
            {Object.entries(eventColors).map(([type, color]) => (
              <div key={type} style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 6 }}>
                <div style={{ width: 10, height: 10, borderRadius: 2, background: color, flexShrink: 0 }} />
                <span style={{ color: "#64748b", fontSize: 12, textTransform: "capitalize" }}>{type}</span>
              </div>
            ))}
          </div>
        </div>

        {/* Event list */}
        <div style={{ flex: 1, overflow: "auto", padding: 20 }}>
          <div style={{ color: "#475569", fontSize: 12, fontWeight: 700, textTransform: "uppercase", letterSpacing: "0.06em", marginBottom: 14 }}>All Upcoming Events</div>
          {upcomingEvents.map(e => {
            const color = eventColors[e.type] || "#6366f1";
            return (
              <div key={e.id} style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 10, padding: "14px 18px", marginBottom: 10, display: "flex", alignItems: "center", gap: 16, boxShadow: "0 1px 3px rgba(0,0,0,0.04)" }}>
                <div style={{ width: 44, height: 44, borderRadius: 10, background: color+"18", border: `1px solid ${color}30`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 18, flexShrink: 0 }}>
                  {e.type === "showing" ? "🏠" : e.type === "closing" ? "🔑" : e.type === "offer" ? "📋" : e.type === "meeting" ? "🤝" : e.type === "reminder" ? "🔔" : "📞"}
                </div>
                <div style={{ flex: 1 }}>
                  <div style={{ color: "#0f172a", fontSize: 14, fontWeight: 700, marginBottom: 2 }}>{e.title}</div>
                  <div style={{ color: "#94a3b8", fontSize: 12 }}>{e.contact && e.contact + " · "}{e.date} at {e.time}</div>
                </div>
                {e.reminder && <div style={{ background: "#eef2ff", color: "#6366f1", fontSize: 10, fontWeight: 700, padding: "3px 9px", borderRadius: 10 }}>🔔 REMINDER</div>}
                <span style={{ background: color+"18", color, fontSize: 11, fontWeight: 700, padding: "3px 9px", borderRadius: 4, textTransform: "capitalize", whiteSpace: "nowrap" }}>{e.type}</span>
                <button onClick={() => setEvents(p => p.filter(ev => ev.id !== e.id))} style={{ background: "transparent", border: "none", color: "#cbd5e1", cursor: "pointer", fontSize: 16, padding: 4 }}>✕</button>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

