const INIT_TEAM = [
  { id: 1, name: "Gerald", role: "Lead Agent", email: "gerald@estateiq.com", phone: "(713) 555-0100", status: "Active", listings: 6, leads: 5, closedYTD: 3, volume: 1865000, img: "G" },
  { id: 2, name: "Sarah Chen", role: "Buyer Agent", email: "s.chen@estateiq.com", phone: "(713) 555-0101", status: "Active", listings: 2, leads: 8, closedYTD: 4, volume: 1420000, img: "S" },
  { id: 3, name: "Marcus Webb", role: "Listing Agent", email: "m.webb@estateiq.com", phone: "(713) 555-0102", status: "Active", listings: 4, leads: 6, closedYTD: 5, volume: 2100000, img: "M" },
  { id: 4, name: "Jenna Park", role: "Transaction Coordinator", email: "j.park@estateiq.com", phone: "(713) 555-0103", status: "Active", listings: 0, leads: 0, closedYTD: 12, volume: 0, img: "J" },
];

function Team() {
  const [team, setTeam] = useState(INIT_TEAM);
  const [selected, setSelected] = useState(null);
  const [showAdd, setShowAdd] = useState(false);
  const [form, setForm] = useState({ name: "", role: "", email: "", phone: "", status: "Active" });

  const inp = { background: "#f8fafc", border: "1px solid #e2e8f0", color: "#0f172a", borderRadius: 6, padding: "9px 12px", fontSize: 13, outline: "none", fontFamily: "inherit", width: "100%", boxSizing: "border-box" };
  const avatarColors = ["#6366f1","#10b981","#f59e0b","#ec4899","#8b5cf6","#0ea5e9"];
  const totalVolume = team.reduce((s,m) => s + m.volume, 0);

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#f8fafc" }}>
      <TopBar title="Team" sub={`${team.length} team members · $${(totalVolume/1e6).toFixed(1)}M total volume YTD`} action={
        <button onClick={() => setShowAdd(!showAdd)} style={{ background: "#6366f1", border: "none", color: "white", borderRadius: 7, padding: "9px 18px", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>+ Add Member</button>
      } />

      {showAdd && (
        <div style={{ background: "white", borderBottom: "1px solid #f1f5f9", padding: "18px 24px" }}>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(5,1fr)", gap: 12, marginBottom: 12 }}>
            {[["Name","name","Full name"],["Role","role","e.g. Buyer Agent"],["Email","email","email@domain.com"],["Phone","phone","(713) 555-0000"],["Status","status","Active"]].map(([label,key,placeholder]) => (
              <div key={key}><label style={{ color: "#64748b", fontSize: 11, fontWeight: 600, display: "block", marginBottom: 4 }}>{label}</label><input value={form[key]} onChange={e => setForm(f=>({...f,[key]:e.target.value}))} placeholder={placeholder} style={inp} /></div>
            ))}
          </div>
          <div style={{ display: "flex", gap: 10 }}>
            <button onClick={() => { setTeam(p => [...p, {...form, id: Date.now(), listings:0, leads:0, closedYTD:0, volume:0, img: form.name[0]||"?" }]); setShowAdd(false); }} style={{ background: "#6366f1", border: "none", color: "white", borderRadius: 7, padding: "9px 20px", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>Add Member</button>
            <button onClick={() => setShowAdd(false)} style={{ background: "white", border: "1px solid #e2e8f0", color: "#64748b", borderRadius: 7, padding: "9px 14px", fontSize: 13, cursor: "pointer", fontFamily: "inherit" }}>Cancel</button>
          </div>
        </div>
      )}

      <div style={{ flex: 1, overflow: "auto", padding: 24 }}>
        {/* Summary stats */}
        <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 14, marginBottom: 24 }}>
          {[["Team Members", team.length, "#6366f1"], ["Total Leads", team.reduce((s,m)=>s+m.leads,0), "#0ea5e9"], ["Closed YTD", team.reduce((s,m)=>s+m.closedYTD,0), "#10b981"], ["Total Volume", "$"+(totalVolume/1e6).toFixed(1)+"M", "#f59e0b"]].map(([l,v,c]) => (
            <div key={l} style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 10, padding: "18px 20px", boxShadow: "0 1px 3px rgba(0,0,0,0.04)" }}>
              <div style={{ color: "#94a3b8", fontSize: 11, fontWeight: 700, textTransform: "uppercase", letterSpacing: "0.06em", marginBottom: 8 }}>{l}</div>
              <div style={{ color: c, fontSize: 28, fontWeight: 800 }}>{v}</div>
            </div>
          ))}
        </div>

        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(300px,1fr))", gap: 16 }}>
          {team.map((m, idx) => (
            <div key={m.id} onClick={() => setSelected(selected?.id === m.id ? null : m)} style={{ background: "white", border: `2px solid ${selected?.id === m.id ? "#6366f1" : "#f1f5f9"}`, borderRadius: 12, padding: "20px 22px", cursor: "pointer", boxShadow: "0 1px 4px rgba(0,0,0,0.04)", transition: "all 0.15s" }}>
              <div style={{ display: "flex", alignItems: "center", gap: 14, marginBottom: 16 }}>
                <div style={{ width: 48, height: 48, borderRadius: "50%", background: avatarColors[idx % avatarColors.length], color: "white", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 18, fontWeight: 800, flexShrink: 0 }}>{m.img}</div>
                <div>
                  <div style={{ color: "#0f172a", fontSize: 15, fontWeight: 800 }}>{m.name}</div>
                  <div style={{ color: "#64748b", fontSize: 12 }}>{m.role}</div>
                </div>
                <div style={{ marginLeft: "auto", background: "#dcfce7", color: "#16a34a", fontSize: 10, fontWeight: 700, padding: "3px 9px", borderRadius: 10 }}>{m.status}</div>
              </div>
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 8 }}>
                {[["Listings", m.listings], ["Leads", m.leads], ["Closed", m.closedYTD]].map(([k,v]) => (
                  <div key={k} style={{ background: "#f8fafc", borderRadius: 6, padding: "8px 10px", textAlign: "center" }}>
                    <div style={{ color: "#94a3b8", fontSize: 10, fontWeight: 700, textTransform: "uppercase" }}>{k}</div>
                    <div style={{ color: "#0f172a", fontSize: 18, fontWeight: 800 }}>{v}</div>
                  </div>
                ))}
              </div>
              {m.volume > 0 && <div style={{ marginTop: 10, color: "#6366f1", fontSize: 13, fontWeight: 700, textAlign: "center" }}>Volume YTD: {fmt(m.volume)}</div>}
              <div style={{ marginTop: 10, color: "#94a3b8", fontSize: 11, textAlign: "center" }}>{m.email} · {m.phone}</div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}


// ─── IDX / MLS Feed Config ────────────────────────────────────────────────────
// Supports iHomeFinder, IDX Broker, Showcase IDX, and RETS/RESO feeds
// Fill in your credentials below once you receive them from your IDX vendor
const IDX_CONFIG = {
  vendor: null,           // "ihomefinder" | "idxbroker" | "showcase" | "rets"
  apiKey: null,           // Your IDX API key — paste here when ready
  partnerId: null,        // iHomeFinder partner ID (if applicable)
  mlsId: "HAR",          // Houston Association of Realtors
  defaultZip: "77598",   // Default search ZIP
  connected: false,
};

// IDX vendor API endpoints
const IDX_ENDPOINTS = {
  ihomefinder: "https://api.ihomefinder.com/v1/listing/search",
  idxbroker:   "https://api.idxbroker.com/clients/listings",
  showcase:    "https://api.showcaseidx.com/v2/listings",
};

async function fetchIDXListings(zip = "77598", filters = {}) {
  if (!IDX_CONFIG.connected || !IDX_CONFIG.apiKey) return null;
  try {
    const endpoint = IDX_ENDPOINTS[IDX_CONFIG.vendor];
    if (!endpoint) return null;
    const params = new URLSearchParams({ zip, limit: 50, ...filters });
    const res = await fetch(`${endpoint}?${params}`, {
      headers: {
        "Authorization": `Bearer ${IDX_CONFIG.apiKey}`,
        "Content-Type": "application/json",
      }
    });
    if (!res.ok) return null;
    const data = await res.json();
    return (data.listings || data.results || data.data || []).map(l => ({
      id: l.listingId || l.id || l.mlsId,
      address: l.address?.full || l.streetAddress || l.address,
      city: l.address?.city || l.city,
      state: l.address?.state || l.state || "TX",
      zip: l.address?.zip || l.zipCode || zip,
      price: parseInt(l.listPrice || l.price) || 0,
      beds: parseInt(l.bedrooms || l.beds) || 0,
      baths: parseFloat(l.bathrooms || l.baths) || 0,
      sqft: parseInt(l.livingArea || l.sqft) || 0,
      type: l.propertyType || l.type || "Single Family",
      status: l.standardStatus || l.status || "Active",
      daysOnMarket: parseInt(l.daysOnMarket || l.dom) || 0,
      img: l.photos?.[0]?.url || l.primaryPhoto || l.imageUrl || "https://images.unsplash.com/photo-1564013799919-ab600027ffc6?w=400&q=80",
      views: 0,
      saves: 0,
      mlsNumber: l.listingId || l.mlsId,
    }));
  } catch { return null; }
}


