const FARM_HOMES = [
  { id: 1, address: "18342 Heritage Park Dr", owner: "Gary & Susan Hoffmann", yearsOwned: 18, estValue: 385000, equity: 79, lastContact: "2026-05-10", contacted: true, status: "Hot" },
  { id: 2, address: "2104 Pipers Meadow Dr", owner: "Maria Contreras", yearsOwned: 12, estValue: 310000, equity: 61, lastContact: null, contacted: false, status: "Not Contacted" },
  { id: 3, address: "716 Edgewater Blvd", owner: "James & Beverly Tran", yearsOwned: 24, estValue: 460000, equity: 88, lastContact: "2026-04-22", contacted: true, status: "Warm" },
  { id: 4, address: "19803 Sterling Knoll Ln", owner: "Derek & Alicia Fontenot", yearsOwned: 7, estValue: 355000, equity: 53, lastContact: null, contacted: false, status: "Not Contacted" },
  { id: 5, address: "1422 Walnut Place Dr", owner: "Pat & Linda Okonkwo", yearsOwned: 14, estValue: 330000, equity: 66, lastContact: "2026-05-01", contacted: true, status: "Warm" },
  { id: 6, address: "17940 Webdale St", owner: "Carl & Debra Simmons", yearsOwned: 21, estValue: 298000, equity: 71, lastContact: null, contacted: false, status: "Not Contacted" },
  { id: 7, address: "504 Clear Creek Shores Blvd", owner: "Tom & Gail Burford", yearsOwned: 29, estValue: 520000, equity: 92, lastContact: "2026-03-15", contacted: true, status: "Cold" },
  { id: 8, address: "250 El Dorado Blvd #118", owner: "Robert Nguyen", yearsOwned: 9, estValue: 195000, equity: 44, lastContact: null, contacted: false, status: "Not Contacted" },
];

function FarmTracker() {
  const [homes, setHomes] = useState(FARM_HOMES);
  const [filterStatus, setFilterStatus] = useState("All");
  const statusColors = { "Hot": "#ef4444", "Warm": "#f97316", "Cold": "#0ea5e9", "Not Contacted": "#94a3b8" };
  const filtered = homes.filter(h => filterStatus === "All" || h.status === filterStatus);
  const contacted = homes.filter(h => h.contacted).length;
  const pct = Math.round((contacted / homes.length) * 100);

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#f8fafc" }}>
      <TopBar title="Farm Tracker — 77598" sub="Track every home in your target farm area" action={
        <button style={{ background: "#6366f1", border: "none", color: "white", borderRadius: 7, padding: "9px 18px", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>+ Add Home</button>
      } />
      <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 14, padding: "14px 24px", background: "white", borderBottom: "1px solid #f1f5f9" }}>
        {[["Total Homes", homes.length, "#6366f1"], ["Contacted", contacted, "#10b981"], ["Coverage", pct + "%", "#f59e0b"], ["Hot Prospects", homes.filter(h=>h.status==="Hot").length, "#ef4444"]].map(([l,v,c]) => (
          <div key={l} style={{ textAlign: "center" }}>
            <div style={{ color: c, fontSize: 24, fontWeight: 800 }}>{v}</div>
            <div style={{ color: "#0f172a", fontSize: 12, fontWeight: 600 }}>{l}</div>
          </div>
        ))}
      </div>
      <div style={{ padding: "10px 20px", background: "white", borderBottom: "1px solid #f1f5f9", display: "flex", gap: 8 }}>
        {["All", "Hot", "Warm", "Cold", "Not Contacted"].map(s => (
          <button key={s} onClick={() => setFilterStatus(s)} style={{ padding: "5px 12px", borderRadius: 6, border: `1px solid ${filterStatus === s ? (statusColors[s]||"#6366f1") : "#e2e8f0"}`, background: filterStatus === s ? (statusColors[s]||"#6366f1")+"15" : "white", color: filterStatus === s ? (statusColors[s]||"#6366f1") : "#64748b", fontSize: 11, fontWeight: 600, cursor: "pointer" }}>{s}</button>
        ))}
      </div>
      <div style={{ flex: 1, overflow: "auto" }}>
        <table style={{ width: "100%", borderCollapse: "collapse" }}>
          <thead>
            <tr style={{ background: "#f8fafc", borderBottom: "1px solid #f1f5f9" }}>
              {["Address", "Owner", "Years Owned", "Est. Value", "Equity", "Status", "Last Contact", ""].map(h => (
                <th key={h} style={{ padding: "10px 16px", color: "#94a3b8", fontSize: 11, fontWeight: 700, textAlign: "left", letterSpacing: "0.05em", textTransform: "uppercase" }}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {filtered.map(h => (
              <tr key={h.id} style={{ borderBottom: "1px solid #f8fafc", background: "white" }}>
                <td style={{ padding: "13px 16px", color: "#0f172a", fontSize: 13, fontWeight: 600 }}>{h.address}</td>
                <td style={{ padding: "13px 16px", color: "#475569", fontSize: 13 }}>{h.owner}</td>
                <td style={{ padding: "13px 16px", color: "#475569", fontSize: 13 }}>{h.yearsOwned} yrs</td>
                <td style={{ padding: "13px 16px", color: "#6366f1", fontWeight: 700, fontSize: 13 }}>{fmt(h.estValue)}</td>
                <td style={{ padding: "13px 16px" }}>
                  <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
                    <div style={{ width: 40, height: 5, background: "#f1f5f9", borderRadius: 3, overflow: "hidden" }}><div style={{ width: h.equity + "%", height: "100%", background: "#10b981" }} /></div>
                    <span style={{ color: "#10b981", fontSize: 12, fontWeight: 700 }}>{h.equity}%</span>
                  </div>
                </td>
                <td style={{ padding: "13px 16px" }}><span style={{ background: (statusColors[h.status]||"#94a3b8")+"18", color: statusColors[h.status]||"#94a3b8", fontSize: 11, fontWeight: 700, padding: "3px 9px", borderRadius: 4 }}>{h.status}</span></td>
                <td style={{ padding: "13px 16px", color: "#94a3b8", fontSize: 12 }}>{h.lastContact || "Never"}</td>
                <td style={{ padding: "13px 16px" }}>
                  <button onClick={() => setHomes(p => p.map(hm => hm.id === h.id ? {...hm, contacted: true, lastContact: new Date().toISOString().split("T")[0], status: hm.status === "Not Contacted" ? "Cold" : hm.status} : hm))} style={{ background: "#6366f1", border: "none", color: "white", borderRadius: 6, padding: "5px 12px", fontSize: 11, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>Log Contact</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

// ─── Social Media Scheduler ───────────────────────────────────────────────────
const INIT_POSTS = [
  { id: 1, platform: "Instagram", content: "Just listed! 🏠 2847 Maple Grove Ln — 4 bed / 3 bath / 2,840 sqft. Listed at $875,000. DM me for a showing! #HoustonRealEstate #JustListed", image: "https://images.unsplash.com/photo-1564013799919-ab600027ffc6?w=400&q=80", scheduledFor: "2026-05-26 9:00 AM", status: "Scheduled" },
  { id: 2, platform: "Facebook", content: "The Houston real estate market is moving fast! Median price in 77598 is up 3.1% year over year. Thinking of selling? Let's talk about your home's value. 📞 Call Gerald today!", image: null, scheduledFor: "2026-05-27 11:00 AM", status: "Scheduled" },
  { id: 3, platform: "LinkedIn", content: "Closed another one! 🎉 Proud to have helped The Kowalski Family find their perfect home in Cedar Ridge. If you or someone you know is buying or selling in Houston, I'd love to help.", image: null, scheduledFor: "2026-05-25 2:00 PM", status: "Posted" },
];

function SocialScheduler() {
  const [posts, setPosts] = useState(INIT_POSTS);
  const [showAdd, setShowAdd] = useState(false);
  const [form, setForm] = useState({ platform: "Instagram", content: "", scheduledFor: "", status: "Scheduled" });
  const platformColors = { Instagram: "#e1306c", Facebook: "#1877f2", LinkedIn: "#0a66c2" };
  const platformIcons = { Instagram: "📷", Facebook: "👥", LinkedIn: "💼" };
  const inp = { background: "#f8fafc", border: "1px solid #e2e8f0", color: "#0f172a", borderRadius: 6, padding: "9px 12px", fontSize: 13, outline: "none", fontFamily: "inherit", width: "100%", boxSizing: "border-box" };

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#f8fafc" }}>
      <TopBar title="Social Media Scheduler" sub="Schedule listing posts to Facebook, Instagram & LinkedIn" action={
        <button onClick={() => setShowAdd(!showAdd)} style={{ background: "#6366f1", border: "none", color: "white", borderRadius: 7, padding: "9px 18px", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>+ Schedule Post</button>
      } />
      {showAdd && (
        <div style={{ background: "white", borderBottom: "1px solid #f1f5f9", padding: "18px 24px" }}>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 2fr 1fr", gap: 12, marginBottom: 12 }}>
            <div>
              <div style={{ color: "#64748b", fontSize: 11, fontWeight: 600, marginBottom: 5 }}>Platform</div>
              <select value={form.platform} onChange={e=>setForm(f=>({...f,platform:e.target.value}))} style={{...inp,cursor:"pointer"}}>
                <option>Instagram</option><option>Facebook</option><option>LinkedIn</option>
              </select>
            </div>
            <div>
              <div style={{ color: "#64748b", fontSize: 11, fontWeight: 600, marginBottom: 5 }}>Post Content</div>
              <textarea value={form.content} onChange={e=>setForm(f=>({...f,content:e.target.value}))} rows={3} style={{...inp,resize:"vertical"}} placeholder="Write your post..." />
            </div>
            <div>
              <div style={{ color: "#64748b", fontSize: 11, fontWeight: 600, marginBottom: 5 }}>Schedule For</div>
              <input value={form.scheduledFor} onChange={e=>setForm(f=>({...f,scheduledFor:e.target.value}))} placeholder="e.g. 2026-06-01 9:00 AM" style={inp} />
            </div>
          </div>
          <div style={{ display: "flex", gap: 10 }}>
            <button onClick={() => { setPosts(p=>[...p,{...form,id:Date.now(),image:null}]); setShowAdd(false); }} style={{ background: "#6366f1", border: "none", color: "white", borderRadius: 7, padding: "9px 20px", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>Schedule</button>
            <button onClick={()=>setShowAdd(false)} style={{ background: "white", border: "1px solid #e2e8f0", color: "#64748b", borderRadius: 7, padding: "9px 14px", fontSize: 13, cursor: "pointer", fontFamily: "inherit" }}>Cancel</button>
          </div>
        </div>
      )}
      <div style={{ flex: 1, overflow: "auto", padding: 24 }}>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(3,1fr)", gap: 14, marginBottom: 24 }}>
          {["Instagram","Facebook","LinkedIn"].map(p => (
            <div key={p} style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 10, padding: "16px 20px", display: "flex", alignItems: "center", gap: 12 }}>
              <div style={{ fontSize: 28 }}>{platformIcons[p]}</div>
              <div>
                <div style={{ color: platformColors[p], fontSize: 13, fontWeight: 700 }}>{p}</div>
                <div style={{ color: "#94a3b8", fontSize: 12 }}>{posts.filter(po=>po.platform===p).length} posts</div>
              </div>
            </div>
          ))}
        </div>
        <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
          {posts.map(p => (
            <div key={p.id} style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 10, padding: "16px 20px", display: "flex", gap: 16, alignItems: "flex-start", boxShadow: "0 1px 3px rgba(0,0,0,0.04)" }}>
              {p.image && <img src={p.image} alt="" style={{ width: 80, height: 60, objectFit: "cover", borderRadius: 6, flexShrink: 0 }} />}
              <div style={{ flex: 1 }}>
                <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 6 }}>
                  <span style={{ background: (platformColors[p.platform])+"18", color: platformColors[p.platform], fontSize: 11, fontWeight: 700, padding: "2px 8px", borderRadius: 4 }}>{platformIcons[p.platform]} {p.platform}</span>
                  <span style={{ background: p.status==="Posted"?"#dcfce7":"#dbeafe", color: p.status==="Posted"?"#16a34a":"#1d4ed8", fontSize: 10, fontWeight: 700, padding: "2px 7px", borderRadius: 10 }}>{p.status}</span>
                  <span style={{ color: "#94a3b8", fontSize: 11, marginLeft: "auto" }}>{p.scheduledFor}</span>
                </div>
                <div style={{ color: "#475569", fontSize: 13, lineHeight: 1.6 }}>{p.content}</div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

