// ─── Goal Tracker ─────────────────────────────────────────────────────────────
function GoalTracker() {
  const [goals, setGoals] = useState([
    { id: 1, label: "Annual GCI", target: 250000, current: 87450, unit: "$", color: "#6366f1" },
    { id: 2, label: "Closed Deals", target: 24, current: 8, unit: "", color: "#10b981" },
    { id: 3, label: "New Leads", target: 200, current: 67, unit: "", color: "#f59e0b" },
    { id: 4, label: "Listings Taken", target: 18, current: 6, unit: "", color: "#8b5cf6" },
    { id: 5, label: "Showings", target: 96, current: 34, unit: "", color: "#0ea5e9" },
    { id: 6, label: "Reviews", target: 20, current: 2, unit: "", color: "#f97316" },
  ]);

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#f8fafc" }}>
      <TopBar title="Goal Tracker" sub="2026 annual goals — track your progress month by month" />
      <div style={{ flex: 1, overflow: "auto", padding: 24 }}>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(2,1fr)", gap: 16, marginBottom: 24 }}>
          {goals.map(g => {
            const pct = Math.min(100, Math.round((g.current / g.target) * 100));
            return (
              <div key={g.id} style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 12, padding: "20px 24px", boxShadow: "0 1px 3px rgba(0,0,0,0.04)" }}>
                <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 12 }}>
                  <div style={{ color: "#0f172a", fontSize: 14, fontWeight: 700 }}>{g.label}</div>
                  <div style={{ color: pct >= 100 ? "#10b981" : "#0f172a", fontSize: 14, fontWeight: 800 }}>{pct}%</div>
                </div>
                <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 8 }}>
                  <span style={{ color: g.color, fontSize: 22, fontWeight: 800 }}>{g.unit}{g.current.toLocaleString()}</span>
                  <span style={{ color: "#94a3b8", fontSize: 13 }}>of {g.unit}{g.target.toLocaleString()}</span>
                </div>
                <div style={{ height: 10, background: "#f1f5f9", borderRadius: 5, overflow: "hidden", marginBottom: 8 }}>
                  <div style={{ width: pct + "%", height: "100%", background: g.color, borderRadius: 5, transition: "width 0.5s" }} />
                </div>
                <div style={{ color: "#94a3b8", fontSize: 11 }}>Remaining: {g.unit}{(g.target - g.current).toLocaleString()} · On pace for {g.unit}{Math.round(g.current * (12/5)).toLocaleString()} by year end</div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

