const INIT_EXPENSES = [
  { id: 1, description: "PropStream Subscription", category: "Software", amount: 99, date: "2026-05-01", deductible: true },
  { id: 2, description: "HAR IDX Fee", category: "MLS/IDX", amount: 50, date: "2026-05-01", deductible: true },
  { id: 3, description: "Facebook Ad Campaign — 77598", category: "Marketing", amount: 250, date: "2026-05-15", deductible: true },
  { id: 4, description: "Professional Photography — Lakefront Dr", category: "Photography", amount: 350, date: "2026-05-22", deductible: true },
  { id: 5, description: "Client Closing Gift — Kowalski", category: "Client Gifts", amount: 150, date: "2026-05-15", deductible: true },
  { id: 6, description: "Mileage — Showings May", category: "Transportation", amount: 87, date: "2026-05-31", deductible: true },
];

function ExpenseTracker() {
  const [expenses, setExpenses] = useState(INIT_EXPENSES);
  const [showAdd, setShowAdd] = useState(false);
  const [form, setForm] = useState({ description: "", category: "Marketing", amount: "", date: new Date().toISOString().split("T")[0], deductible: true });
  const total = expenses.reduce((s,e)=>s+e.amount,0);
  const deductible = expenses.filter(e=>e.deductible).reduce((s,e)=>s+e.amount,0);
  const categories = ["Software","MLS/IDX","Marketing","Photography","Client Gifts","Transportation","Office","Education","Other"];
  const catColors = { Software: "#6366f1", "MLS/IDX": "#0ea5e9", Marketing: "#f59e0b", Photography: "#ec4899", "Client Gifts": "#10b981", Transportation: "#f97316", Office: "#8b5cf6", Education: "#64748b", Other: "#94a3b8" };
  const inp = { background: "#f8fafc", border: "1px solid #e2e8f0", color: "#0f172a", borderRadius: 6, padding: "8px 12px", fontSize: 13, outline: "none", fontFamily: "inherit", width: "100%", boxSizing: "border-box" };

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#f8fafc" }}>
      <TopBar title="Expense Tracker" sub="Track business expenses for tax time" action={
        <button onClick={()=>setShowAdd(!showAdd)} style={{ background: "#6366f1", border: "none", color: "white", borderRadius: 7, padding: "9px 18px", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>+ Add Expense</button>
      } />
      {showAdd && (
        <div style={{ background: "white", borderBottom: "1px solid #f1f5f9", padding: "16px 24px" }}>
          <div style={{ display: "grid", gridTemplateColumns: "2fr 1fr 1fr 1fr", gap: 12, marginBottom: 12 }}>
            <div><div style={{ color: "#64748b", fontSize: 11, fontWeight: 600, marginBottom: 4 }}>Description</div><input value={form.description} onChange={e=>setForm(f=>({...f,description:e.target.value}))} style={inp} /></div>
            <div><div style={{ color: "#64748b", fontSize: 11, fontWeight: 600, marginBottom: 4 }}>Category</div><select value={form.category} onChange={e=>setForm(f=>({...f,category:e.target.value}))} style={{...inp,cursor:"pointer"}}>{categories.map(c=><option key={c}>{c}</option>)}</select></div>
            <div><div style={{ color: "#64748b", fontSize: 11, fontWeight: 600, marginBottom: 4 }}>Amount ($)</div><input value={form.amount} onChange={e=>setForm(f=>({...f,amount:e.target.value}))} placeholder="0.00" style={inp} /></div>
            <div><div style={{ color: "#64748b", fontSize: 11, fontWeight: 600, marginBottom: 4 }}>Date</div><input type="date" value={form.date} onChange={e=>setForm(f=>({...f,date:e.target.value}))} style={inp} /></div>
          </div>
          <div style={{ display: "flex", gap: 10, alignItems: "center" }}>
            <button onClick={()=>{setExpenses(p=>[...p,{...form,id:Date.now(),amount:parseFloat(form.amount)||0}]);setShowAdd(false);}} style={{ background: "#6366f1", border: "none", color: "white", borderRadius: 7, padding: "9px 20px", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>Save</button>
            <button onClick={()=>setShowAdd(false)} style={{ background: "white", border: "1px solid #e2e8f0", color: "#64748b", borderRadius: 7, padding: "9px 14px", fontSize: 13, cursor: "pointer", fontFamily: "inherit" }}>Cancel</button>
            <label style={{ display: "flex", alignItems: "center", gap: 6, color: "#475569", fontSize: 13, cursor: "pointer" }}><input type="checkbox" checked={form.deductible} onChange={e=>setForm(f=>({...f,deductible:e.target.checked}))} style={{ accentColor: "#6366f1" }} />Tax Deductible</label>
          </div>
        </div>
      )}
      <div style={{ flex: 1, overflow: "auto", padding: 24 }}>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 14, marginBottom: 24 }}>
          {[["Total Expenses", "$"+total.toFixed(2), "#ef4444"],["Tax Deductible", "$"+deductible.toFixed(2), "#10b981"],["Est. Tax Savings", "$"+Math.round(deductible*0.25).toLocaleString(), "#6366f1"],["This Month", expenses.filter(e=>e.date.startsWith("2026-05")).length + " items", "#f59e0b"]].map(([l,v,c]) => (
            <div key={l} style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 10, padding: "16px 18px", boxShadow: "0 1px 3px rgba(0,0,0,0.04)" }}>
              <div style={{ color: "#94a3b8", fontSize: 11, fontWeight: 700, textTransform: "uppercase", marginBottom: 6 }}>{l}</div>
              <div style={{ color: c, fontSize: 22, fontWeight: 800 }}>{v}</div>
            </div>
          ))}
        </div>
        <div style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 12, overflow: "hidden" }}>
          <table style={{ width: "100%", borderCollapse: "collapse" }}>
            <thead><tr style={{ background: "#f8fafc", borderBottom: "1px solid #f1f5f9" }}>{["Description","Category","Amount","Date","Deductible"].map(h=><th key={h} style={{ padding: "10px 16px", color: "#94a3b8", fontSize: 11, fontWeight: 700, textAlign: "left", letterSpacing: "0.05em", textTransform: "uppercase" }}>{h}</th>)}</tr></thead>
            <tbody>
              {expenses.map(e => (
                <tr key={e.id} style={{ borderBottom: "1px solid #f8fafc" }}>
                  <td style={{ padding: "12px 16px", color: "#0f172a", fontSize: 13, fontWeight: 600 }}>{e.description}</td>
                  <td style={{ padding: "12px 16px" }}><span style={{ background: (catColors[e.category]||"#94a3b8")+"18", color: catColors[e.category]||"#94a3b8", fontSize: 11, fontWeight: 700, padding: "2px 8px", borderRadius: 4 }}>{e.category}</span></td>
                  <td style={{ padding: "12px 16px", color: "#ef4444", fontWeight: 700, fontSize: 13 }}>${e.amount.toFixed(2)}</td>
                  <td style={{ padding: "12px 16px", color: "#94a3b8", fontSize: 12 }}>{e.date}</td>
                  <td style={{ padding: "12px 16px" }}>{e.deductible?<span style={{ color: "#16a34a", fontWeight: 700, fontSize: 12 }}>✓ Yes</span>:<span style={{ color: "#94a3b8", fontSize: 12 }}>No</span>}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

