function ShowingFeedback() {
  const [feedback] = useState(INIT_FEEDBACK);
  const likelihoodColors = { "Extremely Likely": "#10b981", "Very Likely": "#6366f1", "Likely": "#f59e0b", "Unlikely": "#94a3b8", "No Interest": "#ef4444" };

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#f8fafc" }}>
      <TopBar title="Showing Feedback" sub="Auto-collect buyer feedback after every showing" action={
        <button style={{ background: "#6366f1", border: "none", color: "white", borderRadius: 7, padding: "9px 18px", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>Send Feedback Request</button>
      } />
      <div style={{ flex: 1, overflow: "auto", padding: 24 }}>
        <div style={{ background: "#f0f9ff", border: "1px solid #bae6fd", borderRadius: 10, padding: "14px 18px", marginBottom: 20 }}>
          <div style={{ color: "#0369a1", fontSize: 13, fontWeight: 700, marginBottom: 4 }}>💡 How Automatic Feedback Works</div>
          <div style={{ color: "#0c4a6e", fontSize: 13, lineHeight: 1.6 }}>After a showing is logged, EstateIQ automatically texts the buyer: <em>"Hi [Name], thanks for touring [address] today! Quick question — what did you think? Reply with your thoughts or tap here to fill out a quick form."</em> Responses appear here instantly.</div>
        </div>
        {feedback.map(f => (
          <div key={f.id} style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 12, padding: "20px 22px", marginBottom: 14, boxShadow: "0 1px 3px rgba(0,0,0,0.04)" }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 14 }}>
              <div>
                <div style={{ color: "#0f172a", fontSize: 15, fontWeight: 800, marginBottom: 2 }}>{f.property}</div>
                <div style={{ color: "#64748b", fontSize: 12 }}>{f.buyer} · {f.date}</div>
              </div>
              <div style={{ textAlign: "right" }}>
                <div style={{ color: "#f59e0b", fontSize: 18 }}>{"★".repeat(f.rating)}{"☆".repeat(5-f.rating)}</div>
                <span style={{ background: (likelihoodColors[f.likelihood]||"#94a3b8")+"18", color: likelihoodColors[f.likelihood]||"#94a3b8", fontSize: 11, fontWeight: 700, padding: "3px 9px", borderRadius: 10 }}>{f.likelihood} to Offer</span>
              </div>
            </div>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
              <div style={{ background: "#f0fdf4", border: "1px solid #bbf7d0", borderRadius: 8, padding: "12px 14px" }}>
                <div style={{ color: "#16a34a", fontSize: 11, fontWeight: 700, marginBottom: 4 }}>👍 LIKED</div>
                <div style={{ color: "#15803d", fontSize: 13 }}>{f.liked}</div>
              </div>
              <div style={{ background: "#fef2f2", border: "1px solid #fecaca", borderRadius: 8, padding: "12px 14px" }}>
                <div style={{ color: "#dc2626", fontSize: 11, fontWeight: 700, marginBottom: 4 }}>👎 DISLIKED</div>
                <div style={{ color: "#991b1b", fontSize: 13 }}>{f.disliked}</div>
              </div>
            </div>
            {f.notes && <div style={{ marginTop: 10, color: "#64748b", fontSize: 13, fontStyle: "italic" }}>"{f.notes}"</div>}
          </div>
        ))}
      </div>
    </div>
  );
}

