const INIT_MILESTONES = [
  { id: 1, name: "The Kowalski Family", type: "Closing Anniversary", date: "2026-05-15", note: "1 year in their home next year!", phone: "(512) 334-9012" },
  { id: 2, name: "Marcus Rivera", type: "Birthday", date: "2026-06-12", note: "Send a card and market update", phone: "(512) 847-2931" },
  { id: 3, name: "Patricia Okafor", type: "Birthday", date: "2026-07-04", note: "Long-term lead — great touch point", phone: "(832) 667-1102" },
  { id: 4, name: "Dr. James Thornton", type: "Closing Anniversary", date: "2026-08-15", note: "Check if he wants to invest again", phone: "(512) 601-4408" },
];

function BirthdayTracker() {
  const [milestones, setMilestones] = useState(INIT_MILESTONES);
  const [form, setForm] = useState({ name: "", type: "Birthday", date: "", note: "", phone: "" });
  const [showAdd, setShowAdd] = useState(false);
  const typeColors = { Birthday: "#ec4899", "Closing Anniversary": "#6366f1", "Home Anniversary": "#10b981" };
  const inp = { background: "#f8fafc", border: "1px solid #e2e8f0", color: "#0f172a", borderRadius: 6, padding: "8px 12px", fontSize: 13, outline: "none", fontFamily: "inherit", width: "100%", boxSizing: "border-box" };

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#f8fafc" }}>
      <TopBar title="Birthdays & Anniversaries" sub="Never miss a client milestone — stay top of mind year round" action={
        <button onClick={()=>setShowAdd(!showAdd)} style={{ background: "#6366f1", border: "none", color: "white", borderRadius: 7, padding: "9px 18px", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>+ Add Milestone</button>
      } />
      {showAdd && (
        <div style={{ background: "white", borderBottom: "1px solid #f1f5f9", padding: "16px 24px" }}>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(5,1fr)", gap: 12, marginBottom: 12 }}>
            <div><div style={{ color: "#64748b", fontSize: 11, fontWeight: 600, marginBottom: 4 }}>Client Name</div><input value={form.name} onChange={e=>setForm(f=>({...f,name:e.target.value}))} style={inp} /></div>
            <div><div style={{ color: "#64748b", fontSize: 11, fontWeight: 600, marginBottom: 4 }}>Type</div><select value={form.type} onChange={e=>setForm(f=>({...f,type:e.target.value}))} style={{...inp,cursor:"pointer"}}><option>Birthday</option><option>Closing Anniversary</option><option>Home Anniversary</option></select></div>
            <div><div style={{ color: "#64748b", fontSize: 11, fontWeight: 600, marginBottom: 4 }}>Date</div><input type="date" value={form.date} onChange={e=>setForm(f=>({...f,date:e.target.value}))} style={inp} /></div>
            <div><div style={{ color: "#64748b", fontSize: 11, fontWeight: 600, marginBottom: 4 }}>Phone</div><input value={form.phone} onChange={e=>setForm(f=>({...f,phone:e.target.value}))} style={inp} /></div>
            <div><div style={{ color: "#64748b", fontSize: 11, fontWeight: 600, marginBottom: 4 }}>Note</div><input value={form.note} onChange={e=>setForm(f=>({...f,note:e.target.value}))} style={inp} /></div>
          </div>
          <div style={{ display: "flex", gap: 10 }}>
            <button onClick={()=>{setMilestones(p=>[...p,{...form,id:Date.now()}]);setShowAdd(false);}} style={{ background: "#6366f1", border: "none", color: "white", borderRadius: 7, padding: "9px 20px", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>Save</button>
            <button onClick={()=>setShowAdd(false)} style={{ background: "white", border: "1px solid #e2e8f0", color: "#64748b", borderRadius: 7, padding: "9px 14px", fontSize: 13, cursor: "pointer", fontFamily: "inherit" }}>Cancel</button>
          </div>
        </div>
      )}
      <div style={{ flex: 1, overflow: "auto", padding: 24 }}>
        <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
          {milestones.sort((a,b)=>a.date.localeCompare(b.date)).map(m => {
            const color = typeColors[m.type] || "#6366f1";
            const icon = m.type === "Birthday" ? "🎂" : "🔑";
            return (
              <div key={m.id} style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 12, padding: "16px 20px", display: "flex", alignItems: "center", gap: 16, boxShadow: "0 1px 3px rgba(0,0,0,0.04)" }}>
                <div style={{ width: 48, height: 48, borderRadius: 12, background: color+"18", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 22, flexShrink: 0 }}>{icon}</div>
                <div style={{ flex: 1 }}>
                  <div style={{ color: "#0f172a", fontSize: 14, fontWeight: 700, marginBottom: 2 }}>{m.name}</div>
                  <div style={{ color: "#94a3b8", fontSize: 12 }}>{m.note}</div>
                </div>
                <div style={{ textAlign: "center" }}>
                  <div style={{ color: color, fontSize: 13, fontWeight: 700 }}>{m.date}</div>
                  <span style={{ background: color+"18", color, fontSize: 10, fontWeight: 700, padding: "2px 7px", borderRadius: 10 }}>{m.type}</span>
                </div>
                <div style={{ display: "flex", gap: 8 }}>
                  <button style={{ background: "#6366f1", border: "none", color: "white", borderRadius: 6, padding: "7px 14px", fontSize: 12, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>Send Message</button>
                  <button style={{ background: "#f8fafc", border: "1px solid #e2e8f0", color: "#475569", borderRadius: 6, padding: "7px 12px", fontSize: 12, cursor: "pointer" }}>Call</button>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

// ─── AI Assistant ─────────────────────────────────────────────────────────────
function AIAssistant({ contacts }) {
  const [messages, setMessages] = useState([{ role: "assistant", text: "Hi Gerald! I'm your EstateIQ AI assistant with predictive analytics. I can predict which leads will close, which homeowners will sell, forecast your GCI, analyze market trends across your 52 ZIP codes, and much more. What would you like to predict or analyze today?" }]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [activeTab, setActiveTab] = useState("chat"); // chat | predictions

  // Build rich CRM context for predictions
  const buildContext = () => {
    const hotLeads = contacts.filter(c => c.temperature === "Hot");
    const warmLeads = contacts.filter(c => c.temperature === "Warm");
    const coldLeads = contacts.filter(c => c.temperature === "Cold");
    const closingLeads = contacts.filter(c => c.stage === "Under Contract" || c.stage === "Offer");
    const showingLeads = contacts.filter(c => c.stage === "Showing");
    const totalBudget = contacts.reduce((s,c) => s + (c.budget||0), 0);
    const avgScore = contacts.length ? Math.round(contacts.reduce((s,c) => s+(c.score||40),0)/contacts.length) : 0;
    const preApproved = contacts.filter(c => c.preApproved).length;
    const sources = [...new Set(contacts.map(c=>c.source))].join(", ");

    return `You are EstateIQ AI, an advanced predictive real estate assistant for Gerald, a licensed real estate agent in Houston, Texas.

GERALD'S CRM DATA (use this for all predictions):
- Total contacts: ${contacts.length}
- Hot leads (${hotLeads.length}): ${hotLeads.map(c=>c.name).join(", ")||"none"}
- Warm leads (${warmLeads.length}): ${warmLeads.map(c=>c.name).join(", ")||"none"}
- Cold leads (${coldLeads.length}): ${coldLeads.map(c=>c.name).join(", ")||"none"}
- Under Contract/Offer (${closingLeads.length}): ${closingLeads.map(c=>c.name).join(", ")||"none"}
- Currently Showing (${showingLeads.length}): ${showingLeads.map(c=>c.name).join(", ")||"none"}
- Pre-approved buyers: ${preApproved}
- Total pipeline budget: $${totalBudget.toLocaleString()}
- Average lead score: ${avgScore}/100
- Lead sources: ${sources}
- Top lead by score: ${[...contacts].sort((a,b)=>(b.score||0)-(a.score||0))[0]?.name||"none"}

GERALD'S TERRITORY: 52 ZIP codes across Houston, Webster/Clear Lake (77598), Sugar Land, Pearland, Katy, The Woodlands, Galveston County, Pasadena, Alvin, Dayton, Angleton, South Houston (77089, 77075).

YOUR PREDICTIVE CAPABILITIES:
1. SELLER PREDICTIONS — predict which homeowners will list in 90 days based on equity, years owned, life events
2. LEAD CLOSE PREDICTIONS — predict which leads will close and estimated timeline
3. GCI FORECASTING — forecast monthly and annual commission based on pipeline
4. MARKET TREND PREDICTIONS — predict price movements across Gerald's 52 ZIP codes
5. LEAD SCORING — analyze and re-score leads based on behavior patterns
6. BEST TIME TO CONTACT — predict optimal outreach timing per lead
7. DEAL RISK ANALYSIS — flag deals at risk of falling through
8. REFERRAL PREDICTIONS — predict which closed clients are most likely to refer

PERSONALITY: Be direct, specific, and data-driven. Always reference Gerald's actual CRM data in predictions. Give specific names, numbers, and timeframes. Format predictions clearly with bullet points when listing multiple items. Always end predictions with a recommended action Gerald should take today.`;
  };

  const send = async () => {
    if (!input.trim() || loading) return;
    const userMsg = input.trim();
    setInput("");
    setMessages(p => [...p, { role: "user", text: userMsg }]);
    setLoading(true);

    try {
      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-20250514",
          max_tokens: 1000,
          system: buildContext(),
          messages: [
            ...messages.filter(m=>m.role==="user"||m.role==="assistant").map(m=>({ role: m.role, content: m.text })),
            { role: "user", content: userMsg }
          ]
        })
      });
      const data = await res.json();
      const reply = data.content?.[0]?.text || "Sorry, I couldn't get a response. Please try again.";
      setMessages(p => [...p, { role: "assistant", text: reply }]);
    } catch {
      setMessages(p => [...p, { role: "assistant", text: "Connection error. Please try again." }]);
    }
    setLoading(false);
  };

  const chatSuggestions = [
    "Who are my hottest leads right now?",
    "Draft an outreach email for 77598 sellers",
    "What's the best strategy for a cash buyer?",
    "How do I win a listing presentation?",
  ];

  const predictionSuggestions = [
    { label: "🔮 Which leads will close this month?", prompt: "Based on my CRM data, predict which leads are most likely to close in the next 30 days. Give me names, likelihood percentages, and why." },
    { label: "🏠 Which homeowners will sell in 90 days?", prompt: "Analyze my predictive seller leads and CRM contacts. Who is most likely to list their home in the next 90 days and why?" },
    { label: "💰 Forecast my GCI this year", prompt: "Based on my current pipeline, closed deals, and lead quality, forecast my Gross Commission Income for the rest of 2026. Break it down by month." },
    { label: "📈 Which ZIP codes are heating up?", prompt: "Based on market trends across my 52 ZIP codes in Houston, which areas are seeing the most price appreciation and buyer demand right now?" },
    { label: "⚠️ Which deals are at risk?", prompt: "Analyze my current pipeline and identify any deals that might be at risk of falling through. What warning signs do you see?" },
    { label: "📞 Who should I call today?", prompt: "Based on lead scores, temperature, last contact dates, and pipeline stage, give me a prioritized list of exactly who I should contact today and what to say." },
    { label: "⭐ Who will refer me business?", prompt: "Based on my closed clients and their engagement, predict which past clients are most likely to send me referrals. What should I do to activate them?" },
    { label: "🎯 Where should I focus my farm?", prompt: "Based on my 52 ZIP codes, equity levels, and market data, which 3-5 ZIP codes should I focus my farming efforts on for the highest ROI?" },
  ];

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#f8fafc" }}>
      <TopBar title="AI Assistant + Predictive Analytics" sub="Powered by Claude — predict, analyze, and strategize with your real CRM data" />

      {/* Tab switcher */}
      <div style={{ background: "white", borderBottom: "1px solid #f1f5f9", padding: "0 24px", display: "flex", gap: 0 }}>
        {[["chat", "💬 Chat"], ["predictions", "🔮 Predictions"]].map(([id, label]) => (
          <button key={id} onClick={() => setActiveTab(id)} style={{ background: "transparent", border: "none", borderBottom: `3px solid ${activeTab === id ? "#6366f1" : "transparent"}`, color: activeTab === id ? "#6366f1" : "#94a3b8", padding: "14px 20px", fontSize: 13, fontWeight: activeTab === id ? 700 : 400, cursor: "pointer", fontFamily: "inherit", transition: "all 0.15s" }}>
            {label}
          </button>
        ))}
      </div>

      {activeTab === "predictions" && (
        <div style={{ padding: "20px 24px", background: "#f8fafc", borderBottom: "1px solid #f1f5f9", overflow: "auto", maxHeight: 280 }}>
          <div style={{ color: "#475569", fontSize: 12, fontWeight: 700, textTransform: "uppercase", letterSpacing: "0.06em", marginBottom: 12 }}>Quick Predictions — Click to Run</div>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8 }}>
            {predictionSuggestions.map(p => (
              <button key={p.label} onClick={() => { setActiveTab("chat"); setInput(p.prompt); setTimeout(() => { setInput(""); setMessages(prev => [...prev, { role: "user", text: p.prompt }]); setLoading(true);
                fetch("https://api.anthropic.com/v1/messages", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ model: "claude-sonnet-4-20250514", max_tokens: 1000, system: buildContext(), messages: [{ role: "user", content: p.prompt }] }) })
                .then(r => r.json()).then(data => { setMessages(prev => [...prev, { role: "assistant", text: data.content?.[0]?.text || "Error getting prediction." }]); setLoading(false); })
                .catch(() => { setMessages(prev => [...prev, { role: "assistant", text: "Connection error. Please try again." }]); setLoading(false); }); }, 100); }} style={{ background: "white", border: "1px solid #e2e8f0", color: "#0f172a", borderRadius: 8, padding: "10px 14px", fontSize: 12, fontWeight: 600, cursor: "pointer", fontFamily: "inherit", textAlign: "left", transition: "all 0.15s" }}>
                {p.label}
              </button>
            ))}
          </div>
        </div>
      )}

      <div style={{ flex: 1, overflow: "auto", padding: "20px 24px", display: "flex", flexDirection: "column", gap: 14 }}>
        {messages.map((m, i) => (
          <div key={i} style={{ display: "flex", gap: 12, alignItems: "flex-start", flexDirection: m.role === "user" ? "row-reverse" : "row" }}>
            <div style={{ width: 36, height: 36, borderRadius: "50%", background: m.role === "user" ? "#6366f1" : "#1e2d3d", display: "flex", alignItems: "center", justifyContent: "center", color: "white", fontSize: 14, fontWeight: 800, flexShrink: 0 }}>{m.role === "user" ? "G" : "🔮"}</div>
            <div style={{ maxWidth: "78%", background: m.role === "user" ? "#6366f1" : "white", border: m.role === "user" ? "none" : "1px solid #f1f5f9", borderRadius: m.role === "user" ? "12px 2px 12px 12px" : "2px 12px 12px 12px", padding: "12px 16px", boxShadow: "0 1px 3px rgba(0,0,0,0.06)" }}>
              <div style={{ color: m.role === "user" ? "white" : "#0f172a", fontSize: 13, lineHeight: 1.8, whiteSpace: "pre-wrap" }}>{m.text}</div>
            </div>
          </div>
        ))}
        {loading && (
          <div style={{ display: "flex", gap: 12, alignItems: "center" }}>
            <div style={{ width: 36, height: 36, borderRadius: "50%", background: "#1e2d3d", display: "flex", alignItems: "center", justifyContent: "center", color: "white", fontSize: 14 }}>🔮</div>
            <div style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: "2px 12px 12px 12px", padding: "12px 16px" }}>
              <div style={{ display: "flex", gap: 6, alignItems: "center" }}>
                {[0,1,2].map(i => <div key={i} style={{ width: 8, height: 8, borderRadius: "50%", background: "#6366f1" }} />)}
                <span style={{ color: "#94a3b8", fontSize: 11, marginLeft: 6 }}>Analyzing your CRM data...</span>
              </div>
            </div>
          </div>
        )}
        {messages.length === 1 && activeTab === "chat" && (
          <div style={{ display: "flex", flexWrap: "wrap", gap: 8, marginTop: 8 }}>
            {chatSuggestions.map(s => (
              <button key={s} onClick={() => setInput(s)} style={{ background: "white", border: "1px solid #e2e8f0", color: "#475569", borderRadius: 20, padding: "7px 14px", fontSize: 12, cursor: "pointer", fontFamily: "inherit" }}>{s}</button>
            ))}
          </div>
        )}
      </div>
      <div style={{ padding: "14px 24px", background: "white", borderTop: "1px solid #f1f5f9" }}>
        <div style={{ display: "flex", gap: 10 }}>
          <input value={input} onChange={e=>setInput(e.target.value)} onKeyDown={e=>e.key==="Enter"&&send()} placeholder="Ask anything — predict closings, forecast GCI, analyze leads, strategize..." style={{ flex: 1, background: "#f8fafc", border: "1px solid #e2e8f0", color: "#0f172a", borderRadius: 8, padding: "11px 16px", fontSize: 13, outline: "none", fontFamily: "inherit" }} />
          <button onClick={send} disabled={loading||!input.trim()} style={{ background: input.trim()?"#6366f1":"#e2e8f0", border: "none", color: input.trim()?"white":"#94a3b8", borderRadius: 8, padding: "11px 20px", fontSize: 13, fontWeight: 700, cursor: input.trim()?"pointer":"default", fontFamily: "inherit" }}>Send</button>
        </div>
        <div style={{ color: "#94a3b8", fontSize: 11, marginTop: 6, textAlign: "center" }}>Powered by Claude AI · Analyzes your real CRM data for accurate predictions</div>
      </div>
    </div>
  );
}

// ─── Performance Report ───────────────────────────────────────────────────────
function PerformanceReport() {
  const months = ["Jan","Feb","Mar","Apr","May"];
  const data = { leads: [12,18,14,22,27], closings: [1,2,1,2,2], gci: [14850,29700,14850,29700,29700], showings: [8,14,10,18,22] };
  const maxLeads = Math.max(...data.leads);
  const maxGCI = Math.max(...data.gci);

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#f8fafc" }}>
      <TopBar title="Performance Report" sub="Year-to-date activity and results — 2026" action={
        <button style={{ background: "#6366f1", border: "none", color: "white", borderRadius: 7, padding: "9px 18px", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>Export Report</button>
      } />
      <div style={{ flex: 1, overflow: "auto", padding: 24 }}>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 14, marginBottom: 24 }}>
          {[["YTD GCI", "$"+data.gci.reduce((s,v)=>s+v,0).toLocaleString(), "#10b981"],["Total Leads", data.leads.reduce((s,v)=>s+v,0), "#6366f1"],["Closings", data.closings.reduce((s,v)=>s+v,0), "#f59e0b"],["Showings", data.showings.reduce((s,v)=>s+v,0), "#0ea5e9"]].map(([l,v,c]) => (
            <div key={l} style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 10, padding: "18px 20px", boxShadow: "0 1px 3px rgba(0,0,0,0.04)" }}>
              <div style={{ color: "#94a3b8", fontSize: 11, fontWeight: 700, textTransform: "uppercase", marginBottom: 8 }}>{l}</div>
              <div style={{ color: c, fontSize: 28, fontWeight: 800 }}>{v}</div>
            </div>
          ))}
        </div>
        {/* Monthly charts */}
        {[["Monthly Leads", data.leads, maxLeads, "#6366f1"], ["Monthly GCI ($)", data.gci.map(v=>"$"+v.toLocaleString()), maxGCI, "#10b981"]].map(([title, vals, maxVal, color]) => (
          <div key={title} style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 12, padding: "20px 24px", marginBottom: 16, boxShadow: "0 1px 3px rgba(0,0,0,0.04)" }}>
            <div style={{ color: "#0f172a", fontSize: 14, fontWeight: 700, marginBottom: 20 }}>{title}</div>
            <div style={{ display: "flex", gap: 12, alignItems: "flex-end", height: 120 }}>
              {months.map((m, i) => {
                const rawVal = typeof vals[i] === "string" ? data.gci[i] : vals[i];
                const pct = (rawVal / maxVal) * 100;
                return (
                  <div key={m} style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", gap: 6 }}>
                    <div style={{ color: "#475569", fontSize: 11, fontWeight: 600 }}>{vals[i]}</div>
                    <div style={{ width: "100%", height: pct + "%", background: color, borderRadius: "4px 4px 0 0", minHeight: 4, transition: "height 0.3s" }} />
                    <div style={{ color: "#94a3b8", fontSize: 11 }}>{m}</div>
                  </div>
                );
              })}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

// ─── AI Lead Scorer ───────────────────────────────────────────────────────────
function AILeadScorer({ contacts, setContacts }) {
  const [scoring, setScoring] = useState(false);
  const [scored, setScored] = useState(false);
  const [log, setLog] = useState([]);

  const runScorer = async () => {
    setScoring(true);
    setLog([]);
    for (let i = 0; i < contacts.length; i++) {
      const c = contacts[i];
      await new Promise(r => setTimeout(r, 300));
      setLog(p => [...p, `Analyzing ${c.name}...`]);
    }
    // Auto-adjust scores based on stage and temperature
    setContacts(prev => prev.map(c => {
      let score = c.score || 40;
      if (c.temperature === "Hot") score = Math.min(99, score + 10);
      if (c.temperature === "Cold") score = Math.max(10, score - 10);
      if (c.stage === "Showing" || c.stage === "Offer") score = Math.min(99, score + 15);
      if (c.stage === "New Lead") score = Math.max(20, score - 5);
      if (c.preApproved) score = Math.min(99, score + 8);
      return { ...c, score: Math.round(score) };
    }));
    setLog(p => [...p, "✓ All leads scored and updated!"]);
    setScoring(false);
    setScored(true);
  };

  const sorted = [...contacts].sort((a,b) => (b.score||0) - (a.score||0));
  const scoreColor = (s) => s >= 80 ? "#ef4444" : s >= 60 ? "#f97316" : "#0ea5e9";

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#f8fafc" }}>
      <TopBar title="AI Lead Scorer" sub="Automatically score and prioritize every lead in your CRM" action={
        <button onClick={runScorer} disabled={scoring} style={{ background: scoring?"#e2e8f0":"#6366f1", border: "none", color: scoring?"#94a3b8":"white", borderRadius: 7, padding: "9px 18px", fontSize: 13, fontWeight: 700, cursor: scoring?"default":"pointer", fontFamily: "inherit" }}>
          {scoring ? "⟳ Scoring..." : "🤖 Run AI Scorer"}
        </button>
      } />
      <div style={{ flex: 1, overflow: "auto", padding: 24 }}>
        {log.length > 0 && (
          <div style={{ background: "#0f172a", borderRadius: 10, padding: "14px 18px", marginBottom: 20, fontFamily: "monospace" }}>
            {log.map((l,i) => <div key={i} style={{ color: l.includes("✓") ? "#10b981" : "#a5f3fc", fontSize: 12, marginBottom: 4 }}>{l}</div>)}
          </div>
        )}
        <div style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 12, overflow: "hidden", boxShadow: "0 1px 3px rgba(0,0,0,0.04)" }}>
          <div style={{ padding: "14px 18px", borderBottom: "1px solid #f1f5f9", display: "flex", justifyContent: "space-between" }}>
            <div style={{ color: "#0f172a", fontSize: 14, fontWeight: 700 }}>All Leads — Ranked by Score</div>
            {scored && <div style={{ color: "#10b981", fontSize: 12, fontWeight: 600 }}>✓ Updated {new Date().toLocaleTimeString()}</div>}
          </div>
          <table style={{ width: "100%", borderCollapse: "collapse" }}>
            <thead><tr style={{ background: "#f8fafc", borderBottom: "1px solid #f1f5f9" }}>{["Rank","Lead","Stage","Temperature","Score","Action"].map(h=><th key={h} style={{ padding: "10px 16px", color: "#94a3b8", fontSize: 11, fontWeight: 700, textAlign: "left", letterSpacing: "0.05em", textTransform: "uppercase" }}>{h}</th>)}</tr></thead>
            <tbody>
              {sorted.map((c, i) => (
                <tr key={c.id} style={{ borderBottom: "1px solid #f8fafc", background: i < 3 ? "#fffbeb" : "white" }}>
                  <td style={{ padding: "12px 16px" }}>
                    <div style={{ width: 28, height: 28, borderRadius: "50%", background: i===0?"#f59e0b":i===1?"#94a3b8":i===2?"#cd7c2f":"#f1f5f9", color: i<3?"white":"#94a3b8", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 12, fontWeight: 800 }}>#{i+1}</div>
                  </td>
                  <td style={{ padding: "12px 16px" }}>
                    <div style={{ color: "#0f172a", fontSize: 13, fontWeight: 700 }}>{c.name}</div>
                    <div style={{ color: "#94a3b8", fontSize: 11 }}>{c.email}</div>
                  </td>
                  <td style={{ padding: "12px 16px" }}><span style={{ background: (stageColors[c.stage]||"#64748b")+"18", color: stageColors[c.stage]||"#64748b", fontSize: 11, fontWeight: 700, padding: "2px 8px", borderRadius: 4 }}>{c.stage}</span></td>
                  <td style={{ padding: "12px 16px" }}><TempBadge temp={c.temperature} /></td>
                  <td style={{ padding: "12px 16px" }}>
                    <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                      <div style={{ width: 36, height: 36, borderRadius: "50%", background: scoreColor(c.score||40), color: "white", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 11, fontWeight: 800 }}>{c.score||40}</div>
                      <div style={{ width: 60, height: 6, background: "#f1f5f9", borderRadius: 3, overflow: "hidden" }}><div style={{ width: (c.score||40)+"%", height: "100%", background: scoreColor(c.score||40) }} /></div>
                    </div>
                  </td>
                  <td style={{ padding: "12px 16px" }}><button style={{ background: "#6366f1", border: "none", color: "white", borderRadius: 6, padding: "6px 14px", fontSize: 12, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>Contact Now</button></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

