const INIT_SPHERE = [
  { id: 1, name: "Mike & Cheryl Davis", relationship: "Friend", lastContact: "2026-04-10", notes: "College friends, interested in upsizing", potential: "High", phone: "(713) 441-8810", email: "m.davis@email.com" },
  { id: 2, name: "Pastor James Brown", relationship: "Church", lastContact: "2026-03-22", notes: "Influential in the community — great referral source", potential: "High", phone: "(713) 882-3310", email: "pastor.brown@church.org" },
  { id: 3, name: "Linda Garza", relationship: "Neighbor", lastContact: "2026-05-01", notes: "Mentioned moving closer to family in San Antonio", potential: "Medium", phone: "(281) 554-4481", email: "l.garza@home.net" },
  { id: 4, name: "Tom & Pat Reynolds", relationship: "Former Colleague", lastContact: "2026-02-14", notes: "Both retiring soon, thinking about downsizing", potential: "High", phone: "(713) 663-2211", email: "t.reynolds@corp.com" },
  { id: 5, name: "Jasmine Walker", relationship: "Family", lastContact: "2026-05-20", notes: "Cousin just got engaged — will need home soon", potential: "Medium", phone: "(832) 554-9901", email: "j.walker@family.net" },
];

function SphereOfInfluence() {
  const [sphere, setSphere] = useState(INIT_SPHERE);
  const [showAdd, setShowAdd] = useState(false);
  const [form, setForm] = useState({ name: "", relationship: "Friend", lastContact: "", notes: "", potential: "Medium", phone: "", email: "" });
  const potColors = { High: "#ef4444", Medium: "#f59e0b", Low: "#94a3b8" };
  const relTypes = ["Friend", "Family", "Neighbor", "Church", "Former Colleague", "Business Contact", "Social Media", "Other"];
  const inp = { background: "#f8fafc", border: "1px solid #e2e8f0", color: "#0f172a", borderRadius: 6, padding: "8px 12px", fontSize: 13, outline: "none", fontFamily: "inherit", width: "100%", boxSizing: "border-box" };

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#f8fafc" }}>
      <TopBar title="Sphere of Influence" sub="Manage your personal network as a referral source" action={
        <button onClick={() => setShowAdd(!showAdd)} style={{ background: "#6366f1", border: "none", color: "white", borderRadius: 7, padding: "9px 18px", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>+ Add Contact</button>
      } />
      {showAdd && (
        <div style={{ background: "white", borderBottom: "1px solid #f1f5f9", padding: "16px 24px" }}>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 12, marginBottom: 12 }}>
            <div><div style={{ color: "#64748b", fontSize: 11, fontWeight: 600, marginBottom: 4 }}>Name</div><input value={form.name} onChange={e=>setForm(f=>({...f,name:e.target.value}))} style={inp} /></div>
            <div><div style={{ color: "#64748b", fontSize: 11, fontWeight: 600, marginBottom: 4 }}>Relationship</div><select value={form.relationship} onChange={e=>setForm(f=>({...f,relationship:e.target.value}))} style={{...inp,cursor:"pointer"}}>{relTypes.map(r=><option key={r}>{r}</option>)}</select></div>
            <div><div style={{ color: "#64748b", fontSize: 11, fontWeight: 600, marginBottom: 4 }}>Phone</div><input value={form.phone} onChange={e=>setForm(f=>({...f,phone:e.target.value}))} style={inp} /></div>
            <div><div style={{ color: "#64748b", fontSize: 11, fontWeight: 600, marginBottom: 4 }}>Potential</div><select value={form.potential} onChange={e=>setForm(f=>({...f,potential:e.target.value}))} style={{...inp,cursor:"pointer"}}><option>High</option><option>Medium</option><option>Low</option></select></div>
            <div style={{ gridColumn: "1/-1" }}><div style={{ color: "#64748b", fontSize: 11, fontWeight: 600, marginBottom: 4 }}>Notes</div><input value={form.notes} onChange={e=>setForm(f=>({...f,notes:e.target.value}))} style={inp} /></div>
          </div>
          <div style={{ display: "flex", gap: 10 }}>
            <button onClick={() => { setSphere(p=>[...p,{...form,id:Date.now(),lastContact:new Date().toISOString().split("T")[0]}]); setShowAdd(false); }} style={{ background: "#6366f1", border: "none", color: "white", borderRadius: 7, padding: "9px 20px", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>Save</button>
            <button onClick={()=>setShowAdd(false)} style={{ background: "white", border: "1px solid #e2e8f0", color: "#64748b", borderRadius: 7, padding: "9px 14px", fontSize: 13, cursor: "pointer", fontFamily: "inherit" }}>Cancel</button>
          </div>
        </div>
      )}
      <div style={{ flex: 1, overflow: "auto", padding: 24 }}>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(3,1fr)", gap: 14, marginBottom: 24 }}>
          {[["Total SOI", sphere.length, "#6366f1"],["High Potential", sphere.filter(s=>s.potential==="High").length, "#ef4444"],["Need Follow-Up", sphere.filter(s=>!s.lastContact||new Date()-new Date(s.lastContact)>30*24*60*60*1000).length, "#f59e0b"]].map(([l,v,c]) => (
            <div key={l} style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 10, padding: "16px 20px", boxShadow: "0 1px 3px rgba(0,0,0,0.04)", textAlign: "center" }}>
              <div style={{ color: c, fontSize: 28, fontWeight: 800 }}>{v}</div>
              <div style={{ color: "#475569", fontSize: 13, fontWeight: 600 }}>{l}</div>
            </div>
          ))}
        </div>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(280px,1fr))", gap: 14 }}>
          {sphere.map(s => (
            <div key={s.id} style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 12, padding: "18px 20px", boxShadow: "0 1px 3px rgba(0,0,0,0.04)" }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 10 }}>
                <div>
                  <div style={{ color: "#0f172a", fontSize: 14, fontWeight: 700 }}>{s.name}</div>
                  <div style={{ color: "#94a3b8", fontSize: 12 }}>{s.relationship}</div>
                </div>
                <span style={{ background: (potColors[s.potential])+"18", color: potColors[s.potential], fontSize: 10, fontWeight: 700, padding: "2px 8px", borderRadius: 10 }}>{s.potential}</span>
              </div>
              <div style={{ color: "#64748b", fontSize: 12, marginBottom: 10, lineHeight: 1.5 }}>{s.notes}</div>
              <div style={{ color: "#94a3b8", fontSize: 11, marginBottom: 12 }}>Last contact: {s.lastContact || "Never"}</div>
              <div style={{ display: "flex", gap: 8 }}>
                <button style={{ flex: 1, background: "#6366f1", border: "none", color: "white", borderRadius: 6, padding: "7px", fontSize: 11, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>Log Contact</button>
                <button style={{ flex: 1, background: "#f8fafc", border: "1px solid #e2e8f0", color: "#475569", borderRadius: 6, padding: "7px", fontSize: 11, cursor: "pointer", fontFamily: "inherit" }}>Send Message</button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

// ─── Business Card Scanner ────────────────────────────────────────────────────
function CardScanner({ onAddToLeads }) {
  const [mode, setMode] = useState("manual");
  const [form, setForm] = useState({ name: "", company: "", phone: "", email: "", address: "", notes: "" });
  const [saved, setSaved] = useState(false);
  const inp = { width: "100%", background: "#f8fafc", border: "1px solid #e2e8f0", color: "#0f172a", borderRadius: 6, padding: "9px 12px", fontSize: 13, outline: "none", fontFamily: "inherit", boxSizing: "border-box" };
  const lbl = { color: "#64748b", fontSize: 11, fontWeight: 600, display: "block", marginBottom: 5 };

  const handleSave = () => {
    onAddToLeads({
      id: Date.now(),
      name: form.name,
      email: form.email,
      phone: form.phone,
      stage: "New Lead",
      temperature: "Warm",
      budget: 0,
      preApproved: false,
      interest: [],
      lastContact: new Date().toISOString().split("T")[0],
      agent: "Gerald",
      source: "Business Card",
      tags: ["Business Card", form.company].filter(Boolean),
      notes: form.notes || "Scanned business card",
      score: 40,
      lastActivity: "Added via card scanner",
    });
    setSaved(true);
    setTimeout(() => { setSaved(false); setForm({ name: "", company: "", phone: "", email: "", address: "", notes: "" }); }, 2000);
  };

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#f8fafc" }}>
      <TopBar title="Business Card Scanner" sub="Scan a card and instantly create a contact in EstateIQ" />
      <div style={{ flex: 1, overflow: "auto", padding: 24 }}>
        <div style={{ maxWidth: 600 }}>
          <div style={{ display: "flex", gap: 10, marginBottom: 20 }}>
            {["manual", "camera"].map(m => (
              <button key={m} onClick={() => setMode(m)} style={{ flex: 1, padding: "10px", borderRadius: 8, border: `2px solid ${mode === m ? "#6366f1" : "#e2e8f0"}`, background: mode === m ? "#eef2ff" : "white", color: mode === m ? "#6366f1" : "#64748b", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>
                {m === "manual" ? "✏️ Manual Entry" : "📷 Scan Card (Camera)"}
              </button>
            ))}
          </div>

          {mode === "camera" && (
            <div style={{ background: "#1e2d3d", borderRadius: 12, padding: "40px", textAlign: "center", marginBottom: 20 }}>
              <div style={{ fontSize: 48, marginBottom: 12 }}>📷</div>
              <div style={{ color: "white", fontSize: 14, fontWeight: 700, marginBottom: 8 }}>Camera Scanner</div>
              <div style={{ color: "rgba(255,255,255,0.5)", fontSize: 12, marginBottom: 16 }}>Point your camera at a business card to auto-fill the form below</div>
              <div style={{ background: "rgba(255,255,255,0.1)", border: "2px dashed rgba(255,255,255,0.3)", borderRadius: 8, padding: "20px", color: "rgba(255,255,255,0.4)", fontSize: 12 }}>Camera requires deployment — available when hosted online</div>
            </div>
          )}

          <div style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 12, padding: 24, boxShadow: "0 1px 4px rgba(0,0,0,0.04)" }}>
            <div style={{ color: "#0f172a", fontSize: 14, fontWeight: 700, marginBottom: 16 }}>📇 Card Information</div>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14, marginBottom: 14 }}>
              <div><label style={lbl}>Full Name *</label><input value={form.name} onChange={e=>setForm(f=>({...f,name:e.target.value}))} placeholder="John Smith" style={inp} /></div>
              <div><label style={lbl}>Company</label><input value={form.company} onChange={e=>setForm(f=>({...f,company:e.target.value}))} placeholder="ABC Realty" style={inp} /></div>
              <div><label style={lbl}>Phone</label><input value={form.phone} onChange={e=>setForm(f=>({...f,phone:e.target.value}))} placeholder="(713) 555-0100" style={inp} /></div>
              <div><label style={lbl}>Email</label><input value={form.email} onChange={e=>setForm(f=>({...f,email:e.target.value}))} placeholder="john@email.com" style={inp} /></div>
              <div style={{ gridColumn: "1/-1" }}><label style={lbl}>Notes</label><input value={form.notes} onChange={e=>setForm(f=>({...f,notes:e.target.value}))} placeholder="Where did you meet them?" style={inp} /></div>
            </div>
            <button onClick={handleSave} disabled={!form.name} style={{ width: "100%", background: saved ? "#10b981" : form.name ? "#6366f1" : "#e2e8f0", border: "none", color: saved || form.name ? "white" : "#94a3b8", borderRadius: 8, padding: "12px", fontSize: 14, fontWeight: 700, cursor: form.name ? "pointer" : "default", fontFamily: "inherit" }}>
              {saved ? "✓ Contact Added to My Leads!" : "+ Add to My Leads"}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

// ─── Moving Checklist Generator ───────────────────────────────────────────────
function MovingChecklist() {
  const [client, setClient] = useState("The Kowalski Family");
  const [closeDate, setCloseDate] = useState("2026-06-10");
  const [generated, setGenerated] = useState(false);
  const [checked, setChecked] = useState({});

  const checklist = [
    { week: "8 Weeks Before", items: ["Hire a moving company or rent a truck", "Start decluttering — donate, sell, or discard", "Begin collecting packing supplies", "Notify employer of new address", "Research schools if applicable"] },
    { week: "6 Weeks Before", items: ["Start packing non-essential items", "Transfer or cancel local memberships/subscriptions", "Contact utility companies at current home", "Set up utilities at new home", "Update address with bank and credit cards"] },
    { week: "4 Weeks Before", items: ["Pack majority of belongings", "Confirm moving company details", "Notify USPS of address change", "Update drivers license address", "Transfer medical records and prescriptions"] },
    { week: "2 Weeks Before", items: ["Confirm closing date and time with Gerald", "Pack an essentials box for moving day", "Clean out refrigerator and pantry", "Arrange childcare/pet care for moving day", "Back up important documents"] },
    { week: "Moving Day", items: ["Do a final walkthrough of old home", "Take meter readings at old home", "Photograph any damage at new home before moving in", "Confirm all keys and garage openers received", "Call Gerald to celebrate! 🎉"] },
    { week: "After Moving In", items: ["Change locks on new home", "Test smoke and carbon monoxide detectors", "Locate water shutoff and circuit breakers", "Register to vote at new address", "Send Gerald a Google review 😊"] },
  ];

  const toggleCheck = (week, item) => {
    const key = week + item;
    setChecked(p => ({ ...p, [key]: !p[key] }));
  };
  const totalItems = checklist.reduce((s,w)=>s+w.items.length,0);
  const checkedItems = Object.values(checked).filter(Boolean).length;

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#f8fafc" }}>
      <TopBar title="Moving Checklist Generator" sub="Send buyers a personalized moving checklist at closing" />
      <div style={{ flex: 1, overflow: "auto", padding: 24 }}>
        <div style={{ display: "flex", gap: 12, marginBottom: 20, alignItems: "center" }}>
          <input value={client} onChange={e=>setClient(e.target.value)} placeholder="Client name" style={{ background: "#f8fafc", border: "1px solid #e2e8f0", color: "#0f172a", borderRadius: 6, padding: "9px 12px", fontSize: 13, outline: "none", fontFamily: "inherit", width: 220 }} />
          <input type="date" value={closeDate} onChange={e=>setCloseDate(e.target.value)} style={{ background: "#f8fafc", border: "1px solid #e2e8f0", color: "#0f172a", borderRadius: 6, padding: "9px 12px", fontSize: 13, outline: "none", fontFamily: "inherit" }} />
          <button onClick={() => setGenerated(true)} style={{ background: "#6366f1", border: "none", color: "white", borderRadius: 7, padding: "9px 18px", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>Generate Checklist</button>
          {generated && <button style={{ background: "#10b981", border: "none", color: "white", borderRadius: 7, padding: "9px 18px", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>📧 Send to Client</button>}
        </div>
        {generated && (
          <div style={{ maxWidth: 700 }}>
            <div style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 12, padding: "20px 24px", marginBottom: 20, display: "flex", justifyContent: "space-between", alignItems: "center", boxShadow: "0 1px 4px rgba(0,0,0,0.04)" }}>
              <div>
                <div style={{ color: "#0f172a", fontSize: 16, fontWeight: 800 }}>📦 Moving Checklist for {client}</div>
                <div style={{ color: "#64748b", fontSize: 13, marginTop: 2 }}>Closing Date: {closeDate} · Prepared by Gerald</div>
              </div>
              <div style={{ textAlign: "center" }}>
                <div style={{ color: "#6366f1", fontSize: 22, fontWeight: 800 }}>{checkedItems}/{totalItems}</div>
                <div style={{ color: "#94a3b8", fontSize: 11 }}>completed</div>
              </div>
            </div>
            {checklist.map(section => (
              <div key={section.week} style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 12, padding: "16px 20px", marginBottom: 12, boxShadow: "0 1px 3px rgba(0,0,0,0.04)" }}>
                <div style={{ color: "#6366f1", fontSize: 12, fontWeight: 800, textTransform: "uppercase", letterSpacing: "0.06em", marginBottom: 12 }}>{section.week}</div>
                {section.items.map(item => {
                  const key = section.week + item;
                  return (
                    <div key={item} onClick={() => toggleCheck(section.week, item)} style={{ display: "flex", alignItems: "center", gap: 12, padding: "8px 0", cursor: "pointer", borderBottom: "1px solid #f8fafc" }}>
                      <div style={{ width: 20, height: 20, borderRadius: 4, border: `2px solid ${checked[key] ? "#10b981" : "#e2e8f0"}`, background: checked[key] ? "#10b981" : "white", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
                        {checked[key] && <span style={{ color: "white", fontSize: 11, fontWeight: 800 }}>✓</span>}
                      </div>
                      <span style={{ color: checked[key] ? "#94a3b8" : "#0f172a", fontSize: 13, textDecoration: checked[key] ? "line-through" : "none" }}>{item}</span>
                    </div>
                  );
                })}
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

