// ─── Fix & Flip Calculator ────────────────────────────────────────────────────
function FixFlipCalculator() {
  const [form, setForm] = useState({
    purchasePrice: 180000, closingCostsBuy: 3000, rehabCost: 45000,
    holdingMonths: 4, holdingCostPerMonth: 1200, arv: 295000,
    closingCostsSell: 8850, agentCommission: 6, otherCosts: 2000
  });
  const set = (k, v) => setForm(f => ({ ...f, [k]: parseFloat(v) || 0 }));

  const totalInvestment = form.purchasePrice + form.closingCostsBuy + form.rehabCost + (form.holdingCostPerMonth * form.holdingMonths) + form.otherCosts;
  const sellingCosts = (form.arv * form.agentCommission / 100) + form.closingCostsSell;
  const netProfit = form.arv - totalInvestment - sellingCosts;
  const roi = totalInvestment > 0 ? ((netProfit / totalInvestment) * 100).toFixed(1) : 0;
  const annualizedROI = form.holdingMonths > 0 ? ((netProfit / totalInvestment) * (12 / form.holdingMonths) * 100).toFixed(1) : 0;
  const maxAllowableOffer = form.arv * 0.7 - form.rehabCost;

  const inp = { width: "100%", background: "#f8fafc", border: "1px solid #e2e8f0", color: "#0f172a", borderRadius: 6, padding: "9px 12px", fontSize: 13, outline: "none", fontFamily: "inherit", boxSizing: "border-box" };
  const lbl = { color: "#64748b", fontSize: 11, fontWeight: 600, display: "block", marginBottom: 5 };

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#f8fafc" }}>
      <TopBar title="Fix & Flip Calculator" sub="Analyze any flip deal in seconds" />
      <div style={{ flex: 1, overflow: "auto", padding: 24 }}>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 24, maxWidth: 920 }}>
          {/* Inputs */}
          <div style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 12, padding: 24, boxShadow: "0 1px 4px rgba(0,0,0,0.04)" }}>
            <div style={{ color: "#0f172a", fontSize: 15, fontWeight: 700, marginBottom: 20 }}>🔨 Deal Details</div>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14 }}>
              {[
                ["Purchase Price ($)", "purchasePrice"], ["Closing Costs — Buy ($)", "closingCostsBuy"],
                ["Rehab / Renovation ($)", "rehabCost"], ["Holding Months", "holdingMonths"],
                ["Holding Cost / Month ($)", "holdingCostPerMonth"], ["After Repair Value — ARV ($)", "arv"],
                ["Agent Commission (%)", "agentCommission"], ["Closing Costs — Sell ($)", "closingCostsSell"],
                ["Other Costs ($)", "otherCosts"],
              ].map(([label, key]) => (
                <div key={key} style={{ gridColumn: key === "arv" ? "1/-1" : "auto" }}>
                  <label style={lbl}>{label}</label>
                  <input type="number" value={form[key]} onChange={e => set(key, e.target.value)} style={{ ...inp, borderColor: key === "arv" ? "#6366f1" : "#e2e8f0", fontWeight: key === "arv" ? 700 : 400 }} />
                </div>
              ))}
            </div>
          </div>

          {/* Results */}
          <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
            {/* Profit Summary */}
            <div style={{ background: netProfit >= 0 ? "linear-gradient(135deg, #10b981, #059669)" : "linear-gradient(135deg, #ef4444, #dc2626)", borderRadius: 12, padding: "24px", color: "white" }}>
              <div style={{ fontSize: 12, letterSpacing: "0.1em", textTransform: "uppercase", opacity: 0.8, marginBottom: 8 }}>Estimated Net Profit</div>
              <div style={{ fontSize: 40, fontWeight: 800, marginBottom: 4 }}>{netProfit >= 0 ? fmt(Math.round(netProfit)) : "- " + fmt(Math.abs(Math.round(netProfit)))}</div>
              <div style={{ opacity: 0.85, fontSize: 14 }}>{roi}% ROI · {annualizedROI}% Annualized</div>
            </div>

            {/* Breakdown */}
            <div style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 12, padding: 20, boxShadow: "0 1px 4px rgba(0,0,0,0.04)" }}>
              <div style={{ color: "#0f172a", fontSize: 14, fontWeight: 700, marginBottom: 14 }}>Deal Breakdown</div>
              {[
                ["Purchase Price", fmt(form.purchasePrice), "#ef4444"],
                ["Closing Costs (Buy)", fmt(Math.round(form.closingCostsBuy)), "#ef4444"],
                ["Rehab Cost", fmt(Math.round(form.rehabCost)), "#ef4444"],
                ["Holding Costs", fmt(Math.round(form.holdingCostPerMonth * form.holdingMonths)), "#ef4444"],
                ["Selling Costs", fmt(Math.round(sellingCosts)), "#ef4444"],
                ["Total Investment", fmt(Math.round(totalInvestment + sellingCosts)), "#0f172a"],
                ["After Repair Value", fmt(form.arv), "#10b981"],
              ].map(([k,v,c]) => (
                <div key={k} style={{ display: "flex", justifyContent: "space-between", padding: "8px 0", borderBottom: "1px solid #f8fafc" }}>
                  <span style={{ color: "#475569", fontSize: 13 }}>{k}</span>
                  <span style={{ color: c, fontSize: 13, fontWeight: 600 }}>{v}</span>
                </div>
              ))}
            </div>

            {/* MAO */}
            <div style={{ background: "#fffbeb", border: "1px solid #fde68a", borderRadius: 12, padding: 20 }}>
              <div style={{ color: "#92400e", fontSize: 12, fontWeight: 700, marginBottom: 4 }}>💡 70% RULE — MAX ALLOWABLE OFFER</div>
              <div style={{ color: "#78350f", fontSize: 26, fontWeight: 800, marginBottom: 4 }}>{fmt(Math.round(maxAllowableOffer))}</div>
              <div style={{ color: "#92400e", fontSize: 12 }}>= (ARV × 70%) − Rehab Costs. Never pay more than this to stay profitable.</div>
            </div>

            {/* Deal Quality */}
            <div style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 12, padding: 20, boxShadow: "0 1px 4px rgba(0,0,0,0.04)" }}>
              <div style={{ color: "#0f172a", fontSize: 14, fontWeight: 700, marginBottom: 12 }}>Deal Quality</div>
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>
                {[["Net Profit", fmt(Math.round(netProfit)), netProfit > 30000 ? "#10b981" : netProfit > 10000 ? "#f59e0b" : "#ef4444"],
                  ["ROI", roi + "%", parseFloat(roi) > 20 ? "#10b981" : parseFloat(roi) > 10 ? "#f59e0b" : "#ef4444"],
                  ["Annualized ROI", annualizedROI + "%", parseFloat(annualizedROI) > 40 ? "#10b981" : "#f59e0b"],
                  ["Verdict", netProfit > 30000 ? "🟢 Strong Deal" : netProfit > 10000 ? "🟡 Marginal" : "🔴 Pass", "#0f172a"]
                ].map(([k,v,c]) => (
                  <div key={k} style={{ background: "#f8fafc", borderRadius: 8, padding: "12px 14px" }}>
                    <div style={{ color: "#94a3b8", fontSize: 10, fontWeight: 700, textTransform: "uppercase", marginBottom: 4 }}>{k}</div>
                    <div style={{ color: c, fontSize: 16, fontWeight: 800 }}>{v}</div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

// ─── Rental Property Analyzer ─────────────────────────────────────────────────
function RentalAnalyzer() {
  const [form, setForm] = useState({
    purchasePrice: 280000, downPayment: 20, interestRate: 7.25, loanTerm: 30,
    monthlyRent: 2200, vacancy: 5, propertyTax: 450, insurance: 120,
    maintenance: 150, propertyMgmt: 8, utilities: 0, otherExpenses: 50
  });
  const set = (k, v) => setForm(f => ({ ...f, [k]: parseFloat(v) || 0 }));

  const downPaymentAmt = form.purchasePrice * (form.downPayment / 100);
  const loanAmt = form.purchasePrice - downPaymentAmt;
  const monthlyRate = form.interestRate / 100 / 12;
  const numPayments = form.loanTerm * 12;
  const mortgage = loanAmt * (monthlyRate * Math.pow(1 + monthlyRate, numPayments)) / (Math.pow(1 + monthlyRate, numPayments) - 1);
  const effectiveRent = form.monthlyRent * (1 - form.vacancy / 100);
  const mgmtFee = effectiveRent * form.propertyMgmt / 100;
  const totalExpenses = mortgage + form.propertyTax + form.insurance + form.maintenance + mgmtFee + form.utilities + form.otherExpenses;
  const monthlyCashFlow = effectiveRent - totalExpenses;
  const annualCashFlow = monthlyCashFlow * 12;
  const cashOnCash = downPaymentAmt > 0 ? ((annualCashFlow / downPaymentAmt) * 100).toFixed(2) : 0;
  const grossRentMultiplier = (form.purchasePrice / (form.monthlyRent * 12)).toFixed(2);
  const capRate = ((((effectiveRent - (form.propertyTax + form.insurance + form.maintenance + mgmtFee + form.utilities + form.otherExpenses)) * 12) / form.purchasePrice) * 100).toFixed(2);

  const inp = { width: "100%", background: "#f8fafc", border: "1px solid #e2e8f0", color: "#0f172a", borderRadius: 6, padding: "9px 12px", fontSize: 13, outline: "none", fontFamily: "inherit", boxSizing: "border-box" };
  const lbl = { color: "#64748b", fontSize: 11, fontWeight: 600, display: "block", marginBottom: 5 };

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#f8fafc" }}>
      <TopBar title="Rental Property Analyzer" sub="Analyze cash flow, cap rate, and ROI for any rental property" />
      <div style={{ flex: 1, overflow: "auto", padding: 24 }}>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 24, maxWidth: 920 }}>
          {/* Inputs */}
          <div style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 12, padding: 24, boxShadow: "0 1px 4px rgba(0,0,0,0.04)" }}>
            <div style={{ color: "#0f172a", fontSize: 15, fontWeight: 700, marginBottom: 20 }}>🏘 Property Details</div>
            <div style={{ color: "#6366f1", fontSize: 12, fontWeight: 700, marginBottom: 12, textTransform: "uppercase", letterSpacing: "0.06em" }}>Purchase</div>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12, marginBottom: 20 }}>
              {[["Purchase Price ($)", "purchasePrice"], ["Down Payment (%)", "downPayment"], ["Interest Rate (%)", "interestRate"], ["Loan Term (years)", "loanTerm"]].map(([label, key]) => (
                <div key={key}><label style={lbl}>{label}</label><input type="number" value={form[key]} onChange={e => set(key, e.target.value)} style={inp} /></div>
              ))}
            </div>
            <div style={{ color: "#10b981", fontSize: 12, fontWeight: 700, marginBottom: 12, textTransform: "uppercase", letterSpacing: "0.06em" }}>Income</div>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12, marginBottom: 20 }}>
              {[["Monthly Rent ($)", "monthlyRent"], ["Vacancy Rate (%)", "vacancy"]].map(([label, key]) => (
                <div key={key}><label style={lbl}>{label}</label><input type="number" value={form[key]} onChange={e => set(key, e.target.value)} style={inp} /></div>
              ))}
            </div>
            <div style={{ color: "#ef4444", fontSize: 12, fontWeight: 700, marginBottom: 12, textTransform: "uppercase", letterSpacing: "0.06em" }}>Monthly Expenses</div>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
              {[["Property Tax ($)", "propertyTax"], ["Insurance ($)", "insurance"], ["Maintenance ($)", "maintenance"], ["Prop. Management (%)", "propertyMgmt"], ["Utilities ($)", "utilities"], ["Other ($)", "otherExpenses"]].map(([label, key]) => (
                <div key={key}><label style={lbl}>{label}</label><input type="number" value={form[key]} onChange={e => set(key, e.target.value)} style={inp} /></div>
              ))}
            </div>
          </div>

          {/* Results */}
          <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
            <div style={{ background: monthlyCashFlow >= 0 ? "linear-gradient(135deg, #10b981, #059669)" : "linear-gradient(135deg, #ef4444, #dc2626)", borderRadius: 12, padding: 24, color: "white" }}>
              <div style={{ fontSize: 12, letterSpacing: "0.1em", textTransform: "uppercase", opacity: 0.8, marginBottom: 8 }}>Monthly Cash Flow</div>
              <div style={{ fontSize: 40, fontWeight: 800, marginBottom: 4 }}>{monthlyCashFlow >= 0 ? "+" : ""}{fmt(Math.round(monthlyCashFlow))}</div>
              <div style={{ opacity: 0.85, fontSize: 14 }}>{fmt(Math.round(Math.abs(annualCashFlow)))}/year · {cashOnCash}% Cash-on-Cash</div>
            </div>

            <div style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 12, padding: 20, boxShadow: "0 1px 4px rgba(0,0,0,0.04)" }}>
              <div style={{ color: "#0f172a", fontSize: 14, fontWeight: 700, marginBottom: 14 }}>Monthly Income vs Expenses</div>
              {[
                ["Effective Rent", fmt(Math.round(effectiveRent)), "#10b981"],
                ["Mortgage Payment", "- " + fmt(Math.round(mortgage)), "#ef4444"],
                ["Property Tax", "- " + fmt(form.propertyTax), "#ef4444"],
                ["Insurance", "- " + fmt(form.insurance), "#ef4444"],
                ["Maintenance", "- " + fmt(form.maintenance), "#ef4444"],
                ["Prop. Management", "- " + fmt(Math.round(mgmtFee)), "#ef4444"],
                ["Other", "- " + fmt(form.utilities + form.otherExpenses), "#ef4444"],
              ].map(([k,v,c]) => (
                <div key={k} style={{ display: "flex", justifyContent: "space-between", padding: "8px 0", borderBottom: "1px solid #f8fafc" }}>
                  <span style={{ color: "#475569", fontSize: 13 }}>{k}</span>
                  <span style={{ color: c, fontSize: 13, fontWeight: 600 }}>{v}</span>
                </div>
              ))}
            </div>

            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
              {[
                ["Cap Rate", capRate + "%", parseFloat(capRate) > 6 ? "#10b981" : parseFloat(capRate) > 4 ? "#f59e0b" : "#ef4444"],
                ["Cash-on-Cash", cashOnCash + "%", parseFloat(cashOnCash) > 8 ? "#10b981" : parseFloat(cashOnCash) > 4 ? "#f59e0b" : "#ef4444"],
                ["Gross Rent Mult.", grossRentMultiplier + "x", parseFloat(grossRentMultiplier) < 12 ? "#10b981" : "#f59e0b"],
                ["Down Payment", fmt(Math.round(downPaymentAmt)), "#6366f1"],
                ["Loan Amount", fmt(Math.round(loanAmt)), "#0f172a"],
                ["Verdict", parseFloat(cashOnCash) > 8 ? "🟢 Strong Deal" : parseFloat(cashOnCash) > 4 ? "🟡 Marginal" : "🔴 Negative CF", "#0f172a"],
              ].map(([k,v,c]) => (
                <div key={k} style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 8, padding: "12px 14px", boxShadow: "0 1px 3px rgba(0,0,0,0.04)" }}>
                  <div style={{ color: "#94a3b8", fontSize: 10, fontWeight: 700, textTransform: "uppercase", marginBottom: 4 }}>{k}</div>
                  <div style={{ color: c, fontSize: 16, fontWeight: 800 }}>{v}</div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

// ─── Wholesale Deals ──────────────────────────────────────────────────────────
const INIT_WHOLESALE = [
  { id: 1, address: "4512 Tidwell Rd", city: "Houston", zip: "77016", arv: 185000, repairCost: 35000, askingPrice: 82000, mao: 94500, assignmentFee: 10000, status: "Analyzing", motivated: true, notes: "Seller behind on taxes, motivated. Property vacant 6 months." },
  { id: 2, address: "9203 Homestead Rd", city: "Houston", zip: "77016", arv: 220000, repairCost: 48000, askingPrice: 98000, mao: 106000, assignmentFee: 12000, status: "Under Contract", motivated: true, notes: "Estate sale, heirs want quick close. Great bones." },
  { id: 3, address: "2801 Telephone Rd", city: "Houston", zip: "77023", arv: 195000, repairCost: 28000, askingPrice: 115000, mao: 108500, assignmentFee: 0, status: "Passed", motivated: false, notes: "Seller asking too much. MAO is $108K, they want $115K." },
];
const wholesaleStatuses = ["Analyzing", "Offer Made", "Under Contract", "Assigned", "Closed", "Passed"];
const wholesaleStatusColors = { Analyzing: "#f59e0b", "Offer Made": "#0ea5e9", "Under Contract": "#8b5cf6", Assigned: "#ec4899", Closed: "#10b981", Passed: "#ef4444" };

function WholesaleDeals() {
  const [deals, setDeals] = useState(INIT_WHOLESALE);
  const [selected, setSelected] = useState(null);
  const [showAdd, setShowAdd] = useState(false);
  const [form, setForm] = useState({ address: "", city: "Houston", zip: "", arv: "", repairCost: "", askingPrice: "", assignmentFee: "", status: "Analyzing", motivated: false, notes: "" });
  const inp = { background: "#f8fafc", border: "1px solid #e2e8f0", color: "#0f172a", borderRadius: 6, padding: "8px 12px", fontSize: 13, outline: "none", fontFamily: "inherit", width: "100%", boxSizing: "border-box" };
  const lbl = { color: "#64748b", fontSize: 11, fontWeight: 600, display: "block", marginBottom: 5 };

  const calcMAO = (arv, repair) => Math.round(arv * 0.7 - repair);
  const totalAssignmentFees = deals.filter(d=>d.status==="Assigned"||d.status==="Closed").reduce((s,d)=>s+d.assignmentFee,0);

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#f8fafc" }}>
      <TopBar title="Wholesale Deals" sub="Track and analyze wholesale opportunities" action={
        <button onClick={() => setShowAdd(!showAdd)} style={{ background: "#6366f1", border: "none", color: "white", borderRadius: 7, padding: "9px 18px", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>+ Add Deal</button>
      } />
      {showAdd && (
        <div style={{ background: "white", borderBottom: "1px solid #f1f5f9", padding: "16px 24px" }}>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 12, marginBottom: 12 }}>
            <div style={{ gridColumn: "1/3" }}><label style={lbl}>Property Address</label><input value={form.address} onChange={e=>setForm(f=>({...f,address:e.target.value}))} style={inp} /></div>
            <div><label style={lbl}>City</label><input value={form.city} onChange={e=>setForm(f=>({...f,city:e.target.value}))} style={inp} /></div>
            <div><label style={lbl}>ZIP</label><input value={form.zip} onChange={e=>setForm(f=>({...f,zip:e.target.value}))} style={inp} /></div>
            <div><label style={lbl}>ARV ($)</label><input value={form.arv} onChange={e=>setForm(f=>({...f,arv:e.target.value}))} style={inp} /></div>
            <div><label style={lbl}>Repair Cost ($)</label><input value={form.repairCost} onChange={e=>setForm(f=>({...f,repairCost:e.target.value}))} style={inp} /></div>
            <div><label style={lbl}>Asking Price ($)</label><input value={form.askingPrice} onChange={e=>setForm(f=>({...f,askingPrice:e.target.value}))} style={inp} /></div>
            <div><label style={lbl}>Assignment Fee ($)</label><input value={form.assignmentFee} onChange={e=>setForm(f=>({...f,assignmentFee:e.target.value}))} style={inp} /></div>
            <div style={{ gridColumn: "1/-1" }}><label style={lbl}>Notes</label><input value={form.notes} onChange={e=>setForm(f=>({...f,notes:e.target.value}))} style={inp} /></div>
          </div>
          <div style={{ display: "flex", gap: 10, alignItems: "center" }}>
            <button onClick={() => { const arv=parseFloat(form.arv)||0; const repair=parseFloat(form.repairCost)||0; setDeals(p=>[...p,{...form,id:Date.now(),arv,repairCost:repair,askingPrice:parseFloat(form.askingPrice)||0,assignmentFee:parseFloat(form.assignmentFee)||0,mao:calcMAO(arv,repair)}]); setShowAdd(false); }} style={{ background: "#6366f1", border: "none", color: "white", borderRadius: 7, padding: "9px 20px", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>Save Deal</button>
            <button onClick={()=>setShowAdd(false)} style={{ background: "white", border: "1px solid #e2e8f0", color: "#64748b", borderRadius: 7, padding: "9px 14px", fontSize: 13, cursor: "pointer", fontFamily: "inherit" }}>Cancel</button>
          </div>
        </div>
      )}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 14, padding: "14px 24px", background: "white", borderBottom: "1px solid #f1f5f9" }}>
        {[["Total Deals", deals.length, "#6366f1"],["Active", deals.filter(d=>!["Passed","Closed"].includes(d.status)).length, "#f59e0b"],["Closed/Assigned", deals.filter(d=>["Assigned","Closed"].includes(d.status)).length, "#10b981"],["Total Fees Earned", fmt(totalAssignmentFees), "#10b981"]].map(([l,v,c]) => (
          <div key={l} style={{ textAlign: "center" }}>
            <div style={{ color: c, fontSize: 22, fontWeight: 800 }}>{v}</div>
            <div style={{ color: "#475569", fontSize: 12, fontWeight: 600 }}>{l}</div>
          </div>
        ))}
      </div>
      <div style={{ flex: 1, display: "flex", overflow: "hidden" }}>
        <div style={{ flex: selected ? "0 0 55%" : "1", overflow: "auto", borderRight: selected ? "1px solid #e2e8f0" : "none" }}>
          <table style={{ width: "100%", borderCollapse: "collapse" }}>
            <thead><tr style={{ background: "#f8fafc", borderBottom: "1px solid #f1f5f9" }}>{["Property","ARV","Repair","MAO","Asking","Spread","Status",""].map(h=><th key={h} style={{ padding: "10px 16px", color: "#94a3b8", fontSize: 11, fontWeight: 700, textAlign: "left", letterSpacing: "0.05em", textTransform: "uppercase" }}>{h}</th>)}</tr></thead>
            <tbody>
              {deals.map(d => {
                const spread = d.mao - d.askingPrice;
                return (
                  <tr key={d.id} onClick={() => setSelected(selected?.id===d.id?null:d)} style={{ borderBottom: "1px solid #f8fafc", cursor: "pointer", background: selected?.id===d.id?"#eef2ff":"white" }}>
                    <td style={{ padding: "13px 16px" }}>
                      <div style={{ color: "#0f172a", fontSize: 13, fontWeight: 700 }}>{d.address}</div>
                      <div style={{ color: "#94a3b8", fontSize: 11 }}>{d.city}, TX {d.zip}</div>
                    </td>
                    <td style={{ padding: "13px 16px", color: "#10b981", fontWeight: 700, fontSize: 13 }}>{fmt(d.arv)}</td>
                    <td style={{ padding: "13px 16px", color: "#ef4444", fontWeight: 600, fontSize: 13 }}>{fmt(d.repairCost)}</td>
                    <td style={{ padding: "13px 16px", color: "#6366f1", fontWeight: 700, fontSize: 13 }}>{fmt(d.mao)}</td>
                    <td style={{ padding: "13px 16px", color: "#0f172a", fontSize: 13 }}>{fmt(d.askingPrice)}</td>
                    <td style={{ padding: "13px 16px" }}><span style={{ color: spread > 0 ? "#10b981" : "#ef4444", fontWeight: 700, fontSize: 13 }}>{spread > 0 ? "+" : ""}{fmt(spread)}</span></td>
                    <td style={{ padding: "13px 16px" }}><span style={{ background: (wholesaleStatusColors[d.status]||"#94a3b8")+"18", color: wholesaleStatusColors[d.status]||"#94a3b8", fontSize: 11, fontWeight: 700, padding: "3px 9px", borderRadius: 4 }}>{d.status}</span></td>
                    <td style={{ padding: "13px 16px" }}>
                      <select value={d.status} onChange={e => { e.stopPropagation(); setDeals(p=>p.map(dl=>dl.id===d.id?{...dl,status:e.target.value}:dl)); }} style={{ background: "#f8fafc", border: "1px solid #e2e8f0", color: "#475569", borderRadius: 5, padding: "4px 8px", fontSize: 11, cursor: "pointer", outline: "none" }}>
                        {wholesaleStatuses.map(s=><option key={s}>{s}</option>)}
                      </select>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
        {selected && (
          <div style={{ flex: "0 0 45%", overflow: "auto", background: "white", padding: 24 }}>
            <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 20 }}>
              <div style={{ color: "#0f172a", fontSize: 16, fontWeight: 800 }}>{selected.address}</div>
              <button onClick={() => setSelected(null)} style={{ background: "#f8fafc", border: "1px solid #e2e8f0", color: "#64748b", borderRadius: 6, padding: "5px 10px", fontSize: 12, cursor: "pointer" }}>✕</button>
            </div>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10, marginBottom: 20 }}>
              {[["ARV", fmt(selected.arv)], ["Repair Cost", fmt(selected.repairCost)], ["MAO (70% Rule)", fmt(selected.mao)], ["Asking Price", fmt(selected.askingPrice)], ["Spread", fmt(selected.mao - selected.askingPrice)], ["Assignment Fee", fmt(selected.assignmentFee)]].map(([k,v]) => (
                <div key={k} style={{ background: "#f8fafc", borderRadius: 8, padding: "12px 14px" }}>
                  <div style={{ color: "#94a3b8", fontSize: 10, fontWeight: 700, textTransform: "uppercase", marginBottom: 4 }}>{k}</div>
                  <div style={{ color: k === "Spread" ? (selected.mao - selected.askingPrice > 0 ? "#10b981" : "#ef4444") : k === "ARV" ? "#10b981" : "#0f172a", fontSize: 15, fontWeight: 800 }}>{v}</div>
                </div>
              ))}
            </div>
            {selected.motivated && <div style={{ background: "#fef3c7", border: "1px solid #fde68a", borderRadius: 8, padding: "10px 14px", marginBottom: 14 }}><div style={{ color: "#92400e", fontSize: 12, fontWeight: 700 }}>🔥 MOTIVATED SELLER</div></div>}
            <div style={{ background: "#f8fafc", borderRadius: 8, padding: "14px", marginBottom: 16 }}><div style={{ color: "#64748b", fontSize: 13, lineHeight: 1.6 }}>{selected.notes}</div></div>
            <div style={{ display: "flex", gap: 8 }}>
              <button style={{ flex: 1, background: "#6366f1", border: "none", color: "white", borderRadius: 7, padding: "11px", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>Make Offer</button>
              <button style={{ flex: 1, background: "#f8fafc", border: "1px solid #e2e8f0", color: "#475569", borderRadius: 7, padding: "10px", fontSize: 13, cursor: "pointer", fontFamily: "inherit" }}>Find Buyer</button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

