// ─── Brokerage Dashboard ──────────────────────────────────────────────────────
function BrokerageDashboard({ contacts }) {
  const totalGCI = BROKERAGE_AGENTS.reduce((s,a) => s+a.gciYTD, 0);
  const brokerGCI = Math.round(BROKERAGE_AGENTS.reduce((s,a) => s + (a.gciYTD * (1 - a.split/100)), 0));
  const totalVolume = BROKERAGE_AGENTS.reduce((s,a) => s+a.volumeYTD, 0);
  const totalClosings = BROKERAGE_AGENTS.reduce((s,a) => s+a.closedYTD, 0);
  const activeListings = BROKERAGE_LISTINGS.filter(l=>l.status==="Active").length;
  const doubleSided = BROKERAGE_LISTINGS.filter(l=>l.bothSides).length;

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#f8fafc" }}>
      <TopBar title="Brokerage Dashboard" sub="Gerald's Real Estate Brokerage · TX License #TX-BK-2019-00142" />
      <div style={{ flex: 1, overflow: "auto", padding: 24 }}>
        {/* KPI Cards */}
        <div style={{ display: "grid", gridTemplateColumns: "repeat(3,1fr)", gap: 14, marginBottom: 20 }}>
          {[
            ["Total GCI (All Agents)", "$"+totalGCI.toLocaleString(), "#059669", "YTD 2026"],
            ["Your Broker Cut", "$"+brokerGCI.toLocaleString(), "#1d4ed8", "After agent splits"],
            ["Total Volume", "$"+(totalVolume/1e6).toFixed(1)+"M", "#f59e0b", "All transactions"],
            ["Total Closings", totalClosings, "#10b981", "All agents combined"],
            ["Active Listings", activeListings, "#1d4ed8", "Brokerage inventory"],
            ["Double-Sided Deals", doubleSided, "#8b5cf6", "Both sides captured"],
          ].map(([l,v,c,sub]) => (
            <div key={l} style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 12, padding: "18px 20px", boxShadow: "0 1px 4px rgba(0,0,0,0.04)" }}>
              <div style={{ color: "#94a3b8", fontSize: 11, fontWeight: 700, textTransform: "uppercase", letterSpacing: "0.06em", marginBottom: 8 }}>{l}</div>
              <div style={{ color: c, fontSize: 28, fontWeight: 800, marginBottom: 2 }}>{v}</div>
              <div style={{ color: "#94a3b8", fontSize: 11 }}>{sub}</div>
            </div>
          ))}
        </div>

        {/* Agent Performance */}
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 20, marginBottom: 20 }}>
          <div style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 12, padding: 20, boxShadow: "0 1px 4px rgba(0,0,0,0.04)" }}>
            <div style={{ color: "#0f172a", fontSize: 14, fontWeight: 700, marginBottom: 16 }}>👥 Agent Performance</div>
            {BROKERAGE_AGENTS.filter(a=>a.split>0).sort((a,b)=>b.gciYTD-a.gciYTD).map((a,i) => (
              <div key={a.id} style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 14 }}>
                <div style={{ width: 32, height: 32, borderRadius: "50%", background: a.color, color: "white", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 12, fontWeight: 800, flexShrink: 0 }}>{a.avatar}</div>
                <div style={{ flex: 1 }}>
                  <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 4 }}>
                    <span style={{ color: "#0f172a", fontSize: 13, fontWeight: 700 }}>{a.name}</span>
                    <span style={{ color: "#059669", fontSize: 13, fontWeight: 700 }}>${a.gciYTD.toLocaleString()}</span>
                  </div>
                  <div style={{ height: 5, background: "#f1f5f9", borderRadius: 3, overflow: "hidden" }}>
                    <div style={{ width: (a.gciYTD/BROKERAGE_AGENTS[0].gciYTD*100)+"%", height: "100%", background: a.color, borderRadius: 3 }} />
                  </div>
                </div>
              </div>
            ))}
          </div>

          <div style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 12, padding: 20, boxShadow: "0 1px 4px rgba(0,0,0,0.04)" }}>
            <div style={{ color: "#0f172a", fontSize: 14, fontWeight: 700, marginBottom: 16 }}>🏆 Brokerage Goals 2026</div>
            {[
              ["Total GCI Target", "$500K", totalGCI, 500000, "#059669"],
              ["Agent Count", "8 agents", BROKERAGE_AGENTS.length, 8, "#1d4ed8"],
              ["Total Closings", "50 closes", totalClosings, 50, "#f59e0b"],
              ["Market Share", "15%", 3, 15, "#8b5cf6"],
            ].map(([label, target, current, max, color]) => {
              const pct = Math.min(100, Math.round(current/max*100));
              return (
                <div key={label} style={{ marginBottom: 14 }}>
                  <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 5 }}>
                    <span style={{ color: "#475569", fontSize: 12, fontWeight: 600 }}>{label}</span>
                    <span style={{ color: "#94a3b8", fontSize: 12 }}>{pct}% of {target}</span>
                  </div>
                  <div style={{ height: 8, background: "#f1f5f9", borderRadius: 4, overflow: "hidden" }}>
                    <div style={{ width: pct+"%", height: "100%", background: color, borderRadius: 4 }} />
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Recent Brokerage Activity */}
        <div style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 12, padding: 20, boxShadow: "0 1px 4px rgba(0,0,0,0.04)" }}>
          <div style={{ color: "#0f172a", fontSize: 14, fontWeight: 700, marginBottom: 16 }}>📋 Recent Brokerage Activity</div>
          {[
            { icon: "🏠", text: "Marcus Webb listed 88 Riverside Blvd at $620K", time: "2h ago", color: "#10b981" },
            { icon: "🔄", text: "Double-sided deal closed — 88 Riverside Blvd. Brokerage earns both sides!", time: "1d ago", color: "#8b5cf6" },
            { icon: "👤", text: "Angela Pierce joined the brokerage — Buyer Agent", time: "2d ago", color: "#1d4ed8" },
            { icon: "📈", text: "Sarah Chen hit 4 closings YTD — on pace for bonus", time: "3d ago", color: "#f59e0b" },
            { icon: "🎯", text: "New recruit Carlos Reyes scheduled interview", time: "4d ago", color: "#ec4899" },
          ].map((a,i) => (
            <div key={i} style={{ display: "flex", gap: 12, alignItems: "center", padding: "10px 0", borderBottom: i<4?"1px solid #f8fafc":"none" }}>
              <div style={{ width: 32, height: 32, borderRadius: 8, background: a.color+"18", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 16, flexShrink: 0 }}>{a.icon}</div>
              <div style={{ flex: 1, color: "#0f172a", fontSize: 13 }}>{a.text}</div>
              <div style={{ color: "#94a3b8", fontSize: 11, whiteSpace: "nowrap" }}>{a.time}</div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

// ─── Agent Management ─────────────────────────────────────────────────────────
function AgentManagement() {
  const [agents, setAgents] = useState(BROKERAGE_AGENTS);
  const [selected, setSelected] = useState(null);
  const [showAdd, setShowAdd] = useState(false);
  const [form, setForm] = useState({ name: "", role: "Buyer Agent", license: "", phone: "", email: "", split: "70", status: "Active" });
  const inp = { width: "100%", background: "#f8fafc", border: "1px solid #e2e8f0", color: "#0f172a", borderRadius: 6, padding: "9px 12px", fontSize: 13, outline: "none", fontFamily: "inherit", boxSizing: "border-box" };
  const colors = ["#1d4ed8","#10b981","#f59e0b","#8b5cf6","#ec4899","#ef4444","#0d9488","#f97316"];

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#f8fafc" }}>
      <TopBar title="Agent Management" sub={`${agents.filter(a=>a.status==="Active").length} active agents under your license`} action={
        <button onClick={()=>setShowAdd(!showAdd)} style={{ background: "#1d4ed8", border: "none", color: "white", borderRadius: 7, padding: "9px 18px", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>+ Add Agent</button>
      } />
      {showAdd && (
        <div style={{ background: "white", borderBottom: "1px solid #f1f5f9", padding: "16px 24px" }}>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 12, marginBottom: 12 }}>
            {[["Full Name","name"],["Role","role"],["TX License #","license"],["Phone","phone"],["Email","email"],["Commission Split %","split"]].map(([label,key]) => (
              <div key={key}><div style={{ color: "#64748b", fontSize: 11, fontWeight: 600, marginBottom: 4 }}>{label}</div>
                {key==="role"
                  ? <select value={form[key]} onChange={e=>setForm(f=>({...f,[key]:e.target.value}))} style={{...inp,cursor:"pointer"}}><option>Buyer Agent</option><option>Listing Agent</option><option>Transaction Coordinator</option><option>ISA</option><option>Team Lead</option></select>
                  : <input value={form[key]} onChange={e=>setForm(f=>({...f,[key]:e.target.value}))} style={inp} />
                }
              </div>
            ))}
          </div>
          <div style={{ display: "flex", gap: 10 }}>
            <button onClick={()=>{ setAgents(p=>[...p,{...form,id:Date.now(),joinDate:new Date().toISOString().split("T")[0],listings:0,leads:0,closedYTD:0,volumeYTD:0,gciYTD:0,split:parseInt(form.split)||70,avatar:form.name[0]||"?",color:colors[agents.length%colors.length]}]); setShowAdd(false); }} style={{ background: "#1d4ed8", border: "none", color: "white", borderRadius: 7, padding: "9px 20px", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>Add Agent</button>
            <button onClick={()=>setShowAdd(false)} style={{ background: "white", border: "1px solid #e2e8f0", color: "#64748b", borderRadius: 7, padding: "9px 14px", fontSize: 13, cursor: "pointer", fontFamily: "inherit" }}>Cancel</button>
          </div>
        </div>
      )}
      <div style={{ flex: 1, display: "flex", overflow: "hidden" }}>
        <div style={{ flex: selected?"0 0 55%":"1", overflow: "auto", borderRight: selected?"1px solid #f1f5f9":"none" }}>
          <table style={{ width: "100%", borderCollapse: "collapse" }}>
            <thead><tr style={{ background: "#f8fafc", borderBottom: "1px solid #f1f5f9" }}>{["Agent","Role","License","Split","Closings","GCI YTD","Volume YTD","Status"].map(h=><th key={h} style={{ padding: "10px 16px", color: "#94a3b8", fontSize: 11, fontWeight: 700, textAlign: "left", letterSpacing: "0.05em", textTransform: "uppercase" }}>{h}</th>)}</tr></thead>
            <tbody>
              {agents.map(a => (
                <tr key={a.id} onClick={()=>setSelected(selected?.id===a.id?null:a)} style={{ borderBottom: "1px solid #f8fafc", cursor: "pointer", background: selected?.id===a.id?"#eff6ff":"white" }}>
                  <td style={{ padding: "13px 16px" }}>
                    <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                      <div style={{ width: 34, height: 34, borderRadius: "50%", background: a.color, color: "white", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 13, fontWeight: 800, flexShrink: 0 }}>{a.avatar}</div>
                      <div><div style={{ color: "#0f172a", fontSize: 13, fontWeight: 700 }}>{a.name}{a.role==="Broker/Owner"?" 👑":""}</div><div style={{ color: "#94a3b8", fontSize: 11 }}>{a.email}</div></div>
                    </div>
                  </td>
                  <td style={{ padding: "13px 16px" }}><span style={{ background: "#eff6ff", color: "#1d4ed8", fontSize: 11, fontWeight: 700, padding: "2px 8px", borderRadius: 4 }}>{a.role}</span></td>
                  <td style={{ padding: "13px 16px", color: "#475569", fontSize: 12, fontFamily: "monospace" }}>{a.license}</td>
                  <td style={{ padding: "13px 16px", color: "#f59e0b", fontWeight: 700, fontSize: 13 }}>{a.split>0?a.split+"%":"Staff"}</td>
                  <td style={{ padding: "13px 16px", color: "#0f172a", fontWeight: 600, fontSize: 13 }}>{a.closedYTD}</td>
                  <td style={{ padding: "13px 16px", color: "#059669", fontWeight: 700, fontSize: 13 }}>${a.gciYTD.toLocaleString()}</td>
                  <td style={{ padding: "13px 16px", color: "#475569", fontSize: 13 }}>${(a.volumeYTD/1000).toFixed(0)}K</td>
                  <td style={{ padding: "13px 16px" }}><span style={{ background: a.status==="Active"?"#dcfce7":"#f1f5f9", color: a.status==="Active"?"#16a34a":"#94a3b8", fontSize: 11, fontWeight: 700, padding: "2px 8px", borderRadius: 10 }}>{a.status}</span></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        {selected && (
          <div style={{ flex: "0 0 45%", overflow: "auto", background: "white", padding: 24 }}>
            <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 20 }}>
              <div style={{ display: "flex", gap: 14, alignItems: "center" }}>
                <div style={{ width: 52, height: 52, borderRadius: "50%", background: selected.color, color: "white", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 20, fontWeight: 800 }}>{selected.avatar}</div>
                <div><div style={{ color: "#0f172a", fontSize: 17, fontWeight: 800 }}>{selected.name}</div><div style={{ color: "#64748b", fontSize: 13 }}>{selected.role}</div></div>
              </div>
              <button onClick={()=>setSelected(null)} style={{ background: "#f8fafc", border: "1px solid #e2e8f0", color: "#64748b", borderRadius: 6, padding: "5px 10px", fontSize: 12, cursor: "pointer" }}>✕</button>
            </div>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10, marginBottom: 20 }}>
              {[["Commission Split", selected.split>0?selected.split+"%":"Staff/Fixed"],["License #", selected.license||"N/A"],["Joined", selected.joinDate],["Phone", selected.phone],["Closings YTD", selected.closedYTD],["GCI YTD", "$"+selected.gciYTD.toLocaleString()],["Volume YTD", "$"+(selected.volumeYTD/1000).toFixed(0)+"K"],["Broker Cut", "$"+Math.round(selected.gciYTD*(1-selected.split/100)).toLocaleString()]].map(([k,v]) => (
                <div key={k} style={{ background: "#f8fafc", borderRadius: 8, padding: "12px 14px" }}>
                  <div style={{ color: "#94a3b8", fontSize: 10, fontWeight: 700, textTransform: "uppercase", marginBottom: 4 }}>{k}</div>
                  <div style={{ color: k==="GCI YTD"?"#059669":k==="Broker Cut"?"#1d4ed8":"#0f172a", fontSize: 14, fontWeight: 700 }}>{v}</div>
                </div>
              ))}
            </div>
            <div style={{ display: "flex", gap: 8 }}>
              <button style={{ flex: 1, background: "#1d4ed8", border: "none", color: "white", borderRadius: 7, padding: "10px", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>📧 Email Agent</button>
              <button style={{ flex: 1, background: "#f8fafc", border: "1px solid #e2e8f0", color: "#475569", borderRadius: 7, padding: "10px", fontSize: 13, cursor: "pointer", fontFamily: "inherit" }}>Edit Profile</button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

// ─── Listing Inventory ────────────────────────────────────────────────────────
function ListingInventory() {
  const [filter, setFilter] = useState("All");
  const [agentFilter, setAgentFilter] = useState("All");
  const statuses = ["All","Active","Under Contract","Closed"];
  const agents = ["All",...new Set(BROKERAGE_LISTINGS.map(l=>l.agent))];
  const filtered = BROKERAGE_LISTINGS.filter(l=>(filter==="All"||l.status===filter)&&(agentFilter==="All"||l.agent===agentFilter));
  const totalActive = BROKERAGE_LISTINGS.filter(l=>l.status==="Active").reduce((s,l)=>s+l.price,0);

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#f8fafc" }}>
      <TopBar title="Listing Inventory" sub={`${BROKERAGE_LISTINGS.filter(l=>l.status==="Active").length} active listings · $${(totalActive/1e6).toFixed(1)}M inventory`} action={
        <button style={{ background: "#1d4ed8", border: "none", color: "white", borderRadius: 7, padding: "9px 18px", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>+ New Listing</button>
      } />
      <div style={{ padding: "10px 20px", background: "white", borderBottom: "1px solid #f1f5f9", display: "flex", gap: 8, flexWrap: "wrap" }}>
        <select value={agentFilter} onChange={e=>setAgentFilter(e.target.value)} style={{ background: "#f8fafc", border: "1px solid #e2e8f0", color: "#0f172a", borderRadius: 6, padding: "7px 12px", fontSize: 12, outline: "none", cursor: "pointer", fontFamily: "inherit" }}>
          {agents.map(a=><option key={a}>{a}</option>)}
        </select>
        {statuses.map(s=><button key={s} onClick={()=>setFilter(s)} style={{ padding: "6px 14px", borderRadius: 6, border: `1px solid ${filter===s?"#1d4ed8":"#e2e8f0"}`, background: filter===s?"#eff6ff":"white", color: filter===s?"#1d4ed8":"#64748b", fontSize: 12, fontWeight: 600, cursor: "pointer" }}>{s}</button>)}
      </div>
      <div style={{ flex: 1, overflow: "auto" }}>
        <table style={{ width: "100%", borderCollapse: "collapse" }}>
          <thead><tr style={{ background: "#f8fafc", borderBottom: "1px solid #f1f5f9" }}>{["Property","Agent","Price","Type","ZIP","Listed","DOM","Status","Both Sides"].map(h=><th key={h} style={{ padding: "10px 16px", color: "#94a3b8", fontSize: 11, fontWeight: 700, textAlign: "left", letterSpacing: "0.05em", textTransform: "uppercase" }}>{h}</th>)}</tr></thead>
          <tbody>
            {filtered.map(l => {
              const agent = BROKERAGE_AGENTS.find(a=>a.name===l.agent);
              return (
                <tr key={l.id} style={{ borderBottom: "1px solid #f8fafc", background: l.bothSides?"#fdf4ff":"white" }}>
                  <td style={{ padding: "13px 16px" }}>
                    <div style={{ color: "#0f172a", fontSize: 13, fontWeight: 700 }}>{l.address}</div>
                    <div style={{ color: "#94a3b8", fontSize: 11 }}>{l.zip}</div>
                  </td>
                  <td style={{ padding: "13px 16px" }}>
                    <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                      <div style={{ width: 24, height: 24, borderRadius: "50%", background: agent?.color||"#94a3b8", color: "white", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 10, fontWeight: 800 }}>{l.agent[0]}</div>
                      <span style={{ color: "#475569", fontSize: 13 }}>{l.agent}</span>
                    </div>
                  </td>
                  <td style={{ padding: "13px 16px", color: "#059669", fontWeight: 700, fontSize: 13 }}>{fmt(l.price)}</td>
                  <td style={{ padding: "13px 16px" }}><span style={{ background: (propertyTypeColors[l.type]||"#94a3b8")+"18", color: propertyTypeColors[l.type]||"#94a3b8", fontSize: 11, fontWeight: 700, padding: "2px 8px", borderRadius: 4 }}>{l.type}</span></td>
                  <td style={{ padding: "13px 16px", color: "#475569", fontSize: 13 }}>{l.zip}</td>
                  <td style={{ padding: "13px 16px", color: "#94a3b8", fontSize: 12 }}>{l.listed}</td>
                  <td style={{ padding: "13px 16px", color: l.dom>30?"#ef4444":l.dom>14?"#f59e0b":"#059669", fontWeight: 700, fontSize: 13 }}>{l.dom}d</td>
                  <td style={{ padding: "13px 16px" }}><span style={{ background: (listingStatusColors[l.status]||"#94a3b8")+"18", color: listingStatusColors[l.status]||"#94a3b8", fontSize: 11, fontWeight: 700, padding: "2px 8px", borderRadius: 4 }}>{l.status}</span></td>
                  <td style={{ padding: "13px 16px" }}>{l.bothSides?<span style={{ background: "#fdf4ff", color: "#8b5cf6", fontSize: 11, fontWeight: 800, padding: "2px 8px", borderRadius: 10 }}>🔄 BOTH SIDES</span>:<span style={{ color: "#94a3b8", fontSize: 12 }}>—</span>}</td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
}

// ─── Double-Sided Deal Tracker ────────────────────────────────────────────────
function DoubleSidedDeals() {
  const [deals, setDeals] = useState([
    { id: 1, address: "88 Riverside Blvd #401", listingAgent: "Marcus Webb", buyerAgent: "Sarah Chen", price: 620000, commRate: 6, status: "Under Contract", closeDate: "2026-06-10", notes: "Brokerage represents both sides — full 6% commission stays in-house" },
    { id: 2, address: "1103 Cedar Ridge Ct", listingAgent: "Marcus Webb", buyerAgent: "Gerald", price: 495000, commRate: 6, status: "Closed", closeDate: "2026-05-15", notes: "Closed double-sided. Total commission: $29,700 kept in brokerage." },
  ]);

  const totalComm = deals.filter(d=>d.status==="Closed").reduce((s,d)=>s+(d.price*d.commRate/100),0);
  const pendingComm = deals.filter(d=>d.status!=="Closed").reduce((s,d)=>s+(d.price*d.commRate/100),0);

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#f8fafc" }}>
      <TopBar title="Double-Sided Deal Tracker" sub="Deals where your brokerage represents both buyer AND seller" action={
        <button style={{ background: "#8b5cf6", border: "none", color: "white", borderRadius: 7, padding: "9px 18px", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>+ Log Double-Sided Deal</button>
      } />
      <div style={{ display: "grid", gridTemplateColumns: "repeat(3,1fr)", gap: 14, padding: "14px 24px", background: "white", borderBottom: "1px solid #f1f5f9" }}>
        {[["Total Double-Sided", deals.length, "#8b5cf6"],["Closed Commission", "$"+Math.round(totalComm).toLocaleString(), "#059669"],["Pending Commission", "$"+Math.round(pendingComm).toLocaleString(), "#f59e0b"]].map(([l,v,c])=>(
          <div key={l} style={{ textAlign: "center" }}>
            <div style={{ color: c, fontSize: 24, fontWeight: 800 }}>{v}</div>
            <div style={{ color: "#475569", fontSize: 12, fontWeight: 600 }}>{l}</div>
          </div>
        ))}
      </div>
      <div style={{ flex: 1, overflow: "auto", padding: 24 }}>
        <div style={{ background: "#fdf4ff", border: "1px solid #e9d5ff", borderRadius: 10, padding: "14px 18px", marginBottom: 20 }}>
          <div style={{ color: "#7c3aed", fontSize: 13, fontWeight: 700, marginBottom: 4 }}>💡 Why Double-Sided Deals Matter</div>
          <div style={{ color: "#4c1d95", fontSize: 13, lineHeight: 1.6 }}>When your brokerage represents both the buyer AND the seller, you keep 100% of the total commission instead of splitting with another brokerage. On a $600K home at 6%, that's $36,000 vs $18,000 — double the revenue. This is why top brokers always check their own listings first when a buyer comes in.</div>
        </div>
        {deals.map(d => {
          const totalComm2 = Math.round(d.price * d.commRate / 100);
          return (
            <div key={d.id} style={{ background: "white", border: "2px solid #e9d5ff", borderRadius: 12, padding: "20px 22px", marginBottom: 14, boxShadow: "0 1px 4px rgba(0,0,0,0.04)" }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 14 }}>
                <div>
                  <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 4 }}>
                    <div style={{ color: "#0f172a", fontSize: 15, fontWeight: 800 }}>{d.address}</div>
                    <span style={{ background: "#fdf4ff", color: "#8b5cf6", fontSize: 11, fontWeight: 800, padding: "2px 8px", borderRadius: 10 }}>🔄 BOTH SIDES</span>
                  </div>
                  <div style={{ color: "#64748b", fontSize: 13 }}>Close: {d.closeDate}</div>
                </div>
                <div style={{ textAlign: "right" }}>
                  <div style={{ color: "#059669", fontSize: 22, fontWeight: 800 }}>${totalComm2.toLocaleString()}</div>
                  <div style={{ color: "#94a3b8", fontSize: 12 }}>Full commission in-house</div>
                </div>
              </div>
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr 1fr", gap: 10, marginBottom: 14 }}>
                {[["Listing Agent", d.listingAgent],["Buyer Agent", d.buyerAgent],["Sale Price", fmt(d.price)],["Comm Rate", d.commRate+"%"]].map(([k,v])=>(
                  <div key={k} style={{ background: "#f8fafc", borderRadius: 7, padding: "10px 12px" }}>
                    <div style={{ color: "#94a3b8", fontSize: 10, fontWeight: 700, textTransform: "uppercase", marginBottom: 4 }}>{k}</div>
                    <div style={{ color: "#0f172a", fontSize: 13, fontWeight: 700 }}>{v}</div>
                  </div>
                ))}
              </div>
              <div style={{ color: "#64748b", fontSize: 13, fontStyle: "italic" }}>{d.notes}</div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

