const ISA_LEADS = [
  { id: 1, name: "Tom & Beth Harris", phone: "(713) 441-2200", source: "Zillow", callDate: "2026-05-24", callDuration: "8 min", status: "Qualified", score: 88, budget: 450000, timeline: "30-60 days", assignedTo: "Sarah Chen", notes: "Pre-approved, serious buyer. Ready to tour this week." },
  { id: 2, name: "Sam Lee", phone: "(832) 551-8800", source: "Google Ads", callDate: "2026-05-24", callDuration: "4 min", status: "Nurture", score: 52, budget: 320000, timeline: "6+ months", assignedTo: null, notes: "Early stage, not ready yet. Follow up in 90 days." },
  { id: 3, name: "The Pham Family", phone: "(713) 774-3381", source: "Facebook Ads", callDate: "2026-05-23", callDuration: "12 min", status: "Qualified", score: 81, budget: 380000, timeline: "30 days", assignedTo: "Angela Pierce", notes: "Must move before school starts. Very motivated family." },
  { id: 4, name: "Rachel Espinoza", phone: "(713) 882-4401", source: "IDX Website", callDate: "2026-05-22", callDuration: "6 min", status: "Not Interested", score: 15, budget: 0, timeline: "N/A", assignedTo: null, notes: "Just browsing, not ready to buy or sell." },
];
const isaStatusColors = { Qualified: "#059669", Nurture: "#f59e0b", "Not Interested": "#ef4444", "Attempted Contact": "#94a3b8", "Left Voicemail": "#0d9488" };

function ISAPipeline({ contacts, setContacts }) {
  const [leads] = useState(ISA_LEADS);
  const qualified = leads.filter(l=>l.status==="Qualified").length;
  const converted = Math.round(qualified / leads.length * 100);

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#f8fafc" }}>
      <TopBar title="ISA Pipeline" sub="Inside Sales Agent — track lead qualification calls" action={
        <button style={{ background: "#1d4ed8", border: "none", color: "white", borderRadius: 7, padding: "9px 18px", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>+ Log Call</button>
      } />
      <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 14, padding: "14px 24px", background: "white", borderBottom: "1px solid #f1f5f9" }}>
        {[["Total Calls", leads.length, "#1d4ed8"],["Qualified", qualified, "#059669"],["Conv. Rate", converted+"%", "#f59e0b"],["Assigned to Agent", leads.filter(l=>l.assignedTo).length, "#8b5cf6"]].map(([l,v,c])=>(
          <div key={l} style={{ textAlign: "center" }}>
            <div style={{ color: c, fontSize: 24, fontWeight: 800 }}>{v}</div>
            <div style={{ color: "#475569", fontSize: 12, fontWeight: 600 }}>{l}</div>
          </div>
        ))}
      </div>
      <div style={{ flex: 1, overflow: "auto" }}>
        <table style={{ width: "100%", borderCollapse: "collapse" }}>
          <thead><tr style={{ background: "#f8fafc", borderBottom: "1px solid #f1f5f9" }}>{["Lead","Source","Score","Status","Budget","Timeline","Assigned To","Notes"].map(h=><th key={h} style={{ padding: "10px 16px", color: "#94a3b8", fontSize: 11, fontWeight: 700, textAlign: "left", letterSpacing: "0.05em", textTransform: "uppercase" }}>{h}</th>)}</tr></thead>
          <tbody>
            {leads.map(l => (
              <tr key={l.id} style={{ borderBottom: "1px solid #f8fafc", background: l.status==="Qualified"?"#f0fdf4":"white" }}>
                <td style={{ padding: "13px 16px" }}>
                  <div style={{ color: "#0f172a", fontSize: 13, fontWeight: 700 }}>{l.name}</div>
                  <div style={{ color: "#94a3b8", fontSize: 11 }}>{l.phone} · {l.callDuration}</div>
                </td>
                <td style={{ padding: "13px 16px" }}><span style={{ background: (sourceColors[l.source]||"#94a3b8")+"18", color: sourceColors[l.source]||"#94a3b8", fontSize: 11, fontWeight: 700, padding: "2px 8px", borderRadius: 4 }}>{l.source}</span></td>
                <td style={{ padding: "13px 16px" }}>
                  <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
                    <div style={{ width: 30, height: 30, borderRadius: "50%", background: scoreColor(l.score), color: "white", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 11, fontWeight: 800 }}>{l.score}</div>
                  </div>
                </td>
                <td style={{ padding: "13px 16px" }}><span style={{ background: (isaStatusColors[l.status]||"#94a3b8")+"18", color: isaStatusColors[l.status]||"#94a3b8", fontSize: 11, fontWeight: 700, padding: "2px 8px", borderRadius: 4 }}>{l.status}</span></td>
                <td style={{ padding: "13px 16px", color: l.budget>0?"#059669":"#94a3b8", fontWeight: 700, fontSize: 13 }}>{l.budget>0?fmt(l.budget):"—"}</td>
                <td style={{ padding: "13px 16px", color: "#475569", fontSize: 12 }}>{l.timeline}</td>
                <td style={{ padding: "13px 16px" }}>
                  {l.assignedTo
                    ? <span style={{ background: "#eff6ff", color: "#1d4ed8", fontSize: 11, fontWeight: 700, padding: "2px 8px", borderRadius: 4 }}>{l.assignedTo}</span>
                    : l.status==="Qualified"
                      ? <button onClick={()=>setContacts(p=>[...p,{id:Date.now(),name:l.name,phone:l.phone,email:"",stage:"Hot Lead",temperature:"Hot",budget:l.budget,preApproved:false,interest:[],lastContact:new Date().toISOString().split("T")[0],agent:"Gerald",source:l.source,tags:["ISA Qualified"],notes:l.notes,score:l.score,lastActivity:"ISA Qualified — ready for agent"}])} style={{ background: "#1d4ed8", border: "none", color: "white", borderRadius: 6, padding: "5px 12px", fontSize: 11, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>Assign</button>
                      : <span style={{ color: "#94a3b8", fontSize: 12 }}>—</span>
                  }
                </td>
                <td style={{ padding: "13px 16px", color: "#64748b", fontSize: 12, maxWidth: 200 }}>{l.notes}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

