// ─── Bilingual Lead Forms ─────────────────────────────────────────────────────
function BilingualLeadForms() {
  const [lang, setLang] = useState("spanish");
  const [copied, setCopied] = useState(false);

  const forms = {
    english: { title: "Buyer Inquiry", fields: ["Full Name","Email","Phone","Budget","Desired Area","Bedrooms Needed","Timeline to Buy","Are you pre-approved?"], cta: "Submit", color: "#1d4ed8" },
    spanish: { title: "Consulta de Comprador", fields: ["Nombre Completo","Correo Electrónico","Teléfono","Presupuesto","Área Deseada","Recámaras que Necesita","¿Cuándo Piensa Comprar?","¿Tiene Pre-Aprobación?"], cta: "Enviar", color: "#dc2626" },
  };
  const f = forms[lang];
  const embedCode = `<iframe src="https://estateiq.app/capture/${lang}-buyer?agent=gerald" width="100%" height="650" frameborder="0"></iframe>`;

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#f8fafc" }}>
      <TopBar title="🇺🇸🇪🇸 Bilingual Lead Capture Forms" sub="Capture leads in English and Spanish — flows straight into EstateIQ" />
      <div style={{ flex: 1, overflow: "auto", padding: 24 }}>
        <div style={{ display: "flex", gap: 10, marginBottom: 20 }}>
          <button onClick={()=>setLang("english")} style={{ flex: 1, padding: "12px", borderRadius: 9, border: `2px solid ${lang==="english"?"#1d4ed8":"#e2e8f0"}`, background: lang==="english"?"#eff6ff":"white", color: lang==="english"?"#1d4ed8":"#64748b", fontSize: 14, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>🇺🇸 English Form</button>
          <button onClick={()=>setLang("spanish")} style={{ flex: 1, padding: "12px", borderRadius: 9, border: `2px solid ${lang==="spanish"?"#dc2626":"#e2e8f0"}`, background: lang==="spanish"?"#fff5f5":"white", color: lang==="spanish"?"#dc2626":"#64748b", fontSize: 14, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>🇪🇸 Formulario en Español</button>
        </div>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 20 }}>
          {/* Preview */}
          <div style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 12, overflow: "hidden", boxShadow: "0 2px 8px rgba(0,0,0,0.06)" }}>
            <div style={{ background: f.color, padding: "16px 20px" }}>
              <div style={{ color: "white", fontSize: 15, fontWeight: 800 }}>{f.title}</div>
              <div style={{ color: "rgba(255,255,255,0.7)", fontSize: 12, marginTop: 2 }}>EstateIQ · Gerald · {lang==="spanish"?"Se habla español":"Houston Real Estate"}</div>
            </div>
            <div style={{ padding: "16px 20px" }}>
              {f.fields.map(field => (
                <div key={field} style={{ marginBottom: 12 }}>
                  <div style={{ color: "#475569", fontSize: 11, fontWeight: 600, marginBottom: 4 }}>{field}</div>
                  <div style={{ background: "#f8fafc", border: "1px solid #e2e8f0", borderRadius: 6, padding: "9px 12px", fontSize: 13, color: "#94a3b8" }}>
                    {field.includes("¿") || field.includes("pre") || field.includes("approved") ? lang==="spanish"?"Sí / No":"Yes / No" : lang==="spanish"?"Escriba aquí...":"Enter here..."}
                  </div>
                </div>
              ))}
              <button style={{ width: "100%", background: f.color, border: "none", color: "white", borderRadius: 8, padding: "12px", fontSize: 14, fontWeight: 700, cursor: "pointer", fontFamily: "inherit", marginTop: 4 }}>{f.cta} →</button>
            </div>
          </div>
          {/* Embed code */}
          <div>
            <div style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 12, padding: 20, marginBottom: 16 }}>
              <div style={{ color: "#0f172a", fontSize: 14, fontWeight: 700, marginBottom: 12 }}>Embed on Your Website</div>
              <div style={{ background: "#0f172a", borderRadius: 8, padding: "14px 16px", marginBottom: 12, fontFamily: "monospace", fontSize: 11, color: "#a5f3fc", lineHeight: 1.6, wordBreak: "break-all" }}>{embedCode}</div>
              <button onClick={() => { navigator.clipboard.writeText(embedCode).catch(()=>{}); setCopied(true); setTimeout(()=>setCopied(false),2000); }} style={{ width: "100%", background: copied?"#059669":f.color, border: "none", color: "white", borderRadius: 7, padding: "10px", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>
                {copied?"✓ Copied!":"📋 Copy Embed Code"}
              </button>
            </div>
            <div style={{ background: "#fff5f5", border: "1px solid #fecaca", borderRadius: 10, padding: 16 }}>
              <div style={{ color: "#dc2626", fontSize: 12, fontWeight: 700, marginBottom: 8 }}>🇪🇸 Marketing Tip — Spanish Market</div>
              {["Houston has 1.7M+ Spanish speakers — the largest market in Texas","Add 'Se Habla Español' to your website and Google Business profile","Run Facebook Ads in Spanish targeting Houston ZIP codes with high Hispanic populations","The Spanish-speaking market is UNDERSERVED — this is your competitive advantage","Partner with your wife as a bilingual ISA to qualify Spanish-speaking leads"].map((t,i)=>(
                <div key={i} style={{ display: "flex", gap: 8, marginBottom: 6 }}>
                  <span style={{ color: "#dc2626", fontWeight: 700, flexShrink: 0 }}>•</span>
                  <span style={{ color: "#991b1b", fontSize: 12, lineHeight: 1.5 }}>{t}</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

