// ─── Realtor Exam Prep ────────────────────────────────────────────────────────
function RealtorExamPrep() {
  const [completedTopics, setCompletedTopics] = useState([]);
  const topics = [
    { id: 1, category: "Texas License Law", title: "TREC Rules & Regulations", desc: "Texas Real Estate Commission rules, license requirements, and disciplinary procedures", hours: 3, difficulty: "Medium" },
    { id: 2, category: "Texas License Law", title: "License Requirements & Renewal", desc: "How to obtain, maintain, and renew your Texas real estate license", hours: 2, difficulty: "Easy" },
    { id: 3, category: "Contracts", title: "TREC One to Four Family Contract", desc: "The most common Texas residential purchase contract — every clause explained", hours: 4, difficulty: "Hard" },
    { id: 4, category: "Contracts", title: "Addenda & Amendments", desc: "Common addenda including financing, inspections, and seller concessions", hours: 2, difficulty: "Medium" },
    { id: 5, category: "Agency Law", title: "Fiduciary Duties", desc: "Understanding your duties to clients — loyalty, confidentiality, disclosure, obedience", hours: 2, difficulty: "Medium" },
    { id: 6, category: "Agency Law", title: "Buyer & Seller Representation", desc: "How to properly represent buyers and sellers under Texas law", hours: 2, difficulty: "Medium" },
    { id: 7, category: "Finance", title: "Mortgage Types & Qualification", desc: "Conventional, FHA, VA, USDA loans and how buyers qualify", hours: 3, difficulty: "Medium" },
    { id: 8, category: "Finance", title: "Closing Costs & Settlement", desc: "What happens at closing — prorations, fees, and the HUD-1 statement", hours: 2, difficulty: "Medium" },
    { id: 9, category: "Property Law", title: "Texas Property Rights & Ownership", desc: "Community property, homestead rights, deed types, and easements", hours: 3, difficulty: "Hard" },
    { id: 10, category: "Appraisal", title: "Property Valuation Methods", desc: "Sales comparison, income, and cost approaches to valuing real estate", hours: 3, difficulty: "Medium" },
    { id: 11, category: "Fair Housing", title: "Fair Housing Act", desc: "Protected classes, prohibited practices, and your legal obligations", hours: 2, difficulty: "Easy" },
    { id: 12, category: "Math", title: "Real Estate Math", desc: "Commissions, prorations, area calculations, and loan-to-value ratios", hours: 4, difficulty: "Hard" },
  ];
  const categories = [...new Set(topics.map(t => t.category))];
  const completed = completedTopics.length;
  const pct = Math.round((completed / topics.length) * 100);
  const diffColors = { Easy: "#059669", Medium: "#f59e0b", Hard: "#ef4444" };
  const toggle = (id) => setCompletedTopics(p => p.includes(id) ? p.filter(x=>x!==id) : [...p, id]);

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#f8fafc" }}>
      <TopBar title="🎓 Texas Realtor Exam Prep" sub="Personalized study guide for the Texas Real Estate Salesperson Exam" />
      <div style={{ padding: "12px 24px", background: "white", borderBottom: "1px solid #f1f5f9" }}>
        <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 6 }}>
          <span style={{ color: "#0f172a", fontSize: 13, fontWeight: 700 }}>Study Progress — {completed}/{topics.length} topics completed</span>
          <span style={{ color: "#be185d", fontWeight: 700, fontSize: 13 }}>{pct}%</span>
        </div>
        <div style={{ height: 10, background: "#f1f5f9", borderRadius: 5, overflow: "hidden" }}>
          <div style={{ width: pct+"%", height: "100%", background: "linear-gradient(90deg, #be185d, #9d174d)", borderRadius: 5, transition: "width 0.3s" }} />
        </div>
      </div>
      <div style={{ flex: 1, overflow: "auto", padding: 20 }}>
        <div style={{ background: "#fdf2f8", border: "1px solid #f9a8d4", borderRadius: 10, padding: "14px 18px", marginBottom: 20 }}>
          <div style={{ color: "#be185d", fontSize: 13, fontWeight: 700, marginBottom: 4 }}>📚 Texas Real Estate Exam Overview</div>
          <div style={{ color: "#9d174d", fontSize: 13, lineHeight: 1.6 }}>The Texas Salesperson exam has two parts: <strong>National (85 questions)</strong> and <strong>State (40 questions)</strong>. You need 70% to pass each. With Gerald's guidance and this study guide, you'll be well prepared. Total study time: ~30 hours. Gerald can mentor you through every topic!</div>
        </div>
        {categories.map(cat => (
          <div key={cat} style={{ marginBottom: 20 }}>
            <div style={{ color: "#475569", fontSize: 11, fontWeight: 700, textTransform: "uppercase", letterSpacing: "0.08em", marginBottom: 10 }}>{cat}</div>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(300px,1fr))", gap: 10 }}>
              {topics.filter(t=>t.category===cat).map(t => {
                const done = completedTopics.includes(t.id);
                return (
                  <div key={t.id} onClick={()=>toggle(t.id)} style={{ background: "white", border: `2px solid ${done?"#be185d":"#f1f5f9"}`, borderRadius: 10, padding: "14px 16px", cursor: "pointer", transition: "all 0.15s", opacity: done?0.85:1 }}>
                    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 8 }}>
                      <div style={{ display: "flex", gap: 10, alignItems: "center" }}>
                        <div style={{ width: 22, height: 22, borderRadius: 5, border: `2px solid ${done?"#be185d":"#e2e8f0"}`, background: done?"#be185d":"white", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
                          {done && <span style={{ color: "white", fontSize: 11, fontWeight: 800 }}>✓</span>}
                        </div>
                        <div style={{ color: "#0f172a", fontSize: 13, fontWeight: 700, textDecoration: done?"line-through":"none" }}>{t.title}</div>
                      </div>
                      <span style={{ background: diffColors[t.difficulty]+"18", color: diffColors[t.difficulty], fontSize: 10, fontWeight: 700, padding: "2px 7px", borderRadius: 4, flexShrink: 0 }}>{t.difficulty}</span>
                    </div>
                    <div style={{ color: "#64748b", fontSize: 12, marginBottom: 6, lineHeight: 1.4 }}>{t.desc}</div>
                    <div style={{ color: "#94a3b8", fontSize: 11 }}>⏱ ~{t.hours} hours</div>
                  </div>
                );
              })}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

