                <td style={{ padding: "13px 16px" }}><span style={{ background: (sourceColors[l.source]||"#94a3b8")+"18", color: sourceColors[l.source]||"#94a3b8", fontSize: 11, fontWeight: 700, padding: "2px 8px", borderRadius: 4 }}>{l.source}</span></td>
