function LandingPageBuilder({ contacts, setContacts }) {
  const [step, setStep] = useState("gallery"); // gallery | editor | preview | published
  const [selectedTemplate, setSelectedTemplate] = useState(null);
  const [customized, setCustomized] = useState({});
  const [publishedPages, setPublishedPages] = useState([
    { id: 1, template: LP_TEMPLATES[0], url: "gerald.estateiq.app/home-value", views: 142, leads: 18, published: "2026-05-01", active: true },
    { id: 2, template: LP_TEMPLATES[2], url: "gerald.estateiq.app/valor-casa", views: 89, leads: 12, published: "2026-05-10", active: true },
  ]);
  const [copiedUrl, setCopiedUrl] = useState(null);
  const [filterCat, setFilterCat] = useState("All");

  const tpl = selectedTemplate ? { ...selectedTemplate, ...customized } : null;
  const categories = ["All", ...new Set(LP_TEMPLATES.map(t => t.category))];
  const filtered = LP_TEMPLATES.filter(t => filterCat === "All" || t.category === filterCat);

  const startEdit = (template) => {
    setSelectedTemplate(template);
    setCustomized({
      headline: template.headline,
      subheadline: template.subheadline,
      cta: template.cta,
      agentName: "Gerald",
      agentPhone: "(713) 555-0100",
      agentEmail: "gerald@estateiq.com",
      agentTagline: "Licensed Broker · Houston, TX · Se Habla Español",
    });
    setStep("editor");
  };

  const publish = () => {
    const slug = tpl.headline.toLowerCase().replace(/[^a-z0-9]+/g, "-").slice(0, 30);
    setPublishedPages(p => [...p, {
      id: Date.now(),
      template: { ...tpl },
      url: `gerald.estateiq.app/${slug}`,
      views: 0,
      leads: 0,
      published: new Date().toISOString().split("T")[0],
      active: true,
    }]);
    setStep("published");
  };

  const inp = { width: "100%", background: "#f8fafc", border: "1px solid #e2e8f0", color: "#0f172a", borderRadius: 6, padding: "9px 12px", fontSize: 13, outline: "none", fontFamily: "inherit", boxSizing: "border-box" };
  const lbl = { color: "#64748b", fontSize: 11, fontWeight: 600, display: "block", marginBottom: 5 };

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#f8fafc" }}>
      <TopBar
        title="🌐 Landing Page Builder"
        sub="Create beautiful lead capture pages — no coding needed"
        action={
          <div style={{ display: "flex", gap: 8 }}>
            {step !== "gallery" && <button onClick={() => { setStep("gallery"); setSelectedTemplate(null); }} style={{ background: "white", border: "1px solid #e2e8f0", color: "#475569", borderRadius: 7, padding: "9px 16px", fontSize: 13, cursor: "pointer", fontFamily: "inherit" }}>← Back</button>}
            {step === "editor" && <button onClick={() => setStep("preview")} style={{ background: "#f59e0b", border: "none", color: "white", borderRadius: 7, padding: "9px 18px", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>Preview →</button>}
            {step === "preview" && <button onClick={publish} style={{ background: "#059669", border: "none", color: "white", borderRadius: 7, padding: "9px 18px", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>🚀 Publish Page</button>}
          </div>
        }
      />

      {/* Step indicator */}
      {step !== "gallery" && (
        <div style={{ background: "white", borderBottom: "1px solid #f1f5f9", padding: "10px 24px", display: "flex", gap: 0 }}>
          {[["1", "Choose Template"], ["2", "Customize"], ["3", "Preview"], ["4", "Publish"]].map(([num, label], i) => {
            const stepNum = { gallery: 1, editor: 2, preview: 3, published: 4 }[step];
            const active = parseInt(num) <= stepNum;
            return (
              <div key={num} style={{ display: "flex", alignItems: "center" }}>
                <div style={{ display: "flex", alignItems: "center", gap: 7 }}>
                  <div style={{ width: 24, height: 24, borderRadius: "50%", background: active ? "#f59e0b" : "#f1f5f9", color: active ? "white" : "#94a3b8", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 11, fontWeight: 800 }}>{stepNum > parseInt(num) ? "✓" : num}</div>
                  <span style={{ color: active ? "#0f172a" : "#94a3b8", fontSize: 12, fontWeight: active ? 700 : 400 }}>{label}</span>
                </div>
                {i < 3 && <div style={{ width: 32, height: 2, background: active && parseInt(num) < stepNum ? "#f59e0b" : "#f1f5f9", margin: "0 10px" }} />}
              </div>
            );
          })}
        </div>
      )}

      <div style={{ flex: 1, overflow: "auto", padding: 24 }}>

        {/* GALLERY */}
        {step === "gallery" && (
          <div>
            {/* Published pages stats */}
            {publishedPages.length > 0 && (
              <div style={{ marginBottom: 28 }}>
                <div style={{ color: "#0f172a", fontSize: 15, fontWeight: 700, marginBottom: 14 }}>📊 Your Published Pages</div>
                <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(300px,1fr))", gap: 14, marginBottom: 20 }}>
                  {publishedPages.map(page => (
                    <div key={page.id} style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 12, padding: "18px 20px", boxShadow: "0 1px 4px rgba(0,0,0,0.04)" }}>
                      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 12 }}>
                        <div>
                          <div style={{ color: "#0f172a", fontSize: 13, fontWeight: 700, marginBottom: 4 }}>{page.template.name}</div>
                          <div style={{ color: "#3b82f6", fontSize: 12, fontFamily: "monospace" }}>{page.url}</div>
                        </div>
                        <span style={{ background: "#dcfce7", color: "#16a34a", fontSize: 10, fontWeight: 700, padding: "2px 8px", borderRadius: 10 }}>LIVE</span>
                      </div>
                      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 8, marginBottom: 12 }}>
                        {[["Views", page.views, "#3b82f6"], ["Leads", page.leads, "#059669"], ["Conv%", page.views > 0 ? Math.round(page.leads/page.views*100)+"%" : "—", "#f59e0b"]].map(([l,v,c]) => (
                          <div key={l} style={{ background: "#f8fafc", borderRadius: 6, padding: "8px", textAlign: "center" }}>
                            <div style={{ color: c, fontSize: 16, fontWeight: 800 }}>{v}</div>
                            <div style={{ color: "#94a3b8", fontSize: 10 }}>{l}</div>
                          </div>
                        ))}
                      </div>
                      <div style={{ display: "flex", gap: 6 }}>
                        <button onClick={() => { navigator.clipboard.writeText("https://"+page.url).catch(()=>{}); setCopiedUrl(page.id); setTimeout(()=>setCopiedUrl(null),2000); }} style={{ flex: 1, background: copiedUrl===page.id?"#059669":"#3b82f6", border: "none", color: "white", borderRadius: 6, padding: "7px", fontSize: 11, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>{copiedUrl===page.id?"✓ Copied!":"📋 Copy URL"}</button>
                        <button style={{ flex: 1, background: "#f8fafc", border: "1px solid #e2e8f0", color: "#475569", borderRadius: 6, padding: "7px", fontSize: 11, cursor: "pointer", fontFamily: "inherit" }}>✏️ Edit</button>
                        <button style={{ background: "#f8fafc", border: "1px solid #e2e8f0", color: "#475569", borderRadius: 6, padding: "7px 10px", fontSize: 11, cursor: "pointer" }}>📊</button>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Template gallery */}
            <div style={{ color: "#0f172a", fontSize: 15, fontWeight: 700, marginBottom: 14 }}>🎨 Choose a Template</div>
            <div style={{ display: "flex", gap: 8, marginBottom: 16, flexWrap: "wrap" }}>
              {categories.map(c => (
                <button key={c} onClick={() => setFilterCat(c)} style={{ padding: "6px 14px", borderRadius: 6, border: `1px solid ${filterCat===c?"#f59e0b":"#e2e8f0"}`, background: filterCat===c?"#fffbeb":"white", color: filterCat===c?"#f59e0b":"#64748b", fontSize: 12, fontWeight: 600, cursor: "pointer" }}>{c}</button>
              ))}
            </div>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(260px,1fr))", gap: 16 }}>
              {filtered.map(t => (
                <div key={t.id} style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 12, overflow: "hidden", boxShadow: "0 2px 8px rgba(0,0,0,0.06)", cursor: "pointer", transition: "transform 0.15s", display: "flex", flexDirection: "column" }} onClick={() => startEdit(t)}>
                  {/* Mini preview */}
                  <div style={{ background: t.bgColor, padding: "20px 16px", textAlign: "center" }}>
                    <div style={{ fontSize: 28, marginBottom: 8 }}>{t.icon}</div>
                    <div style={{ color: "white", fontSize: 13, fontWeight: 800, marginBottom: 4, lineHeight: 1.3 }}>{t.headline}</div>
                    <div style={{ color: "rgba(255,255,255,0.6)", fontSize: 10, lineHeight: 1.4, marginBottom: 10 }}>{t.subheadline}</div>
                    <div style={{ background: t.accentColor, color: "white", borderRadius: 6, padding: "6px 12px", fontSize: 11, fontWeight: 700, display: "inline-block" }}>{t.cta} →</div>
                  </div>
                  <div style={{ padding: "14px 16px", flex: 1 }}>
                    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
                      <div style={{ color: "#0f172a", fontSize: 13, fontWeight: 700 }}>{t.name}</div>
                    </div>
                    <div style={{ display: "flex", gap: 6, flexWrap: "wrap", marginBottom: 12 }}>
                      <span style={{ background: (t.color)+"18", color: t.color, fontSize: 10, fontWeight: 700, padding: "2px 7px", borderRadius: 4 }}>{t.category}</span>
                      <span style={{ background: t.lang==="Spanish"?"#fff5f5":"#eff6ff", color: t.lang==="Spanish"?"#dc2626":"#1d4ed8", fontSize: 10, fontWeight: 700, padding: "2px 7px", borderRadius: 4 }}>{t.lang==="Spanish"?"🇪🇸 Español":"🇺🇸 English"}</span>
                    </div>
                    <div style={{ color: "#94a3b8", fontSize: 11, marginBottom: 12 }}>📋 {t.fields.length} form fields</div>
                    <button style={{ width: "100%", background: t.color, border: "none", color: "white", borderRadius: 7, padding: "9px", fontSize: 12, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>
                      Use This Template →
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* EDITOR */}
        {step === "editor" && tpl && (
          <div style={{ display: "grid", gridTemplateColumns: "380px 1fr", gap: 24, maxWidth: 1000 }}>
            <div style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 12, padding: 24, boxShadow: "0 1px 4px rgba(0,0,0,0.04)" }}>
              <div style={{ color: "#0f172a", fontSize: 14, fontWeight: 700, marginBottom: 20 }}>✏️ Customize Your Page</div>
              <div style={{ marginBottom: 14 }}><label style={lbl}>Page Headline</label><input value={customized.headline||tpl.headline} onChange={e=>setCustomized(c=>({...c,headline:e.target.value}))} style={inp} /></div>
              <div style={{ marginBottom: 14 }}><label style={lbl}>Subheadline</label><textarea value={customized.subheadline||tpl.subheadline} onChange={e=>setCustomized(c=>({...c,subheadline:e.target.value}))} rows={2} style={{...inp,resize:"none",lineHeight:1.6}} /></div>
              <div style={{ marginBottom: 14 }}><label style={lbl}>Button Text</label><input value={customized.cta||tpl.cta} onChange={e=>setCustomized(c=>({...c,cta:e.target.value}))} style={inp} /></div>
              <div style={{ borderTop: "1px solid #f1f5f9", paddingTop: 14, marginTop: 14 }}>
                <div style={{ color: "#0f172a", fontSize: 12, fontWeight: 700, marginBottom: 12 }}>Your Contact Info</div>
                <div style={{ marginBottom: 12 }}><label style={lbl}>Your Name</label><input value={customized.agentName||"Gerald"} onChange={e=>setCustomized(c=>({...c,agentName:e.target.value}))} style={inp} /></div>
                <div style={{ marginBottom: 12 }}><label style={lbl}>Phone</label><input value={customized.agentPhone||"(713) 555-0100"} onChange={e=>setCustomized(c=>({...c,agentPhone:e.target.value}))} style={inp} /></div>
                <div style={{ marginBottom: 12 }}><label style={lbl}>Email</label><input value={customized.agentEmail||"gerald@estateiq.com"} onChange={e=>setCustomized(c=>({...c,agentEmail:e.target.value}))} style={inp} /></div>
                <div style={{ marginBottom: 12 }}><label style={lbl}>Tagline</label><input value={customized.agentTagline||tpl.agentTagline} onChange={e=>setCustomized(c=>({...c,agentTagline:e.target.value}))} style={inp} /></div>
              </div>
              <div style={{ borderTop: "1px solid #f1f5f9", paddingTop: 14, marginTop: 4 }}>
                <div style={{ color: "#0f172a", fontSize: 12, fontWeight: 700, marginBottom: 10 }}>Form Fields</div>
                {tpl.fields.map((field, i) => (
                  <div key={i} style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 6 }}>
                    <div style={{ width: 18, height: 18, borderRadius: 4, background: tpl.accentColor, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
                      <span style={{ color: "white", fontSize: 10, fontWeight: 800 }}>✓</span>
                    </div>
                    <span style={{ color: "#475569", fontSize: 12 }}>{field}</span>
                  </div>
                ))}
              </div>
            </div>

            {/* Live preview */}
            <div>
              <div style={{ color: "#475569", fontSize: 12, fontWeight: 600, marginBottom: 10 }}>Live Preview</div>
              <div style={{ background: tpl.bgColor, borderRadius: 12, overflow: "hidden", boxShadow: "0 8px 24px rgba(0,0,0,0.15)" }}>
                {/* Hero */}
                <div style={{ padding: "40px 32px", textAlign: "center" }}>
                  <div style={{ fontSize: 40, marginBottom: 16 }}>{tpl.icon}</div>
                  <div style={{ color: "white", fontSize: 24, fontWeight: 800, marginBottom: 10, lineHeight: 1.3 }}>{customized.headline||tpl.headline}</div>
                  <div style={{ color: "rgba(255,255,255,0.75)", fontSize: 14, lineHeight: 1.6, marginBottom: 24, maxWidth: 380, margin: "0 auto 24px" }}>{customized.subheadline||tpl.subheadline}</div>
                </div>
                {/* Form */}
                <div style={{ background: "white", margin: "0 24px 24px", borderRadius: 12, padding: "24px 24px 20px" }}>
                  <div style={{ color: "#0f172a", fontSize: 15, fontWeight: 700, marginBottom: 16, textAlign: "center" }}>{customized.cta||tpl.cta}</div>
                  {tpl.fields.slice(0,3).map(field => (
                    <div key={field} style={{ background: "#f8fafc", border: "1px solid #e2e8f0", borderRadius: 6, padding: "10px 12px", fontSize: 12, color: "#94a3b8", marginBottom: 8 }}>{field}...</div>
                  ))}
                  {tpl.fields.length > 3 && <div style={{ color: "#94a3b8", fontSize: 11, textAlign: "center", marginBottom: 8 }}>+ {tpl.fields.length - 3} more fields</div>}
                  <button style={{ width: "100%", background: tpl.accentColor, border: "none", color: "white", borderRadius: 8, padding: "13px", fontSize: 14, fontWeight: 800, cursor: "pointer", fontFamily: "inherit", marginTop: 4 }}>
                    {customized.cta||tpl.cta} →
                  </button>
                </div>
                {/* Footer */}
                <div style={{ padding: "16px 24px 24px", textAlign: "center" }}>
                  <div style={{ color: "rgba(255,255,255,0.9)", fontSize: 14, fontWeight: 700 }}>{customized.agentName||"Gerald"}</div>
                  <div style={{ color: "rgba(255,255,255,0.5)", fontSize: 12 }}>{customized.agentPhone||"(713) 555-0100"} · {customized.agentEmail||"gerald@estateiq.com"}</div>
                  <div style={{ color: "rgba(255,255,255,0.4)", fontSize: 11, marginTop: 4 }}>{customized.agentTagline||tpl.agentTagline||"Licensed Broker · Houston, TX"}</div>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* PREVIEW */}
        {step === "preview" && tpl && (
          <div style={{ maxWidth: 600, margin: "0 auto" }}>
            <div style={{ background: "#f0f9ff", border: "1px solid #bae6fd", borderRadius: 10, padding: "12px 18px", marginBottom: 20 }}>
              <div style={{ color: "#0369a1", fontSize: 13, fontWeight: 700 }}>📱 This is exactly how your landing page will look to visitors</div>
            </div>
            <div style={{ background: tpl.bgColor, borderRadius: 16, overflow: "hidden", boxShadow: "0 12px 40px rgba(0,0,0,0.2)" }}>
              <div style={{ padding: "48px 36px 32px", textAlign: "center" }}>
                <div style={{ fontSize: 52, marginBottom: 20 }}>{tpl.icon}</div>
                <div style={{ color: "white", fontSize: 28, fontWeight: 800, marginBottom: 12, lineHeight: 1.3 }}>{customized.headline||tpl.headline}</div>
                <div style={{ color: "rgba(255,255,255,0.75)", fontSize: 15, lineHeight: 1.7, maxWidth: 420, margin: "0 auto" }}>{customized.subheadline||tpl.subheadline}</div>
              </div>
              <div style={{ background: "white", margin: "0 28px 28px", borderRadius: 14, padding: "28px 28px 24px", boxShadow: "0 4px 16px rgba(0,0,0,0.1)" }}>
                <div style={{ color: "#0f172a", fontSize: 17, fontWeight: 800, marginBottom: 20, textAlign: "center" }}>{customized.cta||tpl.cta}</div>
                {tpl.fields.map(field => (
                  <div key={field} style={{ background: "#f8fafc", border: "1px solid #e2e8f0", borderRadius: 8, padding: "12px 14px", fontSize: 13, color: "#94a3b8", marginBottom: 10 }}>{field}...</div>
                ))}
                <button style={{ width: "100%", background: tpl.accentColor, border: "none", color: "white", borderRadius: 10, padding: "15px", fontSize: 15, fontWeight: 800, cursor: "pointer", fontFamily: "inherit", marginTop: 8 }}>
                  {customized.cta||tpl.cta} →
                </button>
                <div style={{ color: "#94a3b8", fontSize: 11, textAlign: "center", marginTop: 10 }}>🔒 Your information is 100% private and secure</div>
              </div>
              <div style={{ padding: "16px 28px 32px", textAlign: "center" }}>
                <img src={GERALD_PHOTO_RED} alt="Gerald" style={{ width: 52, height: 52, borderRadius: "50%", objectFit: "cover", objectPosition: "top", margin: "0 auto 12px", display: "block", border: "3px solid rgba(255,255,255,0.4)" }} />
                <div style={{ color: "white", fontSize: 16, fontWeight: 800 }}>{customized.agentName||"Gerald"}</div>
                <div style={{ color: "rgba(255,255,255,0.6)", fontSize: 13, marginTop: 2 }}>{customized.agentTagline||"Licensed Broker · Houston, TX · Se Habla Español"}</div>
                <div style={{ color: "rgba(255,255,255,0.5)", fontSize: 12, marginTop: 8 }}>{customized.agentPhone||"(713) 555-0100"} · {customized.agentEmail||"gerald@estateiq.com"}</div>
              </div>
            </div>
          </div>
        )}

        {/* PUBLISHED */}
        {step === "published" && (
          <div style={{ maxWidth: 560, margin: "0 auto" }}>
            <div style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 14, padding: "36px", textAlign: "center", boxShadow: "0 4px 16px rgba(0,0,0,0.06)", marginBottom: 20 }}>
              <div style={{ fontSize: 52, marginBottom: 16 }}>🚀</div>
              <div style={{ color: "#0f172a", fontSize: 22, fontWeight: 800, marginBottom: 8 }}>Your Page is Live!</div>
              <div style={{ color: "#64748b", fontSize: 14, marginBottom: 20 }}>Your landing page has been published and is ready to share with clients.</div>
              <div style={{ background: "#f8fafc", borderRadius: 8, padding: "12px 16px", marginBottom: 20, fontFamily: "monospace", fontSize: 13, color: "#1d4ed8" }}>
                https://{publishedPages[publishedPages.length-1]?.url}
              </div>
              <div style={{ display: "flex", gap: 10 }}>
                <button onClick={() => { navigator.clipboard.writeText("https://"+publishedPages[publishedPages.length-1]?.url).catch(()=>{}); }} style={{ flex: 1, background: "#1d4ed8", border: "none", color: "white", borderRadius: 8, padding: "12px", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>📋 Copy Link</button>
                <button style={{ flex: 1, background: "#f8fafc", border: "1px solid #e2e8f0", color: "#475569", borderRadius: 8, padding: "12px", fontSize: 13, cursor: "pointer", fontFamily: "inherit" }}>📱 Share</button>
                <button style={{ flex: 1, background: "#f8fafc", border: "1px solid #e2e8f0", color: "#475569", borderRadius: 8, padding: "12px", fontSize: 13, cursor: "pointer", fontFamily: "inherit" }}>✉️ Email</button>
              </div>
            </div>
            <div style={{ background: "#fffbeb", border: "1px solid #fde68a", borderRadius: 10, padding: "16px 20px", marginBottom: 16 }}>
              <div style={{ color: "#92400e", fontSize: 13, fontWeight: 700, marginBottom: 8 }}>💡 How to Drive Traffic to Your Page</div>
              {["Share the link in your email signature","Post it on Facebook, Instagram, and NextDoor","Add it to your Google Business profile","Run Facebook or Google Ads pointing to it","Put the QR code on your direct mail postcards","Add it to your text auto-responder messages"].map((t,i) => (
                <div key={i} style={{ display: "flex", gap: 8, marginBottom: 5 }}>
                  <span style={{ color: "#f59e0b", fontWeight: 700, flexShrink: 0 }}>•</span>
                  <span style={{ color: "#78350f", fontSize: 12 }}>{t}</span>
                </div>
              ))}
            </div>
            <button onClick={() => { setStep("gallery"); setSelectedTemplate(null); setCustomized({}); }} style={{ width: "100%", background: "#f59e0b", border: "none", color: "white", borderRadius: 8, padding: "13px", fontSize: 14, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>
              + Create Another Landing Page
            </button>
          </div>
        )}
      </div>
    </div>
  );
}


