function NeighborhoodComparison() {
  const [selected, setSelected] = useState([HOUSTON_NEIGHBORHOODS[0], HOUSTON_NEIGHBORHOODS[1]]);
  const metrics = [
    { label: "Median Home Price", key: "medianPrice", format: v => fmt(v), higher: "worse" },
    { label: "School Rating", key: "schools", format: v => v+"/10", higher: "better" },
    { label: "Crime Level", key: "crime", format: v => v, higher: null },
    { label: "Commute to Downtown", key: "commute", format: v => v, higher: null },
    { label: "Best For", key: "bestFor", format: v => v, higher: null },
  ];
  const crimeColor = { "Very Low": "#059669", "Low": "#10b981", "Medium": "#f59e0b", "High": "#ef4444" };

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#f8fafc" }}>
      <TopBar title="🗺 Houston Neighborhood Comparison" sub="Compare neighborhoods side by side for relocating buyers" />
      <div style={{ padding: "12px 24px", background: "white", borderBottom: "1px solid #f1f5f9", display: "flex", gap: 12 }}>
        {[0,1,2].map(i => (
          <select key={i} value={selected[i]?.name||""} onChange={e=>{const n=HOUSTON_NEIGHBORHOODS.find(x=>x.name===e.target.value);setSelected(p=>{const s=[...p];s[i]=n||null;return s;});}} style={{ flex: 1, background: "white", border: "1px solid #e2e8f0", color: "#0f172a", borderRadius: 7, padding: "9px 12px", fontSize: 13, outline: "none", cursor: "pointer", fontFamily: "inherit" }}>
            <option value="">Select neighborhood {i+1}...</option>
            {HOUSTON_NEIGHBORHOODS.map(n=><option key={n.name} value={n.name}>{n.name}</option>)}
          </select>
        ))}
      </div>
      <div style={{ flex: 1, overflow: "auto", padding: 24 }}>
        <div style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 12, overflow: "hidden", boxShadow: "0 1px 4px rgba(0,0,0,0.04)" }}>
          {/* Header */}
          <div style={{ display: "grid", gridTemplateColumns: "200px 1fr 1fr 1fr", borderBottom: "2px solid #f1f5f9" }}>
            <div style={{ background: "#f8fafc", padding: "16px" }} />
            {selected.map((n, i) => n ? (
              <div key={i} style={{ padding: "16px", borderLeft: "1px solid #f1f5f9", background: "#f8fafc" }}>
                <div style={{ color: "#0f172a", fontSize: 15, fontWeight: 800 }}>{n.name}</div>
                <div style={{ color: "#64748b", fontSize: 12 }}>{n.type} · {n.zip}</div>
              </div>
            ) : <div key={i} style={{ padding: "16px", borderLeft: "1px solid #f1f5f9", background: "#f8fafc", color: "#cbd5e1", fontSize: 13 }}>Select neighborhood</div>)}
          </div>
          {/* Metrics */}
          {metrics.map(m => (
            <div key={m.label} style={{ display: "grid", gridTemplateColumns: "200px 1fr 1fr 1fr", borderBottom: "1px solid #f8fafc" }}>
              <div style={{ padding: "14px 16px", background: "#f8fafc", display: "flex", alignItems: "center" }}>
                <span style={{ color: "#475569", fontSize: 12, fontWeight: 600 }}>{m.label}</span>
              </div>
              {selected.map((n, i) => (
                <div key={i} style={{ padding: "14px 16px", borderLeft: "1px solid #f1f5f9", display: "flex", alignItems: "center" }}>
                  {n ? (
                    <span style={{ color: m.key==="crime"?crimeColor[n[m.key]]||"#475569":m.key==="schools"&&n[m.key]>=8?"#059669":m.key==="schools"&&n[m.key]<=6?"#ef4444":"#0f172a", fontSize: 13, fontWeight: m.key==="medianPrice"||m.key==="schools"?700:400 }}>
                      {m.format(n[m.key])}
                    </span>
                  ) : <span style={{ color: "#e2e8f0" }}>—</span>}
                </div>
              ))}
            </div>
          ))}
          {/* Highlights */}
          <div style={{ display: "grid", gridTemplateColumns: "200px 1fr 1fr 1fr", borderBottom: "1px solid #f8fafc" }}>
            <div style={{ padding: "14px 16px", background: "#f8fafc", display: "flex", alignItems: "flex-start" }}><span style={{ color: "#475569", fontSize: 12, fontWeight: 600 }}>Highlights</span></div>
            {selected.map((n, i) => (
              <div key={i} style={{ padding: "14px 16px", borderLeft: "1px solid #f1f5f9" }}>
                {n ? n.highlights.map(h => (
                  <div key={h} style={{ display: "flex", gap: 6, marginBottom: 4 }}>
                    <span style={{ color: "#0ea5e9", fontSize: 11 }}>✓</span>
                    <span style={{ color: "#475569", fontSize: 12 }}>{h}</span>
                  </div>
                )) : <span style={{ color: "#e2e8f0", fontSize: 12 }}>—</span>}
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}

// ─── Cost of Living Calculator ────────────────────────────────────────────────
function CostOfLivingCalc() {
  const [currentCity, setCurrentCity] = useState("New York City, NY");
  const [currentRent, setCurrentRent] = useState(3500);
  const [currentSalary, setCurrentSalary] = useState(120000);

  const cities = {
    "New York City, NY": { rentIndex: 2.8, groceries: 1.3, transport: 1.2, utilities: 1.1, stateTax: 6.85 },
    "Los Angeles, CA": { rentIndex: 2.4, groceries: 1.15, transport: 1.1, utilities: 1.2, stateTax: 9.3 },
    "Chicago, IL": { rentIndex: 1.6, groceries: 1.05, transport: 1.1, utilities: 1.0, stateTax: 4.95 },
    "Dallas, TX": { rentIndex: 1.3, groceries: 0.98, transport: 0.95, utilities: 1.05, stateTax: 0 },
    "Austin, TX": { rentIndex: 1.5, groceries: 1.0, transport: 0.92, utilities: 1.02, stateTax: 0 },
    "San Francisco, CA": { rentIndex: 3.2, groceries: 1.25, transport: 1.15, utilities: 1.3, stateTax: 9.3 },
    "Seattle, WA": { rentIndex: 2.0, groceries: 1.1, transport: 1.05, utilities: 1.15, stateTax: 0 },
    "Denver, CO": { rentIndex: 1.7, groceries: 1.05, transport: 0.98, utilities: 0.95, stateTax: 4.4 },
    "Miami, FL": { rentIndex: 2.0, groceries: 1.08, transport: 1.0, utilities: 1.1, stateTax: 0 },
    "Phoenix, AZ": { rentIndex: 1.4, groceries: 0.97, transport: 0.95, utilities: 1.1, stateTax: 2.5 },
  };
  const houstonData = { rentIndex: 1.0, groceries: 0.95, transport: 0.9, utilities: 0.98, stateTax: 0 };
  const city = cities[currentCity] || cities["New York City, NY"];

  const houstonRent = Math.round(currentRent / city.rentIndex * houstonData.rentIndex);
  const rentSavings = currentRent - houstonRent;
  const taxSavings = Math.round(currentSalary * (city.stateTax / 100));
  const totalMonthlySavings = Math.round(rentSavings + taxSavings/12);
  const totalAnnualSavings = Math.round(rentSavings * 12 + taxSavings);

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#f8fafc" }}>
      <TopBar title="💰 Cost of Living Calculator" sub="Show relocating clients how much they'll save moving to Houston" />
      <div style={{ flex: 1, overflow: "auto", padding: 24 }}>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 24, maxWidth: 860 }}>
          <div style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 12, padding: 24, boxShadow: "0 1px 4px rgba(0,0,0,0.04)" }}>
            <div style={{ color: "#0f172a", fontSize: 14, fontWeight: 700, marginBottom: 18 }}>🏙 Client's Current City</div>
            <div style={{ marginBottom: 16 }}>
              <div style={{ color: "#64748b", fontSize: 11, fontWeight: 600, marginBottom: 6 }}>Current City</div>
              <select value={currentCity} onChange={e=>setCurrentCity(e.target.value)} style={{ width: "100%", background: "#f8fafc", border: "1px solid #e2e8f0", color: "#0f172a", borderRadius: 6, padding: "10px 12px", fontSize: 13, outline: "none", cursor: "pointer", fontFamily: "inherit" }}>
                {Object.keys(cities).map(c=><option key={c}>{c}</option>)}
              </select>
            </div>
            <div style={{ marginBottom: 16 }}>
              <div style={{ color: "#64748b", fontSize: 11, fontWeight: 600, marginBottom: 6 }}>Current Monthly Rent ($)</div>
              <input type="number" value={currentRent} onChange={e=>setCurrentRent(parseInt(e.target.value)||0)} style={{ width: "100%", background: "#f8fafc", border: "1px solid #e2e8f0", color: "#0f172a", borderRadius: 6, padding: "10px 12px", fontSize: 13, outline: "none", fontFamily: "inherit", boxSizing: "border-box" }} />
            </div>
            <div style={{ marginBottom: 16 }}>
              <div style={{ color: "#64748b", fontSize: 11, fontWeight: 600, marginBottom: 6 }}>Annual Salary ($)</div>
              <input type="number" value={currentSalary} onChange={e=>setCurrentSalary(parseInt(e.target.value)||0)} style={{ width: "100%", background: "#f8fafc", border: "1px solid #e2e8f0", color: "#0f172a", borderRadius: 6, padding: "10px 12px", fontSize: 13, outline: "none", fontFamily: "inherit", boxSizing: "border-box" }} />
            </div>
            <div style={{ background: "#f8fafc", borderRadius: 8, padding: "14px 16px" }}>
              <div style={{ color: "#94a3b8", fontSize: 11, fontWeight: 700, textTransform: "uppercase", marginBottom: 8 }}>Current City Facts</div>
              {[["State Income Tax", city.stateTax+"%"],["Rent vs Houston", city.rentIndex+"x more expensive"],["Groceries", city.groceries+"x vs national avg"]].map(([k,v])=>(
                <div key={k} style={{ display: "flex", justifyContent: "space-between", padding: "6px 0", borderBottom: "1px solid #e2e8f0" }}>
                  <span style={{ color: "#475569", fontSize: 12 }}>{k}</span>
                  <span style={{ color: "#0f172a", fontWeight: 600, fontSize: 12 }}>{v}</span>
                </div>
              ))}
            </div>
          </div>

          <div style={{ display: "flex", flexDirection: "column", gap: 14 }}>
            <div style={{ background: "linear-gradient(135deg, #0ea5e9, #0284c7)", borderRadius: 12, padding: 24, color: "white" }}>
              <div style={{ fontSize: 12, textTransform: "uppercase", letterSpacing: "0.1em", opacity: 0.8, marginBottom: 8 }}>Annual Savings Moving to Houston</div>
              <div style={{ fontSize: 44, fontWeight: 800, marginBottom: 4 }}>${totalAnnualSavings.toLocaleString()}</div>
              <div style={{ opacity: 0.85, fontSize: 14 }}>${totalMonthlySavings.toLocaleString()}/month in your pocket</div>
            </div>
            <div style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 12, padding: 20, boxShadow: "0 1px 4px rgba(0,0,0,0.04)" }}>
              <div style={{ color: "#0f172a", fontSize: 14, fontWeight: 700, marginBottom: 14 }}>Houston vs {currentCity.split(",")[0]}</div>
              {[
                ["Monthly Rent (Houston)", fmt(houstonRent), "#0ea5e9"],
                ["Monthly Rent ("+currentCity.split(",")[0]+")", fmt(currentRent), "#ef4444"],
                ["Monthly Rent Savings", fmt(rentSavings), "#059669"],
                ["Annual Tax Savings (No TX income tax)", fmt(taxSavings), "#059669"],
                ["Total Annual Savings", fmt(totalAnnualSavings), "#059669"],
              ].map(([k,v,c]) => (
                <div key={k} style={{ display: "flex", justifyContent: "space-between", padding: "9px 0", borderBottom: "1px solid #f8fafc" }}>
                  <span style={{ color: "#475569", fontSize: 13 }}>{k}</span>
                  <span style={{ color: c, fontWeight: 700, fontSize: 13 }}>{v}</span>
                </div>
              ))}
            </div>
            <div style={{ background: "#f0fdf4", border: "1px solid #bbf7d0", borderRadius: 10, padding: 16 }}>
              <div style={{ color: "#059669", fontSize: 12, fontWeight: 700, marginBottom: 8 }}>🏠 Houston Advantages</div>
              {["No Texas state income tax — save thousands/year","Median home prices 40-60% lower than coastal cities","No hurricane insurance issues in most suburbs","Diverse job market — Energy, NASA, Medical Center, Port","Top-ranked suburban school districts","World-class restaurants and cultural diversity"].map((a,i)=>(
                <div key={i} style={{ display: "flex", gap: 8, marginBottom: 5 }}>
                  <span style={{ color: "#059669", fontWeight: 700, flexShrink: 0 }}>✓</span>
                  <span style={{ color: "#065f46", fontSize: 12 }}>{a}</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

// ─── Relocation Guide Builder ─────────────────────────────────────────────────
function RelocationGuide() {
  const [client, setClient] = useState({ name: "", fromCity: "", targetArea: "77598", moveDate: "", family: "Couple with children", budget: "", employer: "" });
  const [generated, setGenerated] = useState(false);
  const mkt = MARKET_DATA[client.targetArea] || MARKET_DATA["77598"];
  const nb = { "77598": { schools: "Clear Creek ISD (Top 10 in TX)", hospitals: "HCA Houston Healthcare Clear Lake, UTMB", shopping: "Bay Brook Mall, Kemah Boardwalk", parks: "Clear Lake Park, Armand Bayou", employers: "NASA JSC, Bay Area Medical Center, ExxonMobil" }, "77584": { schools: "Pearland ISD (Highly Rated)", hospitals: "HCA Houston Healthcare Pearland, Pearland Medical Center", shopping: "Pearland Town Center", parks: "Shadow Creek Ranch Park, Centennial Park", employers: "Medical Center (25 min), Dow Chemical, Port of Houston" } };
  const info = nb[client.targetArea] || nb["77598"];
  const inp = { width: "100%", background: "#f8fafc", border: "1px solid #e2e8f0", color: "#0f172a", borderRadius: 6, padding: "9px 12px", fontSize: 13, outline: "none", fontFamily: "inherit", boxSizing: "border-box" };
  const lbl = { color: "#64748b", fontSize: 11, fontWeight: 600, display: "block", marginBottom: 5 };

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#f8fafc" }}>
      <TopBar title="📋 Relocation Guide Builder" sub="Create a custom Houston relocation packet for incoming clients" action={generated&&<button onClick={()=>setGenerated(false)} style={{ background: "white", border: "1px solid #e2e8f0", color: "#475569", borderRadius: 7, padding: "9px 18px", fontSize: 13, cursor: "pointer", fontFamily: "inherit" }}>← Edit</button>} />
      {!generated ? (
        <div style={{ flex: 1, overflow: "auto", padding: 24 }}>
          <div style={{ maxWidth: 600 }}>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14, marginBottom: 14 }}>
              <div style={{ gridColumn: "1/-1" }}><label style={lbl}>Client Name</label><input value={client.name} onChange={e=>setClient(c=>({...c,name:e.target.value}))} placeholder="e.g. The Johnson Family" style={inp} /></div>
              <div><label style={lbl}>Relocating From</label><input value={client.fromCity} onChange={e=>setClient(c=>({...c,fromCity:e.target.value}))} placeholder="e.g. Chicago, IL" style={inp} /></div>
              <div><label style={lbl}>Target Area / ZIP</label><select value={client.targetArea} onChange={e=>setClient(c=>({...c,targetArea:e.target.value}))} style={{...inp,cursor:"pointer"}}>{Object.entries(MARKET_DATA).map(([z,d])=><option key={z} value={z}>{z} — {d.area}</option>)}</select></div>
              <div><label style={lbl}>Target Move Date</label><input type="date" value={client.moveDate} onChange={e=>setClient(c=>({...c,moveDate:e.target.value}))} style={inp} /></div>
              <div><label style={lbl}>Family Situation</label><select value={client.family} onChange={e=>setClient(c=>({...c,family:e.target.value}))} style={{...inp,cursor:"pointer"}}><option>Couple with children</option><option>Single professional</option><option>Couple no children</option><option>Retirees</option><option>Single with children</option></select></div>
              <div><label style={lbl}>Budget ($)</label><input value={client.budget} onChange={e=>setClient(c=>({...c,budget:e.target.value}))} placeholder="450000" style={inp} /></div>
              <div style={{ gridColumn: "1/-1" }}><label style={lbl}>New Employer / Reason for Move</label><input value={client.employer} onChange={e=>setClient(c=>({...c,employer:e.target.value}))} placeholder="e.g. NASA JSC, Medical Center, ExxonMobil..." style={inp} /></div>
            </div>
            <button onClick={()=>setGenerated(true)} disabled={!client.name} style={{ background: client.name?"#0ea5e9":"#e2e8f0", border: "none", color: client.name?"white":"#94a3b8", borderRadius: 8, padding: "12px 28px", fontSize: 14, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>Generate Relocation Guide →</button>
          </div>
        </div>
      ) : (
        <div style={{ flex: 1, overflow: "auto", padding: 24 }}>
          <div style={{ maxWidth: 720, margin: "0 auto" }}>
            <div style={{ display: "flex", gap: 10, marginBottom: 20 }}>
              <button style={{ background: "#0ea5e9", border: "none", color: "white", borderRadius: 7, padding: "9px 18px", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>📧 Email to Client</button>
              <button style={{ background: "white", border: "1px solid #e2e8f0", color: "#475569", borderRadius: 7, padding: "9px 18px", fontSize: 13, cursor: "pointer", fontFamily: "inherit" }}>🖨 Print PDF</button>
            </div>
            <div style={{ background: "linear-gradient(135deg, #0ea5e9, #0284c7)", borderRadius: 12, padding: "32px 36px", marginBottom: 16, color: "white" }}>
              <div style={{ fontSize: 11, letterSpacing: "0.15em", textTransform: "uppercase", opacity: 0.6, marginBottom: 10 }}>Personal Relocation Guide</div>
              <div style={{ fontSize: 24, fontWeight: 800, marginBottom: 4 }}>Welcome to Houston, {client.name}! 🏡</div>
              <div style={{ opacity: 0.8, fontSize: 14 }}>Relocating from {client.fromCity||"your city"} to {mkt.area} · Prepared by Gerald</div>
            </div>
            {[
              { title: "📍 Your Target Area", content: [["Area", mkt.area+" ("+client.targetArea+")"],["Median Home Price", fmt(mkt.medianPrice)],["Average Days on Market", mkt.avgDOM+" days"],["School District", info.schools],["Best For", client.family]] },
              { title: "🏫 Schools & Education", content: [["School District", info.schools],["District Rating", "Highly Rated by GreatSchools"],["Notes", "Multiple elementary, middle, and high school options within 5 miles"]] },
              { title: "🏥 Healthcare", content: [["Major Hospitals", info.hospitals],["Distance", "Within 10-15 minutes"],["Specialty Care", "Texas Medical Center (30 min) — World's largest medical complex"]] },
              { title: "🛒 Shopping & Entertainment", content: [["Shopping", info.shopping],["Parks & Recreation", info.parks],["Dining", "Hundreds of restaurants within 15 minutes — world-class diversity"]] },
              { title: "💼 Employment", content: [["Your Employer", client.employer||"TBD"],["Major Employers Nearby", info.employers],["Commute", mkt.area+" — excellent highway access"]] },
            ].map(section => (
              <div key={section.title} style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 12, padding: 22, marginBottom: 14, boxShadow: "0 1px 4px rgba(0,0,0,0.04)" }}>
                <div style={{ color: "#0f172a", fontSize: 15, fontWeight: 700, marginBottom: 14 }}>{section.title}</div>
                {section.content.map(([k,v]) => (
                  <div key={k} style={{ display: "flex", padding: "8px 0", borderBottom: "1px solid #f8fafc" }}>
                    <span style={{ color: "#94a3b8", fontSize: 12, fontWeight: 600, width: 160, flexShrink: 0 }}>{k}</span>
                    <span style={{ color: "#0f172a", fontSize: 13 }}>{v}</span>
                  </div>
                ))}
              </div>
            ))}
            <div style={{ background: "linear-gradient(135deg, #f0f9ff, #e0f2fe)", border: "1px solid #bae6fd", borderRadius: 12, padding: 22 }}>
              <div style={{ color: "#0369a1", fontSize: 15, fontWeight: 700, marginBottom: 14 }}>🤝 Gerald's Relocation Promise</div>
              {["I will find you the perfect home in {area} before your move date".replace("{area}", mkt.area),"Virtual tours available — see homes from {city} before you arrive".replace("{city}",client.fromCity||"your city"),"I'll connect you with trusted lenders, inspectors, and movers","Bilingual service available — Se Habla Español","I'll be your Houston expert long after closing day"].map((p,i)=>(
                <div key={i} style={{ display: "flex", gap: 12, marginBottom: 10 }}>
                  <div style={{ width: 24, height: 24, borderRadius: "50%", background: "#0ea5e9", display: "flex", alignItems: "center", justifyContent: "center", color: "white", fontSize: 11, fontWeight: 800, flexShrink: 0 }}>✓</div>
                  <span style={{ color: "#0c4a6e", fontSize: 13, lineHeight: 1.5 }}>{p}</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// ─── Relocation Checklist ─────────────────────────────────────────────────────
function RelocationChecklist() {
  const [clientName, setClientName] = useState("The Johnson Family");
  const [fromCity, setFromCity] = useState("Chicago, IL");
  const [generated, setGenerated] = useState(false);
  const [checked, setChecked] = useState({});

  const sections = [
    { title: "3-6 Months Before Move", items: ["Research Houston neighborhoods with Gerald","Schedule virtual home tours","Get pre-approved for a mortgage","Research Houston school districts","Connect with HR about relocation assistance","Visit Houston for a scouting trip (Gerald will show you around!)","Start decluttering and downsizing","Research moving companies"] },
    { title: "1-3 Months Before Move", items: ["Make an offer on your new Houston home","Give notice to current landlord/sell current home","Book moving company or truck rental","Notify employer, bank, and insurance of address change","Transfer medical and dental records","Register children for Houston schools","Forward mail (USPS change of address)","Contact utilities for new Houston home"] },
    { title: "2 Weeks Before Move", items: ["Confirm movers and closing date","Pack non-essential items","Take photos/video of all belongings for insurance","Confirm utilities are set up at new home","Arrange childcare or pet care for moving day","Prepare essentials bag for first night in Houston","Get cash for tips for movers","Return cable equipment, keys, etc. to current home"] },
    { title: "Moving Day", items: ["Walk through current home one final time","Take meter readings at old home","Photograph condition of old home","Supervise movers loading truck","Confirm Gerald has your closing documents ready","Take keys and garage openers at closing","Photograph condition of new home before move-in","Call Gerald to celebrate! 🎉"] },
    { title: "First Week in Houston", items: ["Update Texas driver's license (within 90 days)","Register vehicles in Texas","Update voter registration","Find a local grocery store, pharmacy, and urgent care","Download the MetroLift app for public transit","Explore your neighborhood with Gerald's recommendations","Follow Gerald on YouTube for Houston tips!","Join Houston Facebook groups for newcomers"] },
    { title: "First Month in Houston", items: ["Attend community events to meet neighbors","Explore Houston neighborhoods Gerald recommended","Visit the Houston Museum District","Try Gerald's favorite Houston restaurants (ask him!)","Leave Gerald a Google Review 😊","Refer friends to Gerald if they're also relocating!"] },
  ];

  const total = sections.reduce((s,sec)=>s+sec.items.length,0);
  const done = Object.values(checked).filter(Boolean).length;

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#f8fafc" }}>
      <TopBar title="✅ Relocation Checklist" sub="Complete step-by-step moving to Houston guide for your clients" />
      <div style={{ padding: "12px 24px", background: "white", borderBottom: "1px solid #f1f5f9", display: "flex", gap: 10, alignItems: "center" }}>
        <input value={clientName} onChange={e=>setClientName(e.target.value)} placeholder="Client name" style={{ background: "#f8fafc", border: "1px solid #e2e8f0", color: "#0f172a", borderRadius: 6, padding: "8px 12px", fontSize: 13, outline: "none", fontFamily: "inherit", width: 200 }} />
        <input value={fromCity} onChange={e=>setFromCity(e.target.value)} placeholder="Moving from..." style={{ background: "#f8fafc", border: "1px solid #e2e8f0", color: "#0f172a", borderRadius: 6, padding: "8px 12px", fontSize: 13, outline: "none", fontFamily: "inherit", width: 180 }} />
        <button onClick={()=>setGenerated(true)} style={{ background: "#0ea5e9", border: "none", color: "white", borderRadius: 7, padding: "9px 18px", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>Generate Checklist</button>
        {generated && <button style={{ background: "#059669", border: "none", color: "white", borderRadius: 7, padding: "9px 18px", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>📧 Send to Client</button>}
        {generated && <div style={{ color: "#0ea5e9", fontSize: 13, fontWeight: 600, marginLeft: "auto" }}>{done}/{total} complete</div>}
      </div>
      {generated ? (
        <div style={{ flex: 1, overflow: "auto", padding: 20 }}>
          <div style={{ height: 8, background: "#f1f5f9", borderRadius: 4, marginBottom: 20, overflow: "hidden" }}>
            <div style={{ width: (done/total*100)+"%", height: "100%", background: "#0ea5e9", borderRadius: 4, transition: "width 0.3s" }} />
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(360px,1fr))", gap: 16 }}>
            {sections.map(sec => {
              const secDone = sec.items.filter(item=>checked[sec.title+item]).length;
              return (
                <div key={sec.title} style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 12, overflow: "hidden", boxShadow: "0 1px 3px rgba(0,0,0,0.04)" }}>
                  <div style={{ padding: "12px 16px", borderBottom: "1px solid #f1f5f9", display: "flex", justifyContent: "space-between", background: secDone===sec.items.length?"#f0f9ff":"white" }}>
                    <div style={{ color: "#0f172a", fontSize: 13, fontWeight: 700 }}>{sec.title}</div>
                    <span style={{ color: "#94a3b8", fontSize: 11 }}>{secDone}/{sec.items.length}</span>
                  </div>
                  <div style={{ padding: "12px 16px" }}>
                    {sec.items.map(item => (
                      <div key={item} onClick={()=>setChecked(p=>({...p,[sec.title+item]:!p[sec.title+item]}))} style={{ display: "flex", gap: 10, marginBottom: 8, cursor: "pointer", alignItems: "flex-start" }}>
                        <div style={{ width: 18, height: 18, borderRadius: 4, border: `2px solid ${checked[sec.title+item]?"#0ea5e9":"#e2e8f0"}`, background: checked[sec.title+item]?"#0ea5e9":"white", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0, marginTop: 1 }}>
                          {checked[sec.title+item] && <span style={{ color: "white", fontSize: 10, fontWeight: 800 }}>✓</span>}
                        </div>
                        <span style={{ color: checked[sec.title+item]?"#94a3b8":"#475569", fontSize: 12, lineHeight: 1.5, textDecoration: checked[sec.title+item]?"line-through":"none" }}>{item}</span>
                      </div>
                    ))}
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      ) : (
        <div style={{ flex: 1, display: "flex", alignItems: "center", justifyContent: "center" }}><div style={{ textAlign: "center", color: "#94a3b8" }}><div style={{ fontSize: 48, marginBottom: 12 }}>🚚</div><div style={{ fontSize: 15, fontWeight: 700, color: "#475569" }}>Enter client details above and generate their relocation checklist</div></div></div>
      )}
    </div>
  );
}

