// ─── City Comparison Tool ─────────────────────────────────────────────────────
function CityComparison() {
  const [compareCity, setCompareCity] = useState("Chicago, IL");
  const houstonData = { name: "Houston, TX", medianHome: 374692, rent: 1350, stateTax: 0, salesTax: 8.25, avgSalary: 72000, unemployment: 4.1, climate: "Hot & humid", traffic: "Heavy", sports: "Texans, Rockets, Astros, Dynamo", airports: "IAH + Hobby", hospitals: "TMC — World's largest", diversity: "Most diverse US city", noIncomeTax: true };
  const cities = {
    "Chicago, IL": { name: "Chicago, IL", medianHome: 330000, rent: 1950, stateTax: 4.95, salesTax: 10.25, avgSalary: 68000, unemployment: 5.2, climate: "Cold winters, hot summers", traffic: "Very heavy", sports: "Bears, Bulls, Cubs, White Sox, Blackhawks", airports: "O'Hare + Midway", hospitals: "Northwestern, Rush", diversity: "Very diverse", noIncomeTax: false },
    "New York City, NY": { name: "NYC, NY", medianHome: 780000, rent: 3500, stateTax: 6.85, salesTax: 8.875, avgSalary: 85000, unemployment: 4.8, climate: "4 seasons, cold winters", traffic: "Extreme", sports: "Yankees, Mets, Giants, Jets, Knicks, Rangers", airports: "JFK + LGA + EWR", hospitals: "Mount Sinai, NYU Langone", diversity: "Extremely diverse", noIncomeTax: false },
    "Los Angeles, CA": { name: "Los Angeles, CA", medianHome: 850000, rent: 2800, stateTax: 9.3, salesTax: 10.25, avgSalary: 75000, unemployment: 5.5, climate: "Warm year-round", traffic: "Extreme", sports: "Lakers, Clippers, Rams, Chargers, Dodgers, Angels", airports: "LAX", hospitals: "Cedars-Sinai, UCLA", diversity: "Very diverse", noIncomeTax: false },
    "Dallas, TX": { name: "Dallas, TX", medianHome: 340000, rent: 1650, stateTax: 0, salesTax: 8.25, avgSalary: 68000, unemployment: 3.8, climate: "Hot summers, mild winters", traffic: "Heavy", sports: "Cowboys, Mavericks, Rangers, Stars", airports: "DFW + Love Field", hospitals: "UT Southwestern", diversity: "Very diverse", noIncomeTax: true },
    "Austin, TX": { name: "Austin, TX", medianHome: 525000, rent: 1900, stateTax: 0, salesTax: 8.25, avgSalary: 78000, unemployment: 3.2, climate: "Hot, mild winters", traffic: "Heavy", sports: "Austin FC", airports: "AUS", hospitals: "St. David's, Dell Seton", diversity: "Growing diversity", noIncomeTax: true },
    "Seattle, WA": { name: "Seattle, WA", medianHome: 750000, rent: 2200, stateTax: 0, salesTax: 10.25, avgSalary: 88000, unemployment: 3.9, climate: "Rainy, mild", traffic: "Very heavy", sports: "Seahawks, Mariners, Sounders, Kraken", airports: "SEA-TAC", hospitals: "UW Medical", diversity: "Growing", noIncomeTax: true },
    "Miami, FL": { name: "Miami, FL", medianHome: 620000, rent: 2400, stateTax: 0, salesTax: 7.0, avgSalary: 62000, unemployment: 4.2, climate: "Hot & humid, hurricanes", traffic: "Heavy", sports: "Heat, Dolphins, Marlins, Inter Miami", airports: "MIA + FLL", hospitals: "Jackson Health", diversity: "Extremely diverse", noIncomeTax: true },
  };
  const city = cities[compareCity] || cities["Chicago, IL"];
  const metrics = [
    { label: "Median Home Price", h: fmt(houstonData.medianHome), c: fmt(city.medianHome), winner: houstonData.medianHome < city.medianHome ? "houston" : "city" },
    { label: "Average Monthly Rent", h: fmt(houstonData.rent)+"/mo", c: fmt(city.rent)+"/mo", winner: houstonData.rent < city.rent ? "houston" : "city" },
    { label: "State Income Tax", h: "0% ✓", c: city.stateTax+"%", winner: houstonData.stateTax < city.stateTax ? "houston" : city.stateTax === 0 ? "tie" : "houston" },
    { label: "Sales Tax", h: houstonData.salesTax+"%", c: city.salesTax+"%", winner: houstonData.salesTax <= city.salesTax ? "houston" : "city" },
    { label: "Average Salary", h: fmt(houstonData.avgSalary), c: fmt(city.avgSalary), winner: houstonData.avgSalary >= city.avgSalary ? "houston" : "city" },
    { label: "Climate", h: houstonData.climate, c: city.climate, winner: "none" },
    { label: "Traffic", h: houstonData.traffic, c: city.traffic, winner: "none" },
    { label: "Sports Teams", h: houstonData.sports, c: city.sports, winner: "none" },
    { label: "Major Airport(s)", h: houstonData.airports, c: city.airports, winner: "none" },
    { label: "World-Class Hospitals", h: houstonData.hospitals, c: city.hospitals, winner: "none" },
    { label: "Diversity", h: houstonData.diversity, c: city.diversity, winner: "none" },
  ];

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#f8fafc" }}>
      <TopBar title="🏙 Houston vs Other Cities" sub="Show relocating clients how Houston stacks up against their current city" />
      <div style={{ padding: "12px 24px", background: "white", borderBottom: "1px solid #f1f5f9", display: "flex", gap: 10, alignItems: "center" }}>
        <div style={{ color: "#475569", fontSize: 13, fontWeight: 600 }}>Compare Houston vs:</div>
        <select value={compareCity} onChange={e=>setCompareCity(e.target.value)} style={{ background: "#f8fafc", border: "1px solid #e2e8f0", color: "#0f172a", borderRadius: 6, padding: "9px 14px", fontSize: 13, outline: "none", cursor: "pointer", fontFamily: "inherit" }}>
          {Object.keys(cities).map(c=><option key={c}>{c}</option>)}
        </select>
        <div style={{ marginLeft: "auto", background: "#eff6ff", border: "1px solid #bfdbfe", color: "#1d4ed8", fontSize: 12, fontWeight: 700, padding: "6px 14px", borderRadius: 7 }}>
          🏆 Houston wins {metrics.filter(m=>m.winner==="houston").length}/{metrics.filter(m=>m.winner!=="none").length} comparable categories
        </div>
      </div>
      <div style={{ flex: 1, overflow: "auto", padding: 24 }}>
        <div style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 12, overflow: "hidden", boxShadow: "0 1px 4px rgba(0,0,0,0.04)" }}>
          {/* Column headers */}
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", background: "#f8fafc", borderBottom: "2px solid #f1f5f9" }}>
            <div style={{ padding: "14px 20px", color: "#94a3b8", fontSize: 11, fontWeight: 700, textTransform: "uppercase" }}>Category</div>
            <div style={{ padding: "14px 20px", borderLeft: "1px solid #f1f5f9" }}>
              <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
                <div style={{ width: 28, height: 28, background: "#0ea5e9", borderRadius: 6, display: "flex", alignItems: "center", justifyContent: "center", color: "white", fontSize: 12, fontWeight: 800 }}>H</div>
                <span style={{ color: "#0f172a", fontSize: 14, fontWeight: 800 }}>Houston, TX</span>
              </div>
            </div>
            <div style={{ padding: "14px 20px", borderLeft: "1px solid #f1f5f9" }}>
              <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
                <div style={{ width: 28, height: 28, background: "#64748b", borderRadius: 6, display: "flex", alignItems: "center", justifyContent: "center", color: "white", fontSize: 12, fontWeight: 800 }}>{compareCity[0]}</div>
                <span style={{ color: "#0f172a", fontSize: 14, fontWeight: 700 }}>{city.name}</span>
              </div>
            </div>
          </div>
          {metrics.map((m, i) => (
            <div key={m.label} style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", borderBottom: "1px solid #f8fafc", background: i%2===0?"white":"#fafafa" }}>
              <div style={{ padding: "13px 20px", display: "flex", alignItems: "center" }}>
                <span style={{ color: "#475569", fontSize: 12, fontWeight: 600 }}>{m.label}</span>
              </div>
              <div style={{ padding: "13px 20px", borderLeft: "1px solid #f1f5f9", display: "flex", alignItems: "center", gap: 8 }}>
                {m.winner === "houston" && <span style={{ fontSize: 14 }}>🏆</span>}
                <span style={{ color: m.winner==="houston"?"#059669":"#0f172a", fontWeight: m.winner==="houston"?700:400, fontSize: 13 }}>{m.h}</span>
              </div>
              <div style={{ padding: "13px 20px", borderLeft: "1px solid #f1f5f9", display: "flex", alignItems: "center" }}>
                <span style={{ color: m.winner==="city"?"#059669":"#64748b", fontWeight: m.winner==="city"?700:400, fontSize: 13 }}>{m.c}</span>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

