function SchoolDistrictGuide() {
  const districts = [
    { name: "Clear Creek ISD", area: "Webster, Clear Lake, Friendswood, League City", rating: 9, schools: 44, enrollment: 42000, highlights: ["Top 10% in Texas", "NASA partnership programs", "Strong STEM curriculum", "Multiple National Blue Ribbon schools"], zip: "77598", website: "ccisd.net" },
    { name: "Pearland ISD", area: "Pearland, Shadow Creek", rating: 8, schools: 26, enrollment: 25000, highlights: ["Consistently high TEA ratings", "Strong athletics", "IB program available", "New facilities"], zip: "77584", website: "pearlandisd.org" },
    { name: "Friendswood ISD", area: "Friendswood", rating: 9, schools: 7, enrollment: 6800, highlights: ["One of Texas' top districts", "Small class sizes", "High graduation rates", "Strong community involvement"], zip: "77546", website: "fisdk12.net" },
    { name: "Katy ISD", area: "Katy, Cinco Ranch", rating: 8, schools: 75, enrollment: 85000, highlights: ["One of Texas' largest and best", "Multiple National Merit Scholars", "Strong extracurriculars", "Award-winning fine arts"], zip: "77494", website: "katyisd.org" },
    { name: "Fort Bend ISD", area: "Sugar Land, Missouri City", rating: 8, schools: 83, enrollment: 80000, highlights: ["Most diverse district in TX", "Multiple IB schools", "Award-winning programs", "Very strong academics"], zip: "77478", website: "fortbendisd.com" },
    { name: "Conroe ISD / The Woodlands", area: "The Woodlands, Spring", rating: 8, schools: 73, enrollment: 68000, highlights: ["Top-performing schools", "The Woodlands HS — nationally ranked", "Strong dual enrollment", "Multiple Blue Ribbon schools"], zip: "77380", website: "conroeisd.net" },
    { name: "Galveston ISD", area: "Galveston Island", rating: 6, schools: 21, enrollment: 8500, highlights: ["UTMB partnership", "Beach community culture", "Growing improvements", "Strong vocational programs"], zip: "77550", website: "gisd.org" },
    { name: "Alvin ISD", area: "Pearland South, Alvin, Manvel", rating: 7, schools: 35, enrollment: 28000, highlights: ["Fast growing", "New construction schools", "Strong athletics", "Affordable area"], zip: "77511", website: "alvinisd.net" },
  ];
  const ratingColor = r => r>=9?"#059669":r>=7?"#f59e0b":"#ef4444";

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#f8fafc" }}>
      <TopBar title="🎓 School District Guide" sub="Comprehensive guide to Houston area school districts for relocating families" />
      <div style={{ flex: 1, overflow: "auto", padding: 24 }}>
        <div style={{ background: "#f0f9ff", border: "1px solid #bae6fd", borderRadius: 10, padding: "14px 18px", marginBottom: 20 }}>
          <div style={{ color: "#0369a1", fontSize: 13, fontWeight: 700, marginBottom: 4 }}>🏫 Schools are the #1 factor for relocating families</div>
          <div style={{ color: "#0c4a6e", fontSize: 13, lineHeight: 1.6 }}>When families relocate to Houston, school district quality is often the deciding factor on WHERE they buy. The Clear Creek, Friendswood, Katy, and Fort Bend ISDs are consistently ranked among the best in Texas. Use this guide in your buyer consultations and YouTube videos to demonstrate your local expertise.</div>
        </div>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(340px,1fr))", gap: 16 }}>
          {districts.map(d => (
            <div key={d.name} style={{ background: "white", border: `2px solid ${ratingColor(d.rating)}22`, borderRadius: 12, padding: "18px 20px", boxShadow: "0 1px 4px rgba(0,0,0,0.04)" }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 10 }}>
                <div>
                  <div style={{ color: "#0f172a", fontSize: 14, fontWeight: 800, marginBottom: 3 }}>{d.name}</div>
                  <div style={{ color: "#64748b", fontSize: 12 }}>{d.area}</div>
                </div>
                <div style={{ width: 44, height: 44, borderRadius: "50%", background: ratingColor(d.rating), color: "white", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 16, fontWeight: 800, flexShrink: 0 }}>{d.rating}</div>
              </div>
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8, marginBottom: 12 }}>
                {[["Schools", d.schools],["Students", d.enrollment.toLocaleString()],["ZIP Focus", d.zip],["Website", d.website]].map(([k,v])=>(
                  <div key={k} style={{ background: "#f8fafc", borderRadius: 6, padding: "8px 10px" }}>
                    <div style={{ color: "#94a3b8", fontSize: 9, fontWeight: 700, textTransform: "uppercase", marginBottom: 3 }}>{k}</div>
                    <div style={{ color: "#0f172a", fontSize: 12, fontWeight: 600 }}>{v}</div>
                  </div>
                ))}
              </div>
              <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
                {d.highlights.map(h=>(
                  <div key={h} style={{ display: "flex", gap: 8, alignItems: "center" }}>
                    <div style={{ width: 6, height: 6, borderRadius: "50%", background: ratingColor(d.rating), flexShrink: 0 }} />
                    <span style={{ color: "#475569", fontSize: 12 }}>{h}</span>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

