// ─── TRANSACTION & CLOSING TOOLS ─────────────────────────────────────────────

function ClosingChecklist() {
  const [deal, setDeal] = useState("1103 Cedar Ridge Ct — Kowalski Family");
  const [generated, setGenerated] = useState(false);
  const [checked, setChecked] = useState({});
  const sections = [
    { title: "📋 Contract to Accepted (Days 1-3)", items: ["Fully executed contract signed by all parties","Earnest money delivered to title company","Option period / inspection period noted","All addenda signed and attached","Lender notified — loan process begins","Order title commitment"] },
    { title: "🔍 Inspection Period (Days 3-10)", items: ["Schedule home inspection","Schedule termite inspection if required","Schedule any specialized inspections (pool, roof, AC)","Review inspection report with client","Negotiate repairs or seller concessions","Sign inspection amendment / repair addendum"] },
    { title: "💰 Financing & Appraisal (Days 10-25)", items: ["Buyer submits loan application if not done","Appraisal ordered by lender","Appraisal received — confirm at or above purchase price","Loan approval / commitment letter received","Homeowner insurance quote obtained","HOA documents reviewed if applicable"] },
    { title: "📄 Title & Pre-Closing (Days 20-30)", items: ["Title commitment reviewed — no issues","Survey ordered and received","Final walkthrough scheduled (24-48 hrs before closing)","Closing disclosure reviewed by buyer","Wire transfer instructions confirmed (call to verify)","Buyer cashier's check or wire amount confirmed"] },
    { title: "🔑 Closing Day", items: ["Final walkthrough completed","All parties arrive at title company on time","All documents signed","Funds wired / cashier's check delivered","Recording confirmed with title company","Keys, garage openers, mailbox keys delivered","Photos with clients 🎉","Send closing gift"] },
    { title: "🎊 Post-Closing", items: ["Send thank-you card to client","Request Google review","Add to closed clients database","Set home anniversary reminder (1 year)","Log referral source for ROI tracking","Send closing gift if not already done"] },
  ];
  const total = sections.reduce((s,sec)=>s+sec.items.length,0);
  const done = Object.values(checked).filter(Boolean).length;

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#f8fafc" }}>
      <TopBar title="✅ Digital Closing Checklist" sub="Step-by-step from contract to keys — never miss a deadline" />
      <div style={{ padding: "10px 24px", background: "white", borderBottom: "1px solid #f1f5f9", display: "flex", gap: 10, alignItems: "center" }}>
        <input value={deal} onChange={e=>setDeal(e.target.value)} style={{ flex: 1, background: "#f8fafc", border: "1px solid #e2e8f0", color: "#0f172a", borderRadius: 6, padding: "8px 12px", fontSize: 13, outline: "none", fontFamily: "inherit" }} />
        <button onClick={()=>setGenerated(true)} style={{ background: "#f97316", border: "none", color: "white", borderRadius: 7, padding: "9px 18px", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>Generate Checklist</button>
        {generated && <span style={{ color: "#f97316", fontSize: 13, fontWeight: 700 }}>{done}/{total} complete</span>}
      </div>
      {generated ? (
        <div style={{ flex: 1, overflow: "auto", padding: 20 }}>
          <div style={{ height: 8, background: "#f1f5f9", borderRadius: 4, marginBottom: 20, overflow: "hidden" }}>
            <div style={{ width: (done/total*100)+"%", height: "100%", background: "#f97316", borderRadius: 4, transition: "width 0.3s" }} />
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(340px,1fr))", gap: 14 }}>
            {sections.map(sec => (
              <div key={sec.title} style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 12, overflow: "hidden", boxShadow: "0 1px 3px rgba(0,0,0,0.04)" }}>
                <div style={{ padding: "12px 16px", borderBottom: "1px solid #f1f5f9", background: sec.items.every(item=>checked[sec.title+item])?"#fff7ed":"white" }}>
                  <div style={{ color: "#0f172a", fontSize: 13, fontWeight: 700 }}>{sec.title}</div>
                </div>
                <div style={{ padding: "12px 16px" }}>
                  {sec.items.map(item => (
                    <div key={item} onClick={()=>setChecked(p=>({...p,[sec.title+item]:!p[sec.title+item]}))} style={{ display: "flex", gap: 10, marginBottom: 8, cursor: "pointer", alignItems: "flex-start" }}>
                      <div style={{ width: 18, height: 18, borderRadius: 4, border: `2px solid ${checked[sec.title+item]?"#f97316":"#e2e8f0"}`, background: checked[sec.title+item]?"#f97316":"white", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0, marginTop: 1 }}>
                        {checked[sec.title+item] && <span style={{ color: "white", fontSize: 10, fontWeight: 800 }}>✓</span>}
                      </div>
                      <span style={{ color: checked[sec.title+item]?"#94a3b8":"#475569", fontSize: 12, lineHeight: 1.5, textDecoration: checked[sec.title+item]?"line-through":"none" }}>{item}</span>
                    </div>
                  ))}
                </div>
              </div>
            ))}
          </div>
        </div>
      ) : (
        <div style={{ flex: 1, display: "flex", alignItems: "center", justifyContent: "center" }}><div style={{ textAlign: "center", color: "#94a3b8" }}><div style={{ fontSize: 48, marginBottom: 12 }}>✅</div><div style={{ fontSize: 15, fontWeight: 700, color: "#475569" }}>Enter deal name and generate your closing checklist</div></div></div>
      )}
    </div>
  );
}

