function RevenueForecast() {
  const months = ["Jun","Jul","Aug","Sep","Oct","Nov","Dec"];
  const projected = [29700, 14850, 44550, 29700, 14850, 29700, 52500];
  const conservative = [14850, 14850, 29700, 14850, 14850, 14850, 29700];
  const total = projected.reduce((s,v)=>s+v,0);
  const ytd = 118800;

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#f8fafc" }}>
      <TopBar title="📈 Predictive Revenue Forecast" sub="Project your income 6-12 months out based on pipeline data" />
      <div style={{ flex: 1, overflow: "auto", padding: 24 }}>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(3,1fr)", gap: 14, marginBottom: 24 }}>
          {[["YTD Revenue", "$"+ytd.toLocaleString(), "#059669"],["Projected Rest of 2026", "$"+total.toLocaleString(), "#3b82f6"],["Full Year Forecast", "$"+(ytd+total).toLocaleString(), "#f59e0b"]].map(([l,v,c])=>(
            <div key={l} style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 12, padding: "18px 20px", boxShadow: "0 1px 4px rgba(0,0,0,0.04)" }}>
              <div style={{ color: "#94a3b8", fontSize: 11, fontWeight: 700, textTransform: "uppercase", marginBottom: 8 }}>{l}</div>
              <div style={{ color: c, fontSize: 28, fontWeight: 800 }}>{v}</div>
            </div>
          ))}
        </div>
        <div style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 12, padding: 24, marginBottom: 20 }}>
          <div style={{ color: "#0f172a", fontSize: 14, fontWeight: 700, marginBottom: 20 }}>Monthly Revenue Forecast</div>
          <div style={{ display: "flex", gap: 8, alignItems: "flex-end", height: 120 }}>
            {months.map((m,i) => (
              <div key={m} style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", gap: 4 }}>
                <div style={{ color: "#64748b", fontSize: 9 }}>${(projected[i]/1000).toFixed(0)}K</div>
                <div style={{ width: "100%", position: "relative" }}>
                  <div style={{ width: "100%", background: "#3b82f620", borderRadius: "3px 3px 0 0", height: (projected[i]/Math.max(...projected)*90)+"px" }} />
                  <div style={{ position: "absolute", bottom: 0, width: "100%", background: "#059669", borderRadius: "3px 3px 0 0", height: (conservative[i]/Math.max(...projected)*90)+"px" }} />
                </div>
                <div style={{ color: "#94a3b8", fontSize: 11 }}>{m}</div>
              </div>
            ))}
          </div>
          <div style={{ display: "flex", gap: 16, marginTop: 12 }}>
            <div style={{ display: "flex", gap: 6, alignItems: "center" }}><div style={{ width: 12, height: 12, borderRadius: 2, background: "#3b82f620", border: "1px solid #3b82f6" }} /><span style={{ color: "#64748b", fontSize: 11 }}>Projected</span></div>
            <div style={{ display: "flex", gap: 6, alignItems: "center" }}><div style={{ width: 12, height: 12, borderRadius: 2, background: "#059669" }} /><span style={{ color: "#64748b", fontSize: 11 }}>Conservative</span></div>
          </div>
        </div>
      </div>
    </div>
  );
}

