function SpanishYTScripts() {
  const [topic, setTopic] = useState("");
  const [script, setScript] = useState("");
  const [loading, setLoading] = useState(false);

  const quickTopics = [
    "¿Debo Comprar o Seguir Rentando en Houston 2026?",
    "Los 5 Mejores Vecindarios de Houston para Familias",
    "¿Cuánto Dinero Necesito para Comprar una Casa en Houston?",
    "Cómo Comprar una Casa siendo Inmigrante en Texas",
    "¿Vale la Pena Mudarse a Houston desde México?",
    "Probate en Texas: ¿Qué Hacer con la Casa Heredada?",
  ];

  const generate = async () => {
    setLoading(true);
    setScript("");
    try {
      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-20250514",
          max_tokens: 1500,
          system: "Eres escritor de guiones de YouTube para Gerald, un Corredor de Bienes Raíces Licenciado en Houston, TX. Gerald se especializa en ayudar a familias hispanohablantes a comprar, vender y heredar propiedades. Escribe guiones completamente en español, conversacionales y naturales, con gancho fuerte al inicio, contenido de valor, y llamada a la acción al final. Formato: GANCHO, INTRODUCCIÓN, CONTENIDO PRINCIPAL (con marcas de tiempo), LLAMADA A LA ACCIÓN, OUTRO.",
          messages: [{ role: "user", content: `Escribe un guión completo de YouTube en español para: "${topic}"` }]
        })
      });
      const data = await res.json();
      setScript(data.content?.[0]?.text || "Error generando guión.");
    } catch { setScript("Error de conexión."); }
    setLoading(false);
  };

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#f8fafc" }}>
      <TopBar title="🇪🇸▶️ Guiones de YouTube en Español" sub="IA genera guiones completos de YouTube en español para el mercado hispano de Houston" />
      <div style={{ flex: 1, display: "flex", overflow: "hidden" }}>
        <div style={{ width: 360, background: "white", borderRight: "1px solid #f1f5f9", overflow: "auto", padding: 24, flexShrink: 0 }}>
          <div style={{ color: "#475569", fontSize: 12, fontWeight: 600, marginBottom: 8 }}>TEMAS POPULARES</div>
          <div style={{ display: "flex", flexDirection: "column", gap: 6, marginBottom: 16 }}>
            {quickTopics.map(t => (
              <button key={t} onClick={()=>setTopic(t)} style={{ background: "#f8fafc", border: "1px solid #f1f5f9", borderRadius: 7, padding: "9px 12px", fontSize: 12, color: "#475569", cursor: "pointer", textAlign: "left", fontFamily: "inherit" }}>{t}</button>
            ))}
          </div>
          <div style={{ color: "#475569", fontSize: 12, fontWeight: 600, marginBottom: 6 }}>TEMA DEL VIDEO</div>
          <input value={topic} onChange={e=>setTopic(e.target.value)} placeholder="ej. Cómo Vender su Casa en Houston..." style={{ width: "100%", background: "#f8fafc", border: "1px solid #e2e8f0", color: "#0f172a", borderRadius: 7, padding: "10px 12px", fontSize: 13, outline: "none", fontFamily: "inherit", boxSizing: "border-box", marginBottom: 14 }} />
          <div style={{ background: "#fff5f5", border: "1px solid #fecaca", borderRadius: 8, padding: "12px 14px", marginBottom: 14 }}>
            <div style={{ color: "#dc2626", fontSize: 12, fontWeight: 700, marginBottom: 4 }}>🏆 Oportunidad ENORME</div>
            <div style={{ color: "#991b1b", fontSize: 12, lineHeight: 1.6 }}>Casi ningún agente de Houston crea contenido de YouTube en español. ¡Esta es su ventaja competitiva! Los videos en español tienen MENOS competencia y capturan un mercado desatendido de 1.7 millones de hispanohablantes.</div>
          </div>
          <button onClick={generate} disabled={loading||!topic} style={{ width: "100%", background: loading||!topic?"#e2e8f0":"#dc2626", border: "none", color: loading||!topic?"#94a3b8":"white", borderRadius: 8, padding: "13px", fontSize: 14, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>
            {loading?"✍️ Escribiendo Guión...":"🤖 Generar Guión en Español"}
          </button>
        </div>
        <div style={{ flex: 1, overflow: "auto", padding: 24 }}>
          {!script && !loading && <div style={{ textAlign: "center", padding: "60px 20px", color: "#94a3b8" }}><div style={{ fontSize: 48, marginBottom: 12 }}>🇪🇸</div><div style={{ fontSize: 15, fontWeight: 700, color: "#475569" }}>Seleccione un tema y genere su guión en español</div></div>}
          {loading && <div style={{ textAlign: "center", padding: "60px 20px" }}><div style={{ fontSize: 48, marginBottom: 12 }}>✍️</div><div style={{ color: "#dc2626", fontSize: 15, fontWeight: 700 }}>Escribiendo su guión en español...</div></div>}
          {script && (
            <div style={{ maxWidth: 700 }}>
              <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 16 }}>
                <div style={{ color: "#0f172a", fontSize: 15, fontWeight: 700 }}>🇪🇸 {topic}</div>
                <button onClick={() => navigator.clipboard.writeText(script).catch(()=>{})} style={{ background: "#dc2626", border: "none", color: "white", borderRadius: 7, padding: "8px 14px", fontSize: 12, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>📋 Copiar</button>
              </div>
              <div style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 12, padding: "24px 28px", boxShadow: "0 2px 8px rgba(0,0,0,0.06)" }}>
                <pre style={{ color: "#0f172a", fontSize: 13, lineHeight: 1.9, margin: 0, whiteSpace: "pre-wrap", fontFamily: "inherit" }}>{script}</pre>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

