function ProbatePriceTracker() {
  const [reductions, setReductions] = useState([
    { id: 1, address: "4502 Briarwood Dr", originalPrice: 485000, currentPrice: 459000, reductions: [{ date: "2026-04-15", from: 485000, to: 469000, reason: "No offers after 30 days" },{ date: "2026-05-10", from: 469000, to: 459000, reason: "Competing listing at lower price" }], dom: 62, status: "Active", target: 440000 },
    { id: 2, address: "12204 Westheimer Rd", originalPrice: 320000, currentPrice: 320000, reductions: [], dom: 8, status: "Active", target: 295000 },
  ]);

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#f8fafc" }}>
      <TopBar title="📉 Probate Price Reduction Tracker" sub="Most estate homes need price adjustments — track them here" />
      <div style={{ flex: 1, overflow: "auto", padding: 24 }}>
        <div style={{ background: "#f5f3ff", border: "1px solid #e9d5ff", borderRadius: 10, padding: "14px 18px", marginBottom: 20 }}>
          <div style={{ color: "#7c3aed", fontSize: 13, fontWeight: 700, marginBottom: 4 }}>💡 Probate Pricing Strategy</div>
          <div style={{ color: "#4c1d95", fontSize: 13, lineHeight: 1.6 }}>Estate properties often need 1-3 price reductions before selling. Heirs tend to overprice initially based on emotional attachment. Plan for reductions at 30, 60, and 90 days if no offers. The sweet spot is usually 5-10% below market for a quick, clean close.</div>
        </div>
        {reductions.map(p => {
          const totalReduction = p.originalPrice - p.currentPrice;
          const pctOff = Math.round((totalReduction/p.originalPrice)*100);
          return (
            <div key={p.id} style={{ background: "white", border: "1px solid #f1f5f9", borderRadius: 12, padding: "20px 22px", marginBottom: 16, boxShadow: "0 1px 4px rgba(0,0,0,0.04)" }}>
              <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 14 }}>
                <div>
                  <div style={{ color: "#0f172a", fontSize: 15, fontWeight: 700 }}>{p.address}</div>
                  <div style={{ color: "#64748b", fontSize: 12 }}>DOM: {p.dom} days · {p.reductions.length} reduction{p.reductions.length!==1?"s":""}</div>
                </div>
                <div style={{ textAlign: "right" }}>
                  <div style={{ color: "#7c3aed", fontSize: 22, fontWeight: 800 }}>{fmt(p.currentPrice)}</div>
                  {totalReduction > 0 && <div style={{ color: "#059669", fontSize: 12, fontWeight: 600 }}>↓ {fmt(totalReduction)} ({pctOff}% off original)</div>}
                </div>
              </div>
              <div style={{ display: "flex", gap: 10, marginBottom: 14 }}>
                <div style={{ background: "#f8fafc", borderRadius: 7, padding: "8px 12px", flex: 1 }}>
                  <div style={{ color: "#94a3b8", fontSize: 9, fontWeight: 700, textTransform: "uppercase" }}>Original</div>
                  <div style={{ color: "#0f172a", fontSize: 14, fontWeight: 700 }}>{fmt(p.originalPrice)}</div>
                </div>
                <div style={{ background: "#f5f3ff", borderRadius: 7, padding: "8px 12px", flex: 1 }}>
                  <div style={{ color: "#94a3b8", fontSize: 9, fontWeight: 700, textTransform: "uppercase" }}>Current</div>
                  <div style={{ color: "#7c3aed", fontSize: 14, fontWeight: 700 }}>{fmt(p.currentPrice)}</div>
                </div>
                <div style={{ background: "#f0fdf4", borderRadius: 7, padding: "8px 12px", flex: 1 }}>
                  <div style={{ color: "#94a3b8", fontSize: 9, fontWeight: 700, textTransform: "uppercase" }}>Target</div>
                  <div style={{ color: "#059669", fontSize: 14, fontWeight: 700 }}>{fmt(p.target)}</div>
                </div>
              </div>
              {p.reductions.length > 0 && (
                <div>
                  <div style={{ color: "#475569", fontSize: 11, fontWeight: 700, marginBottom: 8 }}>Price History</div>
                  {p.reductions.map((r, i) => (
                    <div key={i} style={{ display: "flex", gap: 10, marginBottom: 6, alignItems: "center" }}>
                      <span style={{ color: "#94a3b8", fontSize: 11 }}>{r.date}</span>
                      <span style={{ color: "#0f172a", fontSize: 12 }}>{fmt(r.from)} → {fmt(r.to)}</span>
                      <span style={{ color: "#059669", fontSize: 11 }}>(↓ {fmt(r.from-r.to)})</span>
                      <span style={{ color: "#64748b", fontSize: 11 }}>{r.reason}</span>
                    </div>
                  ))}
                </div>
              )}
              <button style={{ marginTop: 12, background: "#7c3aed", border: "none", color: "white", borderRadius: 7, padding: "8px 18px", fontSize: 12, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>+ Log Price Reduction</button>
            </div>
          );
        })}
      </div>
    </div>
  );
}

