// ─── Dead Lead Resurrector ────────────────────────────────────────────────────
function DeadLeadResurrector({ contacts }) {
  const deadLeads = contacts.filter(c=>c.temperature==="Cold"||c.stage==="Nurture").slice(0,8);
  const [resurrected, setResurrected] = useState([]);
  const [running, setRunning] = useState(false);
  const [progress, setProgress] = useState(0);

  const runCampaign = () => {
    setRunning(true);
    setProgress(0);
    let p = 0;
    const iv = setInterval(() => {
      p += 10;
      setProgress(p);
      if (p >= 100) {
        clearInterval(iv);
        setRunning(false);
        setResurrected([contacts[0], contacts[2]].filter(Boolean));
      }
    }, 300);
  };

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#0f172a" }}>
      <div style={{ background: "#1e1b4b", padding: "16px 24px", borderBottom: "1px solid rgba(124,58,237,0.3)" }}>
        <div style={{ color: "white", fontSize: 18, fontWeight: 800, marginBottom: 2 }}>🔄 Dead Lead Resurrector</div>
        <div style={{ color: "rgba(255,255,255,0.4)", fontSize: 12 }}>Reactivate cold leads with AI-powered remarketing — find hidden revenue in your database</div>
      </div>
      <div style={{ flex: 1, overflow: "auto", padding: 24 }}>
        <div style={{ background: "#1e1b4b", border: "1px solid rgba(124,58,237,0.2)", borderRadius: 12, padding: 20, marginBottom: 20 }}>
          <div style={{ color: "white", fontSize: 14, fontWeight: 700, marginBottom: 8 }}>💡 The "Surprise Cash" Strategy</div>
          <div style={{ color: "rgba(255,255,255,0.6)", fontSize: 13, lineHeight: 1.7 }}>Ylopo's most powerful insight: <strong style={{ color: "white" }}>agents are sitting on gold in their dead lead databases.</strong> People who went cold 6-18 months ago are often NOW ready to buy or sell — they just need the right trigger. EstateIQ's Dead Lead Resurrector runs an automated AI text + Facebook remarketing campaign to reawaken them. Even a 5% reactivation rate on 200 dead leads = 10 new clients.</div>
        </div>

        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 20, marginBottom: 20 }}>
          <div style={{ background: "#1e1b4b", border: "1px solid rgba(124,58,237,0.2)", borderRadius: 12, padding: 20 }}>
            <div style={{ color: "white", fontSize: 14, fontWeight: 700, marginBottom: 14 }}>💀 Your Cold/Dead Leads ({deadLeads.length})</div>
            {deadLeads.length > 0 ? deadLeads.map(l=>(
              <div key={l.id} style={{ display: "flex", alignItems: "center", gap: 12, padding: "8px 0", borderBottom: "1px solid rgba(255,255,255,0.04)" }}>
                <div style={{ width: 30, height: 30, borderRadius: "50%", background: "#1e2d3d", color: "#94a3b8", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 11, fontWeight: 800, flexShrink: 0 }}>{l.name[0]}</div>
                <div style={{ flex: 1 }}>
                  <div style={{ color: "rgba(255,255,255,0.7)", fontSize: 12, fontWeight: 600 }}>{l.name}</div>
                  <div style={{ color: "rgba(255,255,255,0.3)", fontSize: 10 }}>Last contact: {l.lastContact}</div>
                </div>
                {resurrected.find(r=>r.id===l.id) && <span style={{ background: "#059669", color: "white", fontSize: 9, fontWeight: 800, padding: "2px 7px", borderRadius: 10 }}>🔥 REACTIVATED</span>}
              </div>
            )) : <div style={{ color: "rgba(255,255,255,0.3)", fontSize: 13 }}>No cold leads found — great job!</div>}
          </div>
          <div style={{ background: "#1e1b4b", border: "1px solid rgba(124,58,237,0.2)", borderRadius: 12, padding: 20 }}>
            <div style={{ color: "white", fontSize: 14, fontWeight: 700, marginBottom: 14 }}>🚀 Launch Resurrection Campaign</div>
            <div style={{ display: "flex", flexDirection: "column", gap: 10, marginBottom: 18 }}>
              {[["AI Text Sequence","5 texts over 30 days — personalized per lead","🤖"],["Facebook Remarketing","Show listings to your cold lead custom audience","📘"],["Email Drip","4-email nurture sequence with market updates","📧"],["Spanish Version","Auto-detect and message Spanish speakers in español","🇪🇸"]].map(([title,desc,icon])=>(
                <div key={title} style={{ display: "flex", gap: 10, alignItems: "flex-start" }}>
                  <span style={{ fontSize: 16 }}>{icon}</span>
                  <div><div style={{ color: "white", fontSize: 12, fontWeight: 700 }}>{title}</div><div style={{ color: "rgba(255,255,255,0.4)", fontSize: 11 }}>{desc}</div></div>
                </div>
              ))}
            </div>
            {running ? (
              <div>
                <div style={{ color: "rgba(255,255,255,0.6)", fontSize: 12, marginBottom: 8 }}>Running campaign... {progress}%</div>
                <div style={{ height: 8, background: "rgba(255,255,255,0.08)", borderRadius: 4, overflow: "hidden" }}>
                  <div style={{ width: progress+"%", height: "100%", background: "#7c3aed", borderRadius: 4, transition: "width 0.3s" }} />
                </div>
              </div>
            ) : (
              <button onClick={runCampaign} style={{ width: "100%", background: "linear-gradient(135deg, #7c3aed, #4f46e5)", border: "none", color: "white", borderRadius: 9, padding: "14px", fontSize: 14, fontWeight: 800, cursor: "pointer", fontFamily: "inherit" }}>
                🔄 Launch Dead Lead Campaign
              </button>
            )}
            {resurrected.length > 0 && (
              <div style={{ background: "#059669", borderRadius: 8, padding: "12px 14px", marginTop: 12 }}>
                <div style={{ color: "white", fontSize: 13, fontWeight: 800 }}>🎉 {resurrected.length} leads reactivated!</div>
                <div style={{ color: "rgba(255,255,255,0.8)", fontSize: 11 }}>{resurrected.map(r=>r.name).join(", ")} responded to outreach</div>
              </div>
            )}
          </div>
        </div>

        <div style={{ background: "#1e1b4b", border: "1px solid rgba(124,58,237,0.2)", borderRadius: 12, padding: 20 }}>
          <div style={{ color: "white", fontSize: 14, fontWeight: 700, marginBottom: 14 }}>📊 Resurrection Campaign Results</div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 12 }}>
            {[["Leads Targeted","47","#94a3b8"],["Reactivated","12","#059669"],["Reactivation Rate","25.5%","#f59e0b"],["Revenue Generated","$31,200","#7c3aed"]].map(([k,v,c])=>(
              <div key={k} style={{ background: "rgba(255,255,255,0.04)", borderRadius: 8, padding: "14px", textAlign: "center" }}>
                <div style={{ color: c, fontSize: 22, fontWeight: 800, marginBottom: 4 }}>{v}</div>
                <div style={{ color: "rgba(255,255,255,0.4)", fontSize: 11 }}>{k}</div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}

