// ─── Marketing ROI Report ─────────────────────────────────────────────────────
function MarketingROIReport() {
  const channels = [
    { name: "Facebook Dynamic Ads", spend: 650, leads: 34, closings: 2, revenue: 26400, roi: 3961, color: "#1877F2" },
    { name: "Google Search Ads", spend: 480, leads: 22, closings: 1, revenue: 14850, roi: 2994, color: "#4285F4" },
    { name: "Instagram Retargeting", spend: 190, leads: 18, closings: 1, revenue: 8750, roi: 4505, color: "#E1306C" },
    { name: "Dead Lead Remarketing", spend: 120, leads: 6, closings: 1, revenue: 12500, roi: 10317, color: "#7c3aed" },
    { name: "Organic / SEO Blog", spend: 0, leads: 22, closings: 1, revenue: 14850, roi: 999999, color: "#059669" },
    { name: "YouTube Channel", spend: 0, leads: 8, closings: 0, revenue: 0, roi: 0, color: "#ff0000" },
  ];
  const totalSpend = channels.reduce((s,c)=>s+c.spend,0);
  const totalRevenue = channels.reduce((s,c)=>s+c.revenue,0);
  const totalROI = totalSpend > 0 ? Math.round((totalRevenue-totalSpend)/totalSpend*100) : 0;

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#0f172a" }}>
      <div style={{ background: "#1e1b4b", padding: "16px 24px", borderBottom: "1px solid rgba(124,58,237,0.3)" }}>
        <div style={{ color: "white", fontSize: 18, fontWeight: 800, marginBottom: 2 }}>📊 Marketing ROI Report</div>
        <div style={{ color: "rgba(255,255,255,0.4)", fontSize: 12 }}>Every dollar you spend — tracked, measured, and optimized</div>
      </div>
      <div style={{ flex: 1, overflow: "auto", padding: 24 }}>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 14, marginBottom: 24 }}>
          {[["Total Ad Spend", "$"+totalSpend.toLocaleString(), "#ef4444"],["Total Revenue Generated", "$"+totalRevenue.toLocaleString(), "#10b981"],["Overall ROI", totalROI+"%", "#7c3aed"],["Best Channel", "Dead Lead Remarketing", "#f59e0b"]].map(([l,v,c])=>(
            <div key={l} style={{ background: "#1e1b4b", border: "1px solid rgba(124,58,237,0.2)", borderRadius: 12, padding: "16px 18px" }}>
              <div style={{ color: "rgba(255,255,255,0.4)", fontSize: 10, fontWeight: 700, textTransform: "uppercase", marginBottom: 8 }}>{l}</div>
              <div style={{ color: c, fontSize: l==="Best Channel"?14:22, fontWeight: 800 }}>{v}</div>
            </div>
          ))}
        </div>
        <div style={{ background: "#1e1b4b", border: "1px solid rgba(124,58,237,0.2)", borderRadius: 12, overflow: "hidden", marginBottom: 20 }}>
          <table style={{ width: "100%", borderCollapse: "collapse" }}>
            <thead><tr style={{ borderBottom: "1px solid rgba(255,255,255,0.06)" }}>{["Channel","Ad Spend","Leads","Closings","Revenue","ROI"].map(h=><th key={h} style={{ padding: "12px 16px", color: "rgba(255,255,255,0.3)", fontSize: 11, fontWeight: 700, textAlign: "left", letterSpacing: "0.05em", textTransform: "uppercase" }}>{h}</th>)}</tr></thead>
            <tbody>
              {channels.sort((a,b)=>b.roi-a.roi).map(c=>(
                <tr key={c.name} style={{ borderBottom: "1px solid rgba(255,255,255,0.04)" }}>
                  <td style={{ padding: "13px 16px" }}>
                    <div style={{ display: "flex", gap: 10, alignItems: "center" }}>
                      <div style={{ width: 8, height: 8, borderRadius: "50%", background: c.color }} />
                      <span style={{ color: "rgba(255,255,255,0.8)", fontSize: 13, fontWeight: 600 }}>{c.name}</span>
                    </div>
                  </td>
                  <td style={{ padding: "13px 16px", color: c.spend===0?"#059669":"#ef4444", fontWeight: 700, fontSize: 13 }}>{c.spend===0?"FREE":"$"+c.spend}</td>
                  <td style={{ padding: "13px 16px", color: "#3b82f6", fontWeight: 700, fontSize: 13 }}>{c.leads}</td>
                  <td style={{ padding: "13px 16px", color: "#f59e0b", fontWeight: 700, fontSize: 13 }}>{c.closings}</td>
                  <td style={{ padding: "13px 16px", color: "#10b981", fontWeight: 700, fontSize: 13 }}>{c.revenue>0?fmt(c.revenue):"—"}</td>
                  <td style={{ padding: "13px 16px" }}>
                    <span style={{ color: c.roi>1000?"#10b981":c.roi>500?"#f59e0b":c.roi===999999?"#10b981":"#94a3b8", fontWeight: 800, fontSize: 13 }}>
                      {c.roi===999999?"∞ (FREE)":c.roi===0?"—":c.roi+"%"}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        <div style={{ background: "#1e1b4b", border: "1px solid rgba(16,185,129,0.3)", borderRadius: 12, padding: 20 }}>
          <div style={{ color: "#10b981", fontSize: 14, fontWeight: 700, marginBottom: 10 }}>🏆 Gerald's Competitive Advantage Over Ylopo</div>
          <div style={{ color: "rgba(255,255,255,0.6)", fontSize: 13, lineHeight: 1.7 }}>Ylopo charges <strong style={{ color: "white" }}>$895-$2,000/month</strong> just for the platform — before a single dollar of ad spend. EstateIQ gives you the same dynamic ad engine, AI texting, behavioral tracking, and dead lead reactivation at <strong style={{ color: "#10b981" }}>$0/month</strong>. Your ad budget goes entirely to <strong style={{ color: "white" }}>actual ads</strong> — not platform fees. At $650/month in ad spend, EstateIQ generates the same pipeline Ylopo would — saving you $1,350-$14,000/month.</div>
        </div>
      </div>
    </div>
  );
}


