              <select value={searchParams.type} onChange={e => setSearchParams(s => ({ ...s, type: e.target.value }))} style={{ ...inp, flex: "1 1 100px", cursor: "pointer" }}>
                <option value="">Home Type</option>
                {["Single Family","Condo","Townhouse","Luxury","Penthouse","Beach Home"].map(t => <option key={t}>{t}</option>)}
              </select>
