                <button style={{ flex: 1, background: "#f8fafc", border: "1px solid #e2e8f0", color: "#475569", borderRadius: 6, padding: "8px", fontSize: 11, cursor: "pointer", fontFamily: "inherit" }}>Duplicate</button>
