function SpeedToLeadTimer() {
  const [leads] = useState([
    { id: 1, name: "Jennifer Walsh", source: "Facebook Ad", arrived: new Date(Date.now()-180000), responded: new Date(Date.now()-60000), responseTime: "2 min", status: "Responded", score: 82 },
    { id: 2, name: "Miguel Herrera", source: "IDX Website", arrived: new Date(Date.now()-900000), responded: null, responseTime: null, status: "Overdue", score: 71 },
    { id: 3, name: "Sarah Thompson", source: "Zillow", arrived: new Date(Date.now()-300000), responded: null, responseTime: null, status: "Alert", score: 68 },
    { id: 4, name: "David & Kim Park", source: "Relocation Page", arrived: new Date(Date.now()-7200000), responded: new Date(Date.now()-7080000), responseTime: "2 min", status: "Responded", score: 76 },
  ]);

  const getElapsed = (date) => {
    const diff = Math.floor((Date.now() - date) / 1000);
    if (diff < 60) return diff + "s";
    if (diff < 3600) return Math.floor(diff/60) + "m " + (diff%60) + "s";
    return Math.floor(diff/3600) + "h " + Math.floor((diff%3600)/60) + "m";
  };

  const statusColors6 = { Responded:"#059669", Alert:"#f59e0b", Overdue:"#ef4444" };

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#f8fafc" }}>
      <TopBar title="⚡ Speed-to-Lead Timer" sub="Research shows responding within 5 minutes makes you 21x more likely to convert" />
      <div style={{ background: "#fef2f2", border: "1px solid #fecaca", padding: "12px 24px", display: "flex", gap: 14, alignItems: "center" }}>
        <span style={{ color: "#dc2626", fontSize: 20 }}>⚡</span>
        <div style={{ color: "#991b1b", fontSize: 13, fontWeight: 700 }}>Follow Up Boss Rule: <span style={{ color: "#dc2626" }}>Contact new leads within 5 minutes</span> — you are 21x more likely to qualify them vs waiting 30 minutes.</div>
      </div>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(3,1fr)", gap: 14, padding: "14px 24px", background: "white", borderBottom: "1px solid #f1f5f9" }}>
        {[["Avg Response Time","2 min 18s","#059669"],["Leads Contacted <5min","87%","#3b82f6"],["Overdue Leads",leads.filter(l=>l.status==="Overdue").length,"#ef4444"]].map(([l,v,c])=>(
          <div key={l} style={{ textAlign: "center" }}><div style={{ color: c, fontSize: 22, fontWeight: 800 }}>{v}</div><div style={{ color: "#475569", fontSize: 12, fontWeight: 600 }}>{l}</div></div>
        ))}
      </div>
      <div style={{ flex: 1, overflow: "auto", padding: 20 }}>
        {leads.map(l=>(
          <div key={l.id} style={{ background: "white", border: `2px solid ${l.status==="Overdue"?"#fecaca":l.status==="Alert"?"#fde68a":"#f1f5f9"}`, borderRadius: 12, padding: "16px 20px", marginBottom: 12, boxShadow: "0 1px 4px rgba(0,0,0,0.04)" }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
              <div>
                <div style={{ display: "flex", gap: 8, alignItems: "center", marginBottom: 4 }}>
                  <div style={{ color: "#0f172a", fontSize: 14, fontWeight: 700 }}>{l.name}</div>
                  <span style={{ background: (statusColors6[l.status]||"#94a3b8")+"18", color: statusColors6[l.status]||"#94a3b8", fontSize: 11, fontWeight: 700, padding: "2px 8px", borderRadius: 10 }}>{l.status}</span>
                </div>
                <div style={{ color: "#64748b", fontSize: 12 }}>Source: {l.source} · Lead arrived: {getElapsed(l.arrived)} ago</div>
                {l.responseTime && <div style={{ color: "#059669", fontSize: 12, fontWeight: 700 }}>✓ Responded in {l.responseTime}</div>}
              </div>
              <div style={{ textAlign: "right" }}>
                {l.status !== "Responded" && (
                  <div style={{ background: l.status==="Overdue"?"#fef2f2":"#fffbeb", borderRadius: 8, padding: "8px 14px", textAlign: "center" }}>
                    <div style={{ color: l.status==="Overdue"?"#dc2626":"#f59e0b", fontSize: 24, fontWeight: 800, fontFamily: "monospace" }}>{getElapsed(l.arrived)}</div>
                    <div style={{ color: "#94a3b8", fontSize: 10 }}>elapsed</div>
                  </div>
                )}
              </div>
            </div>
            {l.status !== "Responded" && (
              <div style={{ display: "flex", gap: 8, marginTop: 12 }}>
                <button style={{ flex: 1, background: "#059669", border: "none", color: "white", borderRadius: 7, padding: "9px", fontSize: 12, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>📞 Call Now</button>
                <button style={{ flex: 1, background: "#3b82f6", border: "none", color: "white", borderRadius: 7, padding: "9px", fontSize: 12, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>💬 Text Now</button>
                <button style={{ flex: 1, background: "#f8fafc", border: "1px solid #e2e8f0", color: "#475569", borderRadius: 7, padding: "9px", fontSize: 12, cursor: "pointer", fontFamily: "inherit" }}>📧 Email</button>
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
}

