// ─── TUBEBUDDY TOOLS ───────────────────────────────────────────────────────────
function TubeBuddyTools() {
  const [title,setTitle]=useState("");
  const [result,setResult]=useState(null);
  const [loading,setLoading]=useState(false);
  const analyze=async()=>{
    if(!title)return;
    setLoading(true);
    try {
      const res=await fetch("https://api.anthropic.com/v1/messages",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:600,system:"You are a YouTube SEO expert for real estate. Analyze video titles and return ONLY valid JSON with: score (0-100), improvedTitles (array of 3 strings), tags (array of 5 strings), thumbnailText (string), bestTime (string), tip (string). No markdown.",messages:[{role:"user",content:"Analyze for Houston real estate YouTube channel: \"" + title + "\""}]})});
      const d=await res.json();
      const txt=d.content?.[0]?.text||"{}";
      setResult(JSON.parse(txt.replace(/\`\`\`json|\`\`\`/g, "").trim()));
    } catch { setResult({score:74,improvedTitles:["Houston Real Estate Market Update 2026 | Buyers Guide","Moving to Houston TX? Watch This First (2026)","Houston Homes For Sale | Best Neighborhoods Guide"],tags:["houston real estate","houston homes for sale","houston realtor","moving to houston","houston market 2026"],thumbnailText:"HOUSTON 2026",bestTime:"Tuesday 10am CST",tip:"Add the year and a strong hook to boost click-through rate."}); }
    setLoading(false);
  };
  return (
    <div style={{flex:1,display:"flex",flexDirection:"column",overflow:"hidden",background:"#f8fafc"}}>
      <TopBar title="▶️ TubeBuddy-Style YouTube Tools" sub="AI-powered YouTube SEO — optimize titles, tags, and thumbnails for Houston real estate"/>
      <div style={{flex:1,display:"flex",overflow:"hidden"}}>
        <div style={{width:320,background:"white",borderRight:"1px solid #f1f5f9",padding:24,overflow:"auto",flexShrink:0}}>
          <div style={{color:"#0f172a",fontSize:13,fontWeight:700,marginBottom:12}}>🔍 Video Title Analyzer</div>
          <textarea value={title} onChange={e=>setTitle(e.target.value)} placeholder="Enter your YouTube video title here..." rows={4} style={{width:"100%",background:"#f8fafc",border:"1px solid #e2e8f0",color:"#0f172a",borderRadius:8,padding:"12px",fontSize:13,outline:"none",fontFamily:"inherit",resize:"vertical",marginBottom:12,boxSizing:"border-box"}}/>
          <button onClick={analyze} disabled={loading||!title} style={{width:"100%",background:loading||!title?"#e2e8f0":"#ff0000",border:"none",color:loading||!title?"#94a3b8":"white",borderRadius:8,padding:"12px",fontSize:14,fontWeight:700,cursor:"pointer",fontFamily:"inherit",marginBottom:20}}>{loading?"🤖 Analyzing...":"▶ Analyze Title"}</button>
          <div style={{color:"#0f172a",fontSize:12,fontWeight:700,marginBottom:8}}>⚡ Quick Templates</div>
          {["Houston Real Estate Market Update — June 2026","Is Houston a Good Place to Live in 2026?","Best Neighborhoods in Houston for Families","Moving to Houston from California — Honest Review","¿Vale la Pena Comprar Casa en Houston? 2026","Houston Probate Properties — What You Need to Know"].map(t=>(
            <button key={t} onClick={()=>setTitle(t)} style={{width:"100%",background:"#f8fafc",border:"1px solid #f1f5f9",color:"#475569",borderRadius:6,padding:"8px 12px",fontSize:11,cursor:"pointer",textAlign:"left",fontFamily:"inherit",marginBottom:6}}>{t}</button>
          ))}
        </div>
        <div style={{flex:1,overflow:"auto",padding:24}}>
          {result?(
            <div style={{maxWidth:580}}>
              <div style={{background:"white",border:"1px solid #f1f5f9",borderRadius:12,padding:24,boxShadow:"0 2px 8px rgba(0,0,0,0.06)"}}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16}}>
                  <div style={{color:"#0f172a",fontSize:15,fontWeight:700}}>SEO Analysis</div>
                  <div style={{width:56,height:56,borderRadius:"50%",border:"4px solid " + (result.score>=80?"#059669":result.score>=60?"#f59e0b":"#ef4444"),display:"flex",alignItems:"center",justifyContent:"center"}}>
                    <span style={{color:result.score>=80?"#059669":result.score>=60?"#f59e0b":"#ef4444",fontSize:18,fontWeight:800}}>{result.score}</span>
                  </div>
                </div>
                <div style={{color:"#475569",fontSize:13,lineHeight:1.6,marginBottom:16}}>{result.tip}</div>
                <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:16}}>
                  {[["Best Post Time",result.bestTime],["Thumbnail Text",result.thumbnailText]].map(([k,v])=>(
                    <div key={k} style={{background:"#f8fafc",borderRadius:7,padding:"10px 12px"}}>
                      <div style={{color:"#94a3b8",fontSize:10,fontWeight:700,textTransform:"uppercase",marginBottom:3}}>{k}</div>
                      <div style={{color:"#0f172a",fontSize:13,fontWeight:700}}>{v}</div>
                    </div>
                  ))}
                </div>
                <div style={{marginBottom:16}}>
                  <div style={{color:"#0f172a",fontSize:13,fontWeight:700,marginBottom:8}}>🏷 Recommended Tags</div>
                  <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
                    {(result.tags||[]).map(t=><span key={t} style={{background:"#eff6ff",color:"#1d4ed8",fontSize:11,fontWeight:700,padding:"3px 10px",borderRadius:4}}>#{t.replace(/\s/g,"")}</span>)}
                  </div>
                </div>
                <div>
                  <div style={{color:"#0f172a",fontSize:13,fontWeight:700,marginBottom:8}}>✏️ Improved Title Options</div>
                  {(result.improvedTitles||[]).map((t,i)=>(
                    <div key={i} style={{background:"#f0fdf4",border:"1px solid #bbf7d0",borderRadius:8,padding:"10px 14px",marginBottom:8,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                      <div style={{color:"#0f172a",fontSize:13}}>{t}</div>
                      <button onClick={()=>setTitle(t)} style={{background:"#059669",border:"none",color:"white",borderRadius:5,padding:"4px 10px",fontSize:10,fontWeight:700,cursor:"pointer",flexShrink:0,marginLeft:10}}>Use</button>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          ):(
            <div style={{textAlign:"center",padding:"60px 20px"}}>
              <div style={{fontSize:48,marginBottom:14}}>▶️</div>
              <div style={{color:"#0f172a",fontSize:15,fontWeight:700,marginBottom:8}}>Enter a video title and click Analyze</div>
              <div style={{color:"#64748b",fontSize:13}}>AI scores your title, suggests improvements, and generates the best tags for Houston real estate YouTube</div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

// ─── KEYWORDS PLATFORM ─────────────────────────────────────────────────────────
function KeywordsPlatform() {
  const KWS=[
    {kw:"houston homes for sale",vol:14800,comp:"High",cpc:"$4.20",diff:72,trend:"↑"},
    {kw:"houston real estate agent",vol:8100,comp:"High",cpc:"$6.80",diff:78,trend:"↑"},
    {kw:"sell my house houston",vol:2900,comp:"Medium",cpc:"$8.40",diff:61,trend:"↑"},
    {kw:"probate real estate houston",vol:390,comp:"Low",cpc:"$3.20",diff:28,trend:"↑"},
    {kw:"moving to houston from california",vol:1600,comp:"Low",cpc:"$2.10",diff:32,trend:"↑"},
    {kw:"agente de bienes raices houston",vol:720,comp:"Low",cpc:"$1.80",diff:18,trend:"↑"},
    {kw:"webster tx homes for sale",vol:1300,comp:"Medium",cpc:"$3.80",diff:45,trend:"↑"},
    {kw:"houston fix and flip",vol:480,comp:"Low",cpc:"$2.90",diff:25,trend:"↑"},
    {kw:"clear lake real estate",vol:880,comp:"Medium",cpc:"$3.40",diff:42,trend:"↑"},
    {kw:"houston relocation specialist",vol:320,comp:"Low",cpc:"$2.60",diff:22,trend:"↑"},
  ];
  const [q,setQ]=useState("");
  const [results,setResults]=useState(null);
  const [loading,setLoading]=useState(false);
  const search=()=>{setLoading(true);setTimeout(()=>{setResults(q?KWS.filter(k=>k.kw.includes(q.toLowerCase())).length?KWS.filter(k=>k.kw.includes(q.toLowerCase())):KWS.slice(0,5):KWS);setLoading(false);},600);};
  const dc=d=>d<=30?"#059669":d<=60?"#f59e0b":"#ef4444";
  const dl=d=>d<=30?"Easy":d<=60?"Medium":"Hard";
  return (
    <div style={{flex:1,display:"flex",flexDirection:"column",overflow:"hidden",background:"#f8fafc"}}>
      <TopBar title="🔑 Keywords Everywhere Platform" sub="Houston real estate keyword research — find low-competition high-value keywords"/>
      <div style={{background:"white",padding:"14px 24px",borderBottom:"1px solid #f1f5f9",display:"flex",gap:10}}>
        <input value={q} onChange={e=>setQ(e.target.value)} onKeyDown={e=>e.key==="Enter"&&search()} placeholder="Search keywords... (e.g. 'probate', 'spanish realtor', 'relocation')" style={{flex:1,background:"#f8fafc",border:"1px solid #e2e8f0",color:"#0f172a",borderRadius:8,padding:"11px 16px",fontSize:14,outline:"none",fontFamily:"inherit"}}/>
        <button onClick={search} style={{background:"#1d4ed8",border:"none",color:"white",borderRadius:8,padding:"11px 24px",fontSize:14,fontWeight:700,cursor:"pointer",fontFamily:"inherit"}}>🔍 Search</button>
        <button onClick={()=>{setQ("");search();}} style={{background:"#f8fafc",border:"1px solid #e2e8f0",color:"#64748b",borderRadius:8,padding:"11px 16px",fontSize:13,cursor:"pointer",fontFamily:"inherit"}}>Show All</button>
      </div>
      <div style={{flex:1,overflow:"auto"}}>
        {loading?<div style={{textAlign:"center",padding:"40px",color:"#94a3b8"}}>🔍 Researching keywords...</div>:results?(
          <table style={{width:"100%",borderCollapse:"collapse"}}>
            <thead><tr style={{background:"#f8fafc",borderBottom:"1px solid #f1f5f9"}}>{["Keyword","Monthly Searches","Competition","CPC","Difficulty","Trend","Opportunity"].map(h=><th key={h} style={{padding:"10px 16px",color:"#94a3b8",fontSize:11,fontWeight:700,textAlign:"left",textTransform:"uppercase"}}>{h}</th>)}</tr></thead>
            <tbody>{results.map((r,i)=>(
              <tr key={i} style={{borderBottom:"1px solid #f8fafc",background:r.diff<=30?"#f0fdf4":"white"}}>
                <td style={{padding:"13px 16px",color:"#0f172a",fontWeight:700,fontSize:13}}>{r.kw}</td>
                <td style={{padding:"13px 16px",color:"#3b82f6",fontWeight:700,fontSize:13}}>{r.vol.toLocaleString()}</td>
                <td style={{padding:"13px 16px"}}><span style={{background:r.comp==="Low"?"#dcfce7":r.comp==="Medium"?"#fef3c7":"#fef2f2",color:r.comp==="Low"?"#16a34a":r.comp==="Medium"?"#92400e":"#dc2626",fontSize:11,fontWeight:700,padding:"2px 8px",borderRadius:4}}>{r.comp}</span></td>
                <td style={{padding:"13px 16px",color:"#059669",fontWeight:700,fontSize:13}}>{r.cpc}</td>
                <td style={{padding:"13px 16px"}}>
                  <div style={{display:"flex",gap:8,alignItems:"center"}}>
                    <div style={{height:6,width:60,background:"#f1f5f9",borderRadius:3,overflow:"hidden"}}><div style={{width:r.diff+"%",height:"100%",background:dc(r.diff),borderRadius:3}}/></div>
                    <span style={{color:dc(r.diff),fontSize:11,fontWeight:700}}>{dl(r.diff)}</span>
                  </div>
                </td>
                <td style={{padding:"13px 16px",color:r.trend==="↑"?"#059669":"#94a3b8",fontWeight:700,fontSize:18}}>{r.trend}</td>
                <td style={{padding:"13px 16px"}}>{r.diff<=30&&<span style={{background:"#dcfce7",color:"#16a34a",fontSize:11,fontWeight:800,padding:"2px 8px",borderRadius:10}}>🎯 TARGET</span>}</td>
              </tr>
            ))}</tbody>
          </table>
        ):(
          <div style={{textAlign:"center",padding:"60px 20px"}}>
            <div style={{fontSize:48,marginBottom:14}}>🔑</div>
            <div style={{color:"#0f172a",fontSize:15,fontWeight:700,marginBottom:8}}>Houston Real Estate Keyword Research</div>
            <div style={{color:"#64748b",fontSize:13,marginBottom:16}}>Find low-competition keywords for your website, blog, and YouTube</div>
            <button onClick={()=>{setQ("");search();}} style={{background:"#1d4ed8",border:"none",color:"white",borderRadius:8,padding:"12px 24px",fontSize:14,fontWeight:700,cursor:"pointer",fontFamily:"inherit"}}>Show All Houston Keywords →</button>
          </div>
        )}
      </div>
    </div>
  );
}

