// ─── BANK STATEMENT ANALYZER ───────────────────────────────────────────────────
function BankStatementAnalyzer() {
  const [txns,setTxns]=useState([
    {id:1,date:"2026-05-01",desc:"ZILLOW PREMIER AGENT",amount:-299.00,cat:"Lead Generation",deduct:true},
    {id:2,date:"2026-05-03",desc:"CANVA PRO SUBSCRIPTION",amount:-12.99,cat:"Marketing & Advertising",deduct:true},
    {id:3,date:"2026-05-05",desc:"SHELL GAS STATION",amount:-78.50,cat:"Vehicle / Mileage",deduct:true},
    {id:4,date:"2026-05-07",desc:"VISTAPRINT POSTCARDS",amount:-89.00,cat:"Marketing & Advertising",deduct:true},
    {id:5,date:"2026-05-10",desc:"AMAZON OFFICE SUPPLIES",amount:-34.22,cat:"Office Supplies",deduct:true},
    {id:6,date:"2026-05-12",desc:"STARBUCKS CLIENT MEETING",amount:-12.40,cat:"Client Entertainment",deduct:true},
    {id:7,date:"2026-05-15",desc:"COMMISSION — CEDAR RIDGE CLOSING",amount:14850.00,cat:"Commission Income",deduct:false},
    {id:8,date:"2026-05-18",desc:"HAR MLS FEES",amount:-45.00,cat:"Professional Fees & Dues",deduct:true},
    {id:9,date:"2026-05-20",desc:"CLIENT LUNCH",amount:-24.80,cat:"Client Entertainment",deduct:true},
    {id:10,date:"2026-05-22",desc:"BEEHIIV EMAIL PLATFORM",amount:-42.00,cat:"Marketing & Advertising",deduct:true},
    {id:11,date:"2026-05-25",desc:"TREC LICENSE RENEWAL",amount:-150.00,cat:"Professional Fees & Dues",deduct:true},
    {id:12,date:"2026-05-27",desc:"CLOSING GIFT — KOWALSKI FAMILY",amount:-200.00,cat:"Client Gifts",deduct:true},
  ]);
  const [editing,setEditing]=useState(null);
  const CATS=["Commission Income","Lead Generation","Marketing & Advertising","Vehicle / Mileage","Office Supplies","Client Entertainment","Client Gifts","Professional Fees & Dues","Education & Training","Technology / Software","Home Office","Non-Deductible"];
  const income=txns.filter(t=>t.amount>0).reduce((s,t)=>s+t.amount,0);
  const expenses=Math.abs(txns.filter(t=>t.amount<0&&t.deduct).reduce((s,t)=>s+t.amount,0));
  const byCat=CATS.reduce((a,c)=>{const tot=Math.abs(txns.filter(t=>t.cat===c&&t.amount<0).reduce((s,t)=>s+t.amount,0));if(tot>0)a[c]=tot;return a;},{});
  return (
    <div style={{flex:1,display:"flex",flexDirection:"column",overflow:"hidden",background:"#f8fafc"}}>
      <TopBar title="🏦 Bank Statement Analyzer" sub="Convert bank statements into tax expense reports — auto-categorizes real estate business expenses" action={
        <div style={{display:"flex",gap:8}}>
          <button style={{background:"#3b82f6",border:"none",color:"white",borderRadius:7,padding:"9px 16px",fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"inherit"}}>📥 Import CSV</button>
          <button onClick={()=>navigator.clipboard.writeText("Date,Description,Category,Amount\n"+txns.filter(t=>t.deduct&&t.amount<0).map(t=>`${t.date},${t.desc},${t.cat},${Math.abs(t.amount).toFixed(2)}`).join("\n")).catch(()=>{})} style={{background:"#059669",border:"none",color:"white",borderRadius:7,padding:"9px 16px",fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"inherit"}}>📤 Export for CPA</button>
        </div>
      }/>
      <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:14,padding:"14px 24px",background:"white",borderBottom:"1px solid #f1f5f9"}}>
        {[["Total Income",fmt(income),"#059669"],["Deductible Expenses",fmt(expenses),"#ef4444"],["Net Taxable",fmt(income-expenses),"#1d4ed8"],["Est. Tax Savings (25%)",fmt(expenses*0.25),"#f59e0b"]].map(([l,v,c])=>(
          <div key={l} style={{textAlign:"center"}}><div style={{color:c,fontSize:18,fontWeight:800}}>{v}</div><div style={{color:"#475569",fontSize:11,fontWeight:600}}>{l}</div></div>
        ))}
      </div>
      <div style={{flex:1,display:"flex",overflow:"hidden"}}>
        <div style={{flex:1,overflow:"auto"}}>
          <table style={{width:"100%",borderCollapse:"collapse"}}>
            <thead><tr style={{background:"#f8fafc",borderBottom:"1px solid #f1f5f9"}}>{["Date","Description","Amount","Category","Deductible"].map(h=><th key={h} style={{padding:"10px 16px",color:"#94a3b8",fontSize:11,fontWeight:700,textAlign:"left",textTransform:"uppercase"}}>{h}</th>)}</tr></thead>
            <tbody>{txns.map(t=>(
              <tr key={t.id} style={{borderBottom:"1px solid #f8fafc",background:t.amount>0?"#f0fdf4":"white"}}>
                <td style={{padding:"11px 16px",color:"#94a3b8",fontSize:12,whiteSpace:"nowrap"}}>{t.date}</td>
                <td style={{padding:"11px 16px",color:"#0f172a",fontSize:12,fontWeight:600}}>{t.desc}</td>
                <td style={{padding:"11px 16px",color:t.amount>0?"#059669":"#ef4444",fontWeight:700,fontSize:13,whiteSpace:"nowrap"}}>{t.amount>0?"+":""}{fmt(Math.abs(t.amount))}</td>
                <td style={{padding:"11px 16px"}}>
                  {editing===t.id?(
                    <select value={t.cat} onChange={e=>{setTxns(p=>p.map(tr=>tr.id===t.id?{...tr,cat:e.target.value,deduct:e.target.value!=="Non-Deductible"&&t.amount<0}:tr));setEditing(null);}} style={{background:"#f8fafc",border:"1px solid #e2e8f0",color:"#0f172a",borderRadius:5,padding:"4px 8px",fontSize:11,outline:"none",cursor:"pointer",fontFamily:"inherit"}}>
                      {CATS.map(c=><option key={c}>{c}</option>)}
                    </select>
                  ):(
                    <span onClick={()=>setEditing(t.id)} style={{background:"#f1f5f9",color:"#475569",fontSize:11,fontWeight:600,padding:"3px 8px",borderRadius:4,cursor:"pointer"}}>{t.cat} ✏️</span>
                  )}
                </td>
                <td style={{padding:"11px 16px"}}><span style={{background:t.deduct?"#dcfce7":"#f1f5f9",color:t.deduct?"#16a34a":"#94a3b8",fontSize:11,fontWeight:700,padding:"2px 8px",borderRadius:10}}>{t.deduct?"✓ Deductible":"—"}</span></td>
              </tr>
            ))}</tbody>
          </table>
        </div>
        <div style={{width:220,background:"white",borderLeft:"1px solid #f1f5f9",padding:16,overflow:"auto"}}>
          <div style={{color:"#0f172a",fontSize:12,fontWeight:700,marginBottom:12}}>📊 By Category</div>
          {Object.entries(byCat).sort((a,b)=>b[1]-a[1]).map(([cat,total])=>(
            <div key={cat} style={{marginBottom:11}}>
              <div style={{display:"flex",justifyContent:"space-between",marginBottom:3}}><span style={{color:"#475569",fontSize:10}}>{cat}</span><span style={{color:"#ef4444",fontSize:10,fontWeight:700}}>{fmt(total)}</span></div>
              <div style={{height:4,background:"#f1f5f9",borderRadius:2,overflow:"hidden"}}><div style={{width:Math.min(100,total/expenses*100)+"%",height:"100%",background:"#3b82f6",borderRadius:2}}/></div>
            </div>
          ))}
          <div style={{marginTop:14,background:"#f0fdf4",border:"1px solid #bbf7d0",borderRadius:8,padding:"10px 12px"}}>
            <div style={{color:"#059669",fontSize:11,fontWeight:700,marginBottom:4}}>💡 Share with CPA</div>
            <div style={{color:"#065f46",fontSize:11,lineHeight:1.5}}>Click "Export for CPA" above for a clean CSV of all deductible expenses organized by category.</div>
          </div>
        </div>
      </div>
    </div>
  );
}

