// ─── Airtable Config (set VITE_* in .env.local, then npm run build) ───────────
const AIRTABLE_TOKEN = import.meta.env.VITE_AIRTABLE_TOKEN || "";
const AIRTABLE_BASE  = import.meta.env.VITE_AIRTABLE_BASE || "";
const AT_URL = (table) => `https://api.airtable.com/v0/${AIRTABLE_BASE}/${encodeURIComponent(table)}`;
const AT_HEADERS = { "Authorization": `Bearer ${AIRTABLE_TOKEN}`, "Content-Type": "application/json" };

async function atFetch(table) {
  try {
    const res = await fetch(AT_URL(table), { headers: AT_HEADERS });
    if (!res.ok) return [];
    const data = await res.json();
    return data.records || [];
  } catch { return []; }
}

async function atCreate(table, fields) {
  try {
    const res = await fetch(AT_URL(table), {
      method: "POST", headers: AT_HEADERS,
      body: JSON.stringify({ records: [{ fields }] })
    });
    return res.ok;
  } catch { return false; }
}

async function atUpdate(table, recordId, fields) {
  try {
    const res = await fetch(AT_URL(table) + "/" + recordId, {
      method: "PATCH", headers: AT_HEADERS,
      body: JSON.stringify({ fields })
    });
    return res.ok;
  } catch { return false; }
}

async function atDelete(table, recordId) {
  try {
    const res = await fetch(AT_URL(table) + "/" + recordId, { method: "DELETE", headers: AT_HEADERS });
    return res.ok;
  } catch { return false; }
}

function mapATContact(rec) {
  const f = rec.fields;
  return {
    _id: rec.id,
    id: rec.id,
    name: f.Name || f.name || "Unknown",
    email: f.Email || f.email || "",
    phone: f.Phone || f.phone || "",
    stage: f.Stage || f.stage || "New Lead",
    temperature: f.Temperature || f.temperature || "Warm",
    budget: parseInt(f.Budget || f.budget) || 0,
    preApproved: f.PreApproved || f["Pre-Approved"] || false,
    interest: [],
    lastContact: f.LastContact || f["Last Contact"] || "",
    agent: f.Agent || f.agent || "Gerald",
    source: f.Source || f.source || "Organic",
    tags: f.Tags ? (typeof f.Tags === "string" ? f.Tags.split(",").map(t=>t.trim()) : f.Tags) : [],
    notes: f.Notes || f.notes || "",
    score: parseInt(f.Score || f.score) || 40,
    lastActivity: f.LastActivity || f["Last Activity"] || "",
  };
}

